  const stars = '★'.repeat(Math.round(f.rating||5)) + '☆'.repeat(5-Math.round(f.rating||5));
  const specsHtml = (f.specs||[]).map(s=>`<li style="font-size:12px;color:var(--muted);padding:4px 0;border-bottom:1px solid rgba(255,255,255,0.04);">${s}</li>`).join('');
  const stockColor = (f.stock||99) <= 5 ? '#EF4444' : (f.stock||99) <= 15 ? '#F59E0B' : '#22C55E';
  const stockMsg = (f.stock||99) <= 5 ? `🔥 Apenas ${f.stock} unidades!` : (f.stock||99) <= 15 ? `⚡ ${f.stock} unidades disponíveis` : '✅ Em estoque';

