// State
let _bundleActive = 0;      // active tab index
let _bundleSelected = [];   // which item indices are checked (main always checked)
let _bundleCurrent = [];    // active bundles array for current pdp

function initBundles(pdpIdx) {
  _bundleCurrent = BUNDLE_DATA[pdpIdx] || BUNDLE_DATA['default'];
  _bundleActive = 0;
  _renderBundleTabs();
  _renderBundleItems(0);
}

function _renderBundleTabs() {
  var tabs = document.getElementById('bundleTabs');
  if (!tabs) return;
  tabs.innerHTML = _bundleCurrent.map((b, i) =>
    `<div class="bundle-tab${i === 0 ? ' active' : ''}" onclick="switchBundle(${i},this)">${b.label}</div>`
  ).join('');
}

function switchBundle(idx, el) {
  _bundleActive = idx;
  document.querySelectorAll('.bundle-tab').forEach(t => t.classList.remove('active'));
  el.classList.add('active');
  _renderBundleItems(idx);
}

function _renderBundleItems(idx) {
  var bundle = _bundleCurrent[idx];
  if (!bundle) return;

  // All items selected by default
  _bundleSelected = bundle.items.map((_, i) => i);

  var row = document.getElementById('bundleItemsRow');
  if (!row) return;

  row.innerHTML = bundle.items.map((item, i) => {
    var isMain = !!item.main;
    var checkSvg = `<svg viewBox="0 0 24 24" width="10" height="10" fill="none" stroke="#fff" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>`;
    var html = `<div class="bundle-item${isMain ? ' main-product' : ''} selected" id="bitem_${i}" onclick="${isMain ? '' : `toggleBundleItem(${i})`}">
      <div class="bundle-item-check">${checkSvg}</div>
      <div class="bundle-item-badge">${isMain ? '★' : i + 1}</div>
      <div class="bundle-item-card">
        <div class="bundle-item-emoji">${item.e}</div>
        <div class="bundle-item-name">${item.n.length > 28 ? item.n.slice(0,26)+'…' : item.n}</div>
        <div class="bundle-item-price">R$ ${item.p.toFixed(2).replace('.', ',')}</div>
      </div>
    </div>`;
    return i < bundle.items.length - 1
      ? html + `<div class="bundle-plus">+</div>`
      : html;
  }).join('');

  _updateBundleTotal(idx);

  // Why strip
  var why = document.getElementById('bundleWhy');
  if (why) why.innerHTML = `<div class="bundle-why-icon">🤖</div><div>${bundle.why.replace('🤖 Kz AI: ', '')}</div>`;
}

function toggleBundleItem(i) {
  var el = document.getElementById('bitem_' + i);
  if (!el) return;
  var selIdx = _bundleSelected.indexOf(i);
  if (selIdx > -1) {
    // Deselect — don't allow fewer than 2 items
    if (_bundleSelected.length <= 2) {
      showToast('⚠️ Selecione ao menos 2 itens no bundle');
      return;
    }
    _bundleSelected.splice(selIdx, 1);
    el.classList.remove('selected');
    var chk = el.querySelector('.bundle-item-check');
    if (chk) chk.innerHTML = '';
  } else {
    _bundleSelected.push(i);
    el.classList.add('selected');
    var chk = el.querySelector('.bundle-item-check');
    var checkSvg = `<svg viewBox="0 0 24 24" width="10" height="10" fill="none" stroke="#fff" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>`;
    if (chk) chk.innerHTML = checkSvg;
  }
  _updateBundleTotal(_bundleActive);
}

function _updateBundleTotal(idx) {
  var bundle = _bundleCurrent[idx];
  if (!bundle) return;
  var selItems = _bundleSelected.map(i => bundle.items[i]).filter(Boolean);
  var totalOrig = selItems.reduce((a, it) => a + it.p, 0);
  // Only apply bundle discount if 2+ items selected
  var discPct = _bundleSelected.length >= 2 ? bundle.discount : 0;
  var totalFinal = totalOrig * (1 - discPct / 100);
  var saving = totalOrig - totalFinal;

  var fmt = v => 'R$ ' + v.toFixed(2).replace('.', ',');
  var el; 
  el = document.getElementById('bundlePriceOriginal');
  if (el) el.textContent = _bundleSelected.length >= 2 ? 'De ' + fmt(totalOrig) : '';
  el = document.getElementById('bundlePriceFinal');
  if (el) el.textContent = fmt(totalFinal);
  el = document.getElementById('bundleSavingBadge');
  if (el) el.textContent = _bundleSelected.length >= 2 ? `Economize ${fmt(saving)} (${discPct}% off)` : 'Selecione 2+ itens';

  // Store for addAll
  window._bundleTotalFinal = totalFinal;
  window._bundleSelItems = selItems;
}

function bundleAddAll() {
  var selItems = window._bundleSelItems || [];
  if (!selItems.length) return;
  var added = 0;
  selItems.forEach(item => {
    if (item.main) return; // main product already in cart from buy flow
    if (typeof addToCart === 'function' && item.idx != null) {
      addToCart(item.idx);
    } else {
      // Custom item not in products[] — add directly to cartItemsData
      if (typeof cartItemsData !== 'undefined') {
        cartItemsData.push({
          id: 'bundle_' + Date.now() + '_' + Math.random().toString(36).slice(2,6),
          e: item.e, n: item.n, s: 'WeKz Bundle', v: 1,
          rawPrice: item.p, qty: 1, _selected: true,
        });
        if (typeof updateCartUI === 'function') updateCartUI();
      }
    }
    added++;
  });
  showToast(`🛍️ ${added} ${added === 1 ? 'item adicionado' : 'itens adicionados'} ao carrinho! Bundle ativo.`);
  // Visual feedback on button
  var btn = document.getElementById('bundleAddBtn');
  if (btn) {
    btn.textContent = '✅ Adicionado!';
    btn.style.background = 'linear-gradient(135deg,#22C55E 0%,#16A34A 100%)';
    setTimeout(() => {
      btn.innerHTML = '<svg viewBox="0 0 24 24" width="15" height="15" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 001.99 1.61h9.72a2 2 0 001.99-1.61L23 6H6"/></svg> Adicionar Todos ao Carrinho';
      btn.style.background = '';
    }, 2500);
  }
}

// ── LIGHTBOX ENGINE ──
let lbAllPhotos=[], lbCurrent=0;
function openLightbox(photos, idx){
  lbAllPhotos=photos.filter(p=>p.type==='img'||p.type==='video');
  lbCurrent=idx;
  _lbShow();
  document.getElementById('revLightbox').classList.add('open');
}
function _lbShow(){
  const p=lbAllPhotos[lbCurrent];
  const img=document.getElementById('lbImg');
  img.src=p.url;
  document.getElementById('lbCaption').textContent=(p.caption||'')+(lbAllPhotos.length>1?` · ${lbCurrent+1}/${lbAllPhotos.length}`:'');
}
function closeLightbox(){document.getElementById('revLightbox').classList.remove('open');}
function lbNav(dir){
  lbCurrent=(lbCurrent+dir+lbAllPhotos.length)%lbAllPhotos.length;
  _lbShow();
}
document.addEventListener('keydown',e=>{
  const lb=document.getElementById('revLightbox');
  if(!lb||!lb.classList.contains('open'))return;
  if(e.key==='Escape')closeLightbox();
  if(e.key==='ArrowRight')lbNav(1);
  if(e.key==='ArrowLeft')lbNav(-1);
});

function renderReviewsMain(data=currentReviewData){
  const g=document.getElementById('reviewsListMain');if(!g)return;

  // Social proof header
  const totalPhotos=REVIEWS_DATA.reduce((a,r)=>a+r.photos.length,0);
  const withMedia=REVIEWS_DATA.filter(r=>r.photos.length>0).length;
  const socialHeader=`<div class="rev-social-proof">
    <div class="rev-social-proof-stat"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="#F59E0B" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg><strong>${data.length}</strong> avaliações nesta página</div>
    <div class="rev-social-proof-stat">📸 <strong>${totalPhotos}</strong> fotos & vídeos de compradores</div>
    <div class="rev-social-proof-stat">✅ <strong>${withMedia}</strong> avaliações com mídia real</div>
    <div class="rev-social-proof-stat" style="margin-left:auto;color:var(--teal);font-weight:600;">⭐ 847 avaliações esta semana</div>
  </div>`;

  // FIX FUNC-01: aplicar paginação — mostrar apenas _revVisible items
  const pagedData = data.slice(0, _revVisible);

  g.innerHTML=socialHeader+pagedData.map(r=>{
    // Build photo gallery
    const MAX_VISIBLE=4;
    let photosHtml='';
    if(r.photos.length){
      const visible=r.photos.slice(0,MAX_VISIBLE);
      const extra=r.photos.length-MAX_VISIBLE;
      const allImgs=r.photos.map((p,i)=>`<div class="rev-photo${p.type==='video'?' rev-video-thumb':''}" onclick="openLightbox(${JSON.stringify(r.photos).replace(/"/g,"'")},${i})" title="${p.caption||''}"><img src="${p.url}" alt="${p.caption||'Foto avaliação'}" loading="lazy"></div>`);
      const visibleHtml=allImgs.slice(0,MAX_VISIBLE).join('');
      const extraBtn=extra>0?`<div class="rev-photo-more" onclick="openLightbox(${JSON.stringify(r.photos).replace(/"/g,"'")},${MAX_VISIBLE})">+${extra}</div>`:'';
      const mediaBadge=r.photos.some(p=>p.type==='video')?'<span class="rev-media-badge">▶ Vídeo</span>':'';
      photosHtml=`<div class="rev-photos">${visibleHtml}${extraBtn}</div>${mediaBadge?'<div style="margin-top:4px;">'+mediaBadge+'</div>':''}`;
    }
    // Tags
    const tagsHtml=r.tags&&r.tags.length?`<div style="display:flex;gap:5px;flex-wrap:wrap;margin-top:8px;">${r.tags.map(t=>`<span style="font-size:10px;background:var(--card2);border:1px solid var(--border);color:var(--muted);padding:2px 8px;border-radius:50px;">${t}</span>`).join('')}</div>`:'';
    return `
    <div class="rev-item">
      <div class="rev-header">
        <div class="rev-avatar">${r.avatar}</div>
        <div><div style="display:flex;align-items:center;gap:6px;"><span class="rev-name">${r.user}</span><span>${r.country||''}</span></div>
          <div style="display:flex;align-items:center;gap:6px;margin-top:2px;"><span class="rev-stars">${'★'.repeat(r.rating)}${'☆'.repeat(5-r.rating)}</span>${r.verified?'<span class="rev-verified">✅ Compra verificada</span>':''}</div>
        </div>
        <span class="rev-date">${r.date}</span>
      </div>
      <div class="rev-title">${r.title}${r.photos.length?`<span class="rev-media-badge" style="margin-left:8px;">📸 ${r.photos.length} ${r.photos.length===1?'foto':'fotos'}</span>`:''}</div>
      <div class="rev-text">${r.text}</div>
      ${photosHtml}
      ${tagsHtml}
      <div class="rev-helpful"><span>Útil para você?</span>
        <button class="rev-helpful-btn" onclick="REVIEWS_DATA.find(x=>x.id===${r.id}).helpful++;renderReviewsMain();showToast('👍 Obrigado!')">👍 Sim (${r.helpful})</button>
        <button class="rev-helpful-btn" onclick="showToast('👎 Registrado')">👎 Não</button>
        <button class="rev-helpful-btn" onclick="showToast('⚑ Reportada')">⚑ Reportar</button>
      </div>
    </div>`}).join('');

  // FIX FUNC-01: gerir visibilidade do botão "Ver mais avaliações"
  const loadBtn = document.getElementById('revLoadMoreBtn');
  if (loadBtn) loadBtn.style.display = data.length > _revVisible ? 'block' : 'none';
}

function filterReviews(filter,el){
  document.querySelectorAll('.rev-filter').forEach(b=>b.classList.remove('active'));el.classList.add('active');
  if(filter==='all')currentReviewData=[...REVIEWS_DATA];
  else if(typeof filter==='number')currentReviewData=REVIEWS_DATA.filter(r=>r.rating===filter);
  else if(filter==='photo')currentReviewData=REVIEWS_DATA.filter(r=>r.photos&&r.photos.length>0);
  else if(filter==='video')currentReviewData=REVIEWS_DATA.filter(r=>r.photos&&r.photos.some(p=>p.type==='video'));
  else if(filter==='verified')currentReviewData=REVIEWS_DATA.filter(r=>r.verified);
  // FIX FUNC-01: reset paginação ao filtrar
  _revVisible = 4;
  renderReviewsMain(currentReviewData);
}

// FIX FUNC-01: paginação real — loadMoreQA delega para qaLoadMore(); loadMoreReviews incrementa _revVisible
function loadMoreQA(){ qaLoadMore(); }
function loadMoreReviews(){
  _revVisible += 4;
  renderReviewsMain(currentReviewData);
}

function toggleAskForm(){
  const f=document.getElementById('askSellerForm');
  f.style.display=f.style.display==='none'?'block':'none';
  if(f.style.display==='block')document.getElementById('askSellerInput').focus();
}

function submitQuestion(){
  const inp=document.getElementById('askSellerInput');const val=inp.value.trim();
  if(!val)return showToast('⚠️ Digite sua pergunta');
  // FIX FUNC-04: persistir no array _qaData principal e re-renderizar
  var newQ = {
    id: 'q_' + Date.now(),
    user: 'Você',
    date: new Date().toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit',year:'numeric'}),
    votes: 0, userVote: 0,
    text: val,
    answer: null, helpfulCount: 0,
    highlighted: false,
  };
  if(typeof _qaData !== 'undefined') {
    _qaData.unshift(newQ);
    _qaFilter = 'all';
    _qaVisible = 5;
    if(typeof renderQA === 'function') renderQA();
  } else {
    // fallback legado
    QA_DATA_LEGACY.unshift({id:Date.now(),user:'Você',avatar:'V',date:'Agora',q:val,a:'',aFrom:'',votes:0,answered:false});
    renderQALegacy();
  }
  inp.value='';toggleAskForm();
  showToast('✅ Pergunta enviada! Resposta em até 24h.');
  // Simulação de resposta automática do vendedor
  setTimeout(()=>{
    if(typeof _qaData !== 'undefined' && _qaData[0].id === newQ.id) {
      _qaData[0].answer = {by:'TechStore',isSeller:true,date:'Agora',text:'Obrigado pela pergunta! Vou verificar e responder em breve. Use o chat para retorno imediato! 😊',helpful:0};
      if(typeof renderQA === 'function') renderQA();
    }
    showToast('💬 Vendedor respondeu sua pergunta!');
  },3500);
}

function toggleReviewForm(){const f=document.getElementById('writeReviewForm');f.style.display=f.style.display==='none'?'block':'none';}

// Upload de foto/vídeo no form de avaliação
let _revUploadFiles=[];
function handleRevUpload(input){
  const area=document.getElementById('revUploadArea');
  Array.from(input.files).forEach(file=>{
    if(_revUploadFiles.length>=6)return showToast('⚠️ Máximo 6 arquivos');
    const isVideo=file.type.startsWith('video');
    const id='rup_'+Date.now()+'_'+Math.random().toString(36).slice(2,6);
    const item=document.createElement('div');
    item.className='rev-preview-item'+(isVideo?' rev-video-thumb':'');
    item.id=id;
    _revUploadFiles.push({id,file});
    if(isVideo){
      item.style.background='var(--card2)';
      item.style.display='flex';item.style.alignItems='center';item.style.justifyContent='center';
      item.innerHTML='<svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="rgba(124,58,237,0.7)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="23 7 16 12 23 17 23 7"/><rect x="1" y="5" width="15" height="14" rx="2"/></svg>';
    } else {
      const reader=new FileReader();
      reader.onload=e=>{
        const img=document.createElement('img');img.src=e.target.result;img.alt='preview';
        item.appendChild(img);
      };
      reader.readAsDataURL(file);
    }
    const rm=document.createElement('div');rm.className='rev-preview-remove';rm.textContent='×';
    rm.onclick=()=>{_revUploadFiles=_revUploadFiles.filter(x=>x.id!==id);item.remove();};
    item.appendChild(rm);
    // Insert before the upload buttons
    const labels=area.querySelectorAll('label');
    area.insertBefore(item,labels[0]);
  });
  input.value='';
}

function pickStar(n){
  selectedStar=n;
  document.querySelectorAll('.star-pick').forEach((s,i)=>{s.textContent=i<n?'★':'☆';s.style.transform=i<n?'scale(1.2)':'scale(1)';});
}

function submitReview(){
  if(!selectedStar)return showToast('⚠️ Selecione uma nota de 1 a 5 ★');
  const titleEl = document.querySelector('#writeReviewForm input[type="text"]');
  const textEl  = document.querySelector('#writeReviewForm textarea');
  const title   = titleEl ? titleEl.value.trim() : '';
  const text    = textEl  ? textEl.value.trim()  : '';
  if(!title) return showToast('⚠️ Adicione um título à sua avaliação');
  if(!text)  return showToast('⚠️ Escreva um comentário sobre o produto');

  const hasMedia=_revUploadFiles.length>0;
  const mediaMsg=hasMedia?` com ${_revUploadFiles.length} ${_revUploadFiles.length===1?'foto':'fotos'}`:' (sem fotos)';

  // FIX FUNC-04: persistir no REVIEWS_DATA e re-renderizar
  const newReview = {
    id: Date.now(),
    user: 'Você',
    avatar: 'V',
    rating: selectedStar,
    title: title,
    text: text,
    date: new Date().toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit',year:'numeric'}),
    verified: false,
    photos: [],
    helpful: 0,
    country: '🇧🇷',
    tags: [],
  };
  REVIEWS_DATA.unshift(newReview);
  currentReviewData = [...REVIEWS_DATA];
  _revVisible = 4;
  renderReviewsMain(currentReviewData);

  showToast('✅ Avaliação publicada'+mediaMsg+'! Obrigado.');
  toggleReviewForm();
  selectedStar=0;_revUploadFiles=[];
  document.querySelectorAll('.star-pick').forEach(s=>{s.textContent='☆';s.style.transform='scale(1)';});
  if(titleEl) titleEl.value='';
  if(textEl)  textEl.value='';
  const area=document.getElementById('revUploadArea');
  if(area)area.querySelectorAll('.rev-preview-item').forEach(el=>el.remove());
}

// ─── ENHANCED CHAT ENGINE ───
const chatBotReplies={
  garantia:'✅ Garantia de 12 meses do fabricante + 90 dias extra WeKz! Qualquer problema, abrimos disputa imediatamente.',
  entrega:'📦 Entregamos para todo o Brasil e 180+ países! Sul/Sudeste: 5-8 dias. Norte/Nordeste: 10-14 dias. Frete grátis acima de R$200.',
  devolucao:'↩️ 30 dias de devolução sem precisar justificar. Frete de retorno por nossa conta. Reembolso em até 5 dias úteis.',
  original:'✅ 100% original com nota fiscal eletrônica e serial verificável. Produto novo, lacrado de fábrica.',
  desconto:'💰 2+ unidades: 8% desconto. 5+ unidades: 12%. Entre em contato para cotação de maior volume!',
  foto:'📸 Claro! Tenho várias fotos adicionais do produto. Posso enviar por e-mail ou pelo nosso chat com anexos.',
  parcelamento:'💳 Sim! Parcelamos em até 12x sem juros no cartão. Pix tem 5% de desconto imediato. Boleto também aceito.',
  defaults:['💬 Ótima pergunta! Vou verificar para você...','📋 Deixa eu confirmar essa informação...','✅ Claro! Em que mais posso ajudar?','🙌 Estou aqui para te ajudar com tudo!'],
};

function getChatReply(msg){
  const l=msg.toLowerCase();
  if(l.includes('garantia'))return chatBotReplies.garantia;
  if(l.includes('entrega')||l.includes('frete')||l.includes('prazo')||l.includes('delivery')||l.includes('shipping'))return chatBotReplies.entrega;
  if(l.includes('devolu')||l.includes('troca')||l.includes('return'))return chatBotReplies.devolucao;
  if(l.includes('original')||l.includes('falso')||l.includes('autênt')||l.includes('genuine'))return chatBotReplies.original;
  if(l.includes('desconto')||l.includes('discount'))return chatBotReplies.desconto;
  if(l.includes('foto')||l.includes('imagem')||l.includes('image')||l.includes('photo'))return chatBotReplies.foto;
  if(l.includes('parcela')||l.includes('juros')||l.includes('pix')||l.includes('boleto'))return chatBotReplies.parcelamento;
  const d=chatBotReplies.defaults;return d[Math.floor(Math.random()*d.length)];
}

// New chat send using textarea
function sendChatMsgNew(){
  const inp=document.getElementById('chatMessageInput');
  const msg=inp.value.trim();
  if(!msg)return;
  appendChatMsgNew(msg,'me');
  inp.value='';
  inp.style.height='';
  // Close emoji picker if open
  const ep=document.getElementById('emojiPicker');
  if(ep)ep.classList.remove('open');
  // Typing indicator
  setTimeout(()=>{
    showTypingIndicator();
    setTimeout(()=>{
      hideTypingIndicator();
      appendChatMsgNew(getChatReply(msg),'seller');
    },1400+Math.random()*800);
  },300);
}

function showTypingIndicator(){
  const msgs=document.getElementById('chatMessages');if(!msgs)return;
  const div=document.createElement('div');
  div.id='typingIndicatorBubble';
  div.className='chat-msg-wrap seller';
  div.innerHTML=`<div class="chat-bubble seller" style="padding:10px 14px;"><div class="typing-dots"><div class="typing-dot"></div><div class="typing-dot"></div><div class="typing-dot"></div></div></div>`;
  msgs.appendChild(div);msgs.scrollTop=msgs.scrollHeight;
}

function hideTypingIndicator(){
  const t=document.getElementById('typingIndicatorBubble');
  if(t)t.remove();
}

function appendChatMsgNew(text,from){
  const msgs=document.getElementById('chatMessages');if(!msgs)return;
  const time=new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'});
  const wrap=document.createElement('div');
  wrap.className=`chat-msg-wrap ${from}`;
  const safeText=escapeHtml(text); // Sprint 0.1 fix S1 (escapeHtml para texto simples)
  if(from==='seller'){
    // FIX: usar class em vez de id para evitar IDs duplicados no DOM
    wrap.innerHTML=`<div class="chat-bubble-seller-name chat-seller-name-bubble"></div><div class="chat-bubble seller">${safeText}</div><div class="chat-time">${time}</div>`;
    const nameEl=wrap.querySelector('.chat-seller-name-bubble');
    const sn=document.getElementById('chatSellerName');
    if(nameEl&&sn)nameEl.textContent=sn.textContent;
  } else {
    wrap.innerHTML=`<div class="chat-bubble me">${safeText}</div><div class="chat-time chat-msg-status read">Você · ${time} · ✓✓</div>`;
  }
  msgs.appendChild(wrap);msgs.scrollTop=msgs.scrollHeight;
  // Show floating badge if panel not visible
  const fcbBadge=document.getElementById('fcbBadge');
  if(from==='seller'&&fcbBadge){
    const badge=parseInt(fcbBadge.textContent||'0')+1;
    fcbBadge.textContent=badge;
  }
}

