function initInteractionPanel(productIndex){
  /* v2.9.19 — use productIndex explicitly (never currentPdpIndex) so that
     even if the global drifted between scheduling and execution, the widget
     always matches the product that was passed in. */
  renderQALegacy();renderReviewsMain();
  const p=products[productIndex];
  if(p){
    const sellerName = p.s || 'Vendedor';
    const av=document.getElementById('chatSellerAvatar');
    const nm=document.getElementById('chatSellerName');
    if(av)av.textContent=(sellerName[0]||'V').toUpperCase();
    if(nm)nm.textContent=sellerName+' Oficial';

    /* Sync sticky bar price (mobile) — keeps widget and bar in lockstep */
    const msbP=document.getElementById('msbPrice');
    const msbO=document.getElementById('msbPriceOld');
    const msbD=document.getElementById('msbPriceOff');
    if(msbP) msbP.textContent=formatPrice(p.p);
    if(msbO) msbO.textContent=formatPrice(p.op||p.p);
    if(msbD) msbD.textContent='-'+(p.off||0)+'%';
    // [Loja Oficial / Marca Verificada] Atualiza a faixa de confiança do vendedor
    const trustStrip=document.querySelector('#page-product .seller-verified-strip');
    if(trustStrip){
      if(isOfficialStore(sellerName)){
        trustStrip.innerHTML =
          '<span class="svs-icon">🏅</span>' +
          '<span class="svs-text"><strong style="color:var(--text);">' + sellerName + '</strong> é uma <strong style="color:#A78BFA;">Loja Oficial WeKz</strong> · 4.9★ · 18.4k vendas · 98% satisfação</span>' +
          '<span class="svs-badge" style="color:#A78BFA;">🏅 Oficial</span>';
        trustStrip.style.cursor='default';
        trustStrip.onclick=null;
        trustStrip.style.background='rgba(124,58,237,0.07)';
        trustStrip.style.borderColor='rgba(124,58,237,0.2)';
      } else {
        trustStrip.innerHTML =
          '<span class="svs-icon">🛡️</span>' +
          '<span class="svs-text">Vendedor <strong style="color:var(--text);">verificado WeKz</strong> · 4.7★ · satisfação acima da média</span>' +
          '<span class="svs-badge" style="color:var(--teal);">⭐ Tornar-se Loja Oficial</span>';
        trustStrip.style.cursor='pointer';
        trustStrip.style.background='rgba(34,197,94,0.07)';
        trustStrip.style.borderColor='rgba(34,197,94,0.2)';
        trustStrip.onclick=function(){ openPremiumPlansModal(); };
      }
    }
    // Update context
    const ctxEmoji=document.getElementById('chatCtxEmoji');
    const ctxName=document.getElementById('chatCtxName');
    const ctxPrice=document.getElementById('chatCtxPrice');
    if(ctxEmoji){ ctxEmoji.setAttribute('emoji', p.e || '📦'); if(p.img){ctxEmoji.setAttribute('src',p.img);} else {ctxEmoji.removeAttribute('src');} }
    if(ctxName)ctxName.textContent=p.n;
    if(ctxPrice)ctxPrice.textContent=formatPrice(p.p);
    // Update nego price
    const negoP=document.getElementById('negoCurrentPrice');
    if(negoP)negoP.textContent=formatPrice(p.p);
    // Hint buttons
    ['0.95','0.90','0.85'].forEach((r,i)=>{
      const hints=document.querySelectorAll('.nego-hint');
      if(hints[i]){
        const disc=[5,10,15][i];
        hints[i].textContent=`-${disc}% · ${formatPrice(p.p*parseFloat(r))}`;
        hints[i].onclick=()=>{document.getElementById('negoOfferInput').value=(p.p*parseFloat(r)).toFixed(2);};
      }
    });
  }
  // Reset chat
  const msgs=document.getElementById('chatMessages');
  const sellerLabel = p ? (p.s||'Vendedor')+' Oficial' : 'Vendedor';
  if(msgs){msgs.innerHTML=`
    <div class="chat-msg-wrap seller">
      <div class="chat-bubble-seller-name">${sellerLabel}</div>
      <div class="chat-bubble seller">Olá! 👋 Posso ajudar com este produto?</div>
      <div class="chat-time">Agora</div>
    </div>
    <div class="chat-msg-wrap seller">
      <div class="chat-bubble seller">Estoque disponível, produto 100% original com nota fiscal! 📦✅</div>
      <div class="chat-time">Agora</div>
    </div>`;}
}


function showPage(id){
  // ── FIX: Gerenciar classe kzlive-active ao trocar páginas ──
  // Remove quando sai de live, adiciona quando entra
  if(id === 'live'){
    document.body.classList.add('kzlive-active');
  } else {
    document.body.classList.remove('kzlive-active');
  }
  
  // ── FIX SEC-P01: guard para páginas protegidas ──
  // Impede acesso ao admin via console ou URL sem role adequada.
  const protectedPages = ['admin-dashboard'];
  if(protectedPages.includes(id)){
    var role = (window.currentAdminUser || window.currentUser || {}).role;
    if(role !== 'superadmin' && role !== 'admin'){
      showToast && showToast('⛔ Acesso negado — autenticação necessária');
      id = 'home'; // fallback seguro
    }
  }
  document.documentElement.scrollTop = 0; document.body.scrollTop = 0; // reset imediato antes de trocar
  document.body.setAttribute('data-view', id); // [v2.9.31] ativa body[data-view="product"] CSS p/ sticky bar mobile
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  const pg = document.getElementById('page-'+id);
  // FIX MELHORIA-04: fallback seguro para página não encontrada
  if(!pg){
    showToast && showToast('⚠️ Página não encontrada');
    const fallback = document.getElementById('page-home');
    if(fallback) fallback.classList.add('active');
    return;
  }
  pg.classList.add('active'); pg.scrollTop = 0; // reset container próprio se houver
  window.scrollTo({top:0,behavior:'instant'});
  if(id==='product')renderReviews();
  if(id==='checkout'){ _ckoutStep=1; _ckoutGoto(1); _ckoutPopulateSidebar(); }
  if(id==='cart'){ setTimeout(function(){ if(typeof updateCartUI==='function') updateCartUI(); renderCouponActiveBanner(); },60); }
  if(id==='tracking'){ setTimeout(_initTracking,50); }
  if(id==='pg-flash')renderFlashPage();
  if(id==='wishlist'){
    var activeWTab = document.querySelector('.wishlist-tab-btn.active');
    var wTabName = activeWTab ? (activeWTab.id === 'wishTabStores' ? 'stores' : 'products') : 'products';
    if(wTabName === 'stores'){ renderWishlistStores(); } else { renderWishlist(); }
  }
  updateFloatingChat();
  // [v2.2.0] Controlo visibilidade do botão flutuante do Kz Negotiator
  var floatBtn = document.getElementById('kzNegFloatingBtn');
  if (floatBtn) {
    var negOpen = (function(){
      var ov = document.getElementById('kzNegotiatorOverlay');
      return ov && ov.classList.contains('open');
    })();
    floatBtn.style.display = (id === 'product' && !negOpen) ? 'flex' : 'none';
  }
  setTimeout(function(){ if(typeof initAllScrollFades==="function") initAllScrollFades(); }, 80);
}

