function normalize(str) {
  return (str || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function wkzSearch(query) {
  var inp     = document.getElementById('spInput');
  var clear   = document.getElementById('spClear');
  var sugg    = document.getElementById('spSuggestions');
  var results = document.getElementById('spResults');
  var grid    = document.getElementById('spGrid');
  var empty   = document.getElementById('spEmpty');
  var meta    = document.getElementById('spMeta');

  var q = (query || '').trim();

  // Mostra/oculta botão de limpar
  if(clear) clear.style.display = q.length ? 'flex' : 'none';

  if(!q) {
    // Sem query → mostra sugestões e banner do Kz
    sugg.style.display    = 'block';
    results.style.display = 'none';
    var banner = document.getElementById('spKzBanner');
    if(banner) banner.style.display = 'flex';
    return;
  }

  // Tem query → esconde sugestões e banner, mostra resultados
  sugg.style.display    = 'none';
  results.style.display = 'block';
  var banner = document.getElementById('spKzBanner');
  if(banner) banner.style.display = 'none';

  // Busca: filtra pelo nome, loja ou categoria de emoji (normalizado, sem acentos)
  var qLow = normalize(q);
  var list = products.filter(function(p){
    var catName = normalize(_spEmojiCat[p.e] || '');
    return (
      normalize(p.n).includes(qLow) ||
      normalize(p.s).includes(qLow) ||
      catName.includes(qLow)
    );
  });

  if(list.length === 0) {
    grid.innerHTML = '';
    empty.style.display = 'flex';
    empty.style.flexDirection = 'column';
    empty.style.alignItems    = 'center';
    meta.innerHTML = '';
    return;
  }

  empty.style.display = 'none';

  // Meta line
  meta.innerHTML = 'Exibindo <strong>' + list.length + '</strong> resultado' +
    (list.length !== 1 ? 's' : '') + ' para <strong>"' + q + '"</strong>';

  // Reutiliza a lógica de card de renderProducts
  var catMap = _spCatMap;
  var emojiCatMap = {
    '📱':'eletronicos','💻':'eletronicos','🎧':'eletronicos','⌚':'eletronicos',
    '📷':'eletronicos','🖥️':'eletronicos','⌨️':'eletronicos',
    '👟':'esportes','⚽':'esportes','🧴':'beleza','💄':'beleza',
    '🎮':'games','🪑':'casa','🏠':'casa',
    '📚':'livros','👗':'moda','🐾':'pet','👶':'bebe','🚗':'automotivo'
  };
  grid.innerHTML = list.map(function(p){
    var cat      = catMap[p.s] || emojiCatMap[p.e] || 'outros';
    var nameLow  = p.n.toLowerCase();
    var realIdx  = products.indexOf(p);
    return '<div class="product-card" data-category="' + cat + '" data-name="' + nameLow + '" onclick="openProduct(' + realIdx + ')">' +
      '<div class="product-img"><wkz-product-image src="' + (p.img||'') + '" emoji="' + p.e + '" alt="' + p.n + '"></wkz-product-image>' +
        '<div class="product-badges">' +
          (p.badge==='sale' ? '<span class="badge badge-sale">SALE</span>' : '') +
          (p.badge==='new'  ? '<span class="badge badge-new">NOVO</span>'  : '') +
          (p.badge==='hot'  ? '<span class="badge badge-hot">HOT</span>'   : '') +
          (p._sponsored ? '<span class="badge badge-ad">📢 Patrocinado</span>' : '') +
          ((p._frete||FRETE_GRATIS_SELLERS.includes(p.s)) ? '<span class="badge badge-frete">🚚 Grátis</span>' : '') +
          (Object.values(SELLER_COUPONS).some(function(c){return c.seller===p.s;}) ? '<span class="badge badge-coupon">🏷️ Cupom</span>' : '') +
        '</div>' +
        '<button class="product-wish" onclick="event.stopPropagation();wishToggle(this,' + realIdx + ',event)">♡</button>' +
      '</div>' +
      '<div class="product-info">' +
        '<div class="product-name">' + p.n + '</div>' +
        '<div class="product-store"><span class="store-verified">✅</span>' + p.s + (isOfficialStore(p.s)?'<span class="store-official-tag">🏅 Loja Oficial</span>':'') + '</div>' +
        '<div class="product-price">' +
          '<span class="price-main">' + formatPrice(p.p) + '</span>' +
          '<span class="price-old">'  + formatPrice(p.op) + '</span>' +
          '<span class="price-off">-' + p.off + '%</span>' +
        '</div>' +
        '<div class="product-meta">' +
          '<div class="product-stars"><span class="stars">★★★★★</span> ' + p.r + '</div>' +
          '<div class="product-sales">' + p.sales + ' vendidos</div>' +
        '</div>' +
        '<button class="btn-add" onclick="event.stopPropagation();btnFeedback(this,()=>addToCart(' + realIdx + '))">' +
          '<span class="btn-spinner"></span><span class="btn-check">✓</span>' +
          '<span class="btn-label">Adicionar ao carrinho</span></button>' +
        '<button class="btn-buy" onclick="event.stopPropagation();btnFeedback(this,()=>{addToCart(' + realIdx + ');setTimeout(()=>showPage(\'cart\'),400)},{loadingMs:500,successMs:600})">' +
          '<span class="btn-spinner"></span><span class="btn-check">✓</span>' +
          '<span class="btn-label">⚡ Comprar Agora</span></button>' +
      '</div>' +
    '</div>';
  }).join('');
}

function wkzSearchClear() {
  var inp = document.getElementById('spInput');
  if(inp){ inp.value = ''; inp.focus(); }
  wkzSearch('');
}

function wkzSearchFill(term) {
  var inp = document.getElementById('spInput');
  if(inp){ inp.value = term; }
  wkzSearch(term);
}

function renderFlashPage(){
  const g = document.getElementById('flashPageGrid');
  if(!g) return;
  g.innerHTML = flashItems.map((f,i) => {
    const stockColor = (f.stock||99) <= 5 ? '#EF4444' : (f.stock||99) <= 15 ? '#F59E0B' : '#22C55E';
    const stockMsg = (f.stock||99) <= 5 ? `🔥 ${f.stock} restam!` : (f.stock||99) <= 15 ? `⚡ ${f.stock} disponíveis` : '✅ Em estoque';
    const stars = '★'.repeat(Math.round(f.rating||5)) + '☆'.repeat(5-Math.round(f.rating||5));
    return `
    <div style="background:var(--card);border:1px solid var(--border);border-radius:16px;overflow:hidden;display:flex;flex-direction:column;transition:all 0.22s;" onmouseover="this.style.borderColor='rgba(255,107,53,0.5)';this.style.transform='translateY(-4px)';this.style.boxShadow='0 12px 30px rgba(255,107,53,0.12)'" onmouseout="this.style.borderColor='var(--border)';this.style.transform='';this.style.boxShadow=''">
      <!-- image area -->
      <div style="background:linear-gradient(135deg,rgba(255,107,53,0.08),rgba(255,45,122,0.08));display:flex;align-items:center;justify-content:center;font-size:60px;height:130px;position:relative;cursor:pointer;" onclick="openFlashProduct(${i})">
        ${f.e}
        <span style="position:absolute;top:10px;left:10px;background:linear-gradient(90deg,#FF6B35,#FF2D7A);color:#fff;font-size:10px;font-weight:800;padding:3px 9px;border-radius:20px;">⚡ -${f.off||''}% OFF</span>
        <span style="position:absolute;top:10px;right:10px;font-size:10px;font-weight:600;color:${stockColor};background:var(--card);padding:3px 8px;border-radius:20px;border:1px solid ${stockColor};">${stockMsg}</span>
      </div>
      <!-- info -->
      <div style="padding:14px;flex:1;display:flex;flex-direction:column;gap:8px;cursor:pointer;" onclick="openFlashProduct(${i})">
        <div style="font-size:13px;font-weight:600;line-height:1.4;">${f.n}</div>
        <div style="font-size:11px;color:var(--muted);">🏪 ${f.s||'Flash Sale'}</div>
        <div style="color:#F59E0B;font-size:11px;">${stars} <span style="color:var(--muted);">${f.rating} (${(f.reviews||0).toLocaleString()})</span></div>
        <div style="font-size:11px;color:var(--muted);line-height:1.5;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;">${f.desc||''}</div>
        <div style="display:flex;align-items:center;gap:8px;margin-top:auto;padding-top:4px;">
          <span style="font-family:'DM Sans',sans-serif;font-size:20px;font-weight:800;color:#FF6B35;">${f.p}</span>
          <span style="font-size:11px;color:var(--muted);text-decoration:line-through;">${f.o}</span>
        </div>
      </div>
      <!-- action buttons -->
      <div style="padding:0 14px 14px;display:flex;flex-direction:column;gap:6px;">
        <div style="display:flex;gap:6px;">
          <button onclick="openFlashProduct(${i})" style="flex:1;padding:9px;background:var(--card2);border:1px solid var(--border);color:var(--text);border-radius:9px;font-size:12px;font-weight:600;cursor:pointer;" onmouseover="this.style.borderColor='rgba(255,107,53,0.4)'" onmouseout="this.style.borderColor='var(--border)'">👁 Detalhes</button>
          <button class="btn-add" style="flex:2;margin-top:0;border-radius:9px;font-size:12px;" onclick="event.stopPropagation();btnFeedback(this,()=>addFlashToCart(${i}))"><span class="btn-spinner"></span><span class="btn-check">✓</span><span class="btn-label"><span class="wkz-icon wkz-icon-cart"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 001.99 1.61h9.72a2 2 0 001.99-1.61L23 6H6"/></svg></span> Adicionar</span></button>
        </div>
        <button class="btn-flash-buy" onclick="event.stopPropagation();btnFeedback(this,()=>{addFlashToCart(${i});setTimeout(()=>showPage('cart'),500)},{loadingMs:600,successMs:700})"><span class="btn-spinner"></span><span class="btn-check">✓</span><span class="btn-label"><span class="wkz-icon wkz-icon-zap"><svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polygon points="13,2 3,14 12,14 11,22 21,10 12,10 13,2"/></svg></span> Comprar Agora</span></button>
      </div>
    </div>`;
  }).join('');
}

/* v2.9.19 — geração de produto: cada chamada a openProduct() incrementa
   este contador. Os callbacks setTimeout só executam se a geração ainda
   coincide — evita que um produto aberto rapidamente após outro aplique
   dados (vendedor, preço, widget de chat) do produto anterior. */
var _pdpGeneration = 0;


/* ── 2.2: PDP + Decoradores + Q&A + Cupons + Checkout/Devoluções ─────────
   openProduct() [base] + cadeia de decoradores (KZ Price Alert Engine,
   KZ Comparator Engine, KZ Tour Engine) — PRESERVADOS EM CADEIA, não são
   duplicatas: cada um captura a versão anterior de window.openProduct e
   adiciona comportamento, terminando com _origOpenProductComp(i) no fim.
   showToast V1 morta (duplicata real — Patch 3) REMOVIDA; V2 já vive em
   wkz-core.js.
   Origem monólito: linhas 23189–28105
   ─────────────────────────────────────────────────────────────────────── */
function openProduct(i){
  const p=products[i];
  if(!p) return;
  currentPdpIndex = i;
  /* Incrementa geração ANTES de qualquer setTimeout */
  var myGen = ++_pdpGeneration;

  setTimeout(()=>{ if(_pdpGeneration===myGen) initBundles(i); },80);
  setTimeout(()=>{
    /* Abandona silenciosamente se outro produto foi aberto entretanto */
    if(_pdpGeneration !== myGen) return;
    renderStockWidget(i);
    // Update qty max label
    var p=products[i];
    var qtyMax=document.getElementById('pdpQtyMax');
    if(qtyMax&&p) qtyMax.textContent='Estoque: '+(p.stock===0?'Esgotado':(p.stock+' unidades'));
    // Reset qty to 1 on product change
    var qn=document.getElementById('qtyNum'); if(qn) qn.textContent='1';
    // Reset stock toast shown flag for new product
    window['stk_shown_'+i]=false;
    // Trigger stock toast immediately if critical/low
    if(p){renderStockWidget(i);}
    // Init price history chart
    initPriceHistory(i);
    // Pontos / cashback badge
    renderPdpPointsBadge(i);
    // Q&A
    initQA(i);
  },100);
  const pdpEmoji=document.getElementById('pdpEmoji');
  const pdpTitle=document.getElementById('pdpTitle');
  const pdpBrand=document.getElementById('pdpBrand');
  const pdpPrice=document.getElementById('pdpPrice');
  if(pdpEmoji){ pdpEmoji.setAttribute('emoji', p.e || '📦'); if(p.img){pdpEmoji.setAttribute('src',p.img);} else {pdpEmoji.removeAttribute('src');} }
  if(pdpTitle) pdpTitle.textContent=p.n;
  if(pdpBrand) pdpBrand.textContent=(p.s||'')+' Oficial';
  if(pdpPrice){ pdpPrice.textContent=formatPrice(p.p); pdpPrice.style.cssText=''; }
  // Sync "Vendido por" disclaimer seller name
  const pdpSellerNameEl=document.getElementById('pdpSellerName');
  if(pdpSellerNameEl) pdpSellerNameEl.textContent=(p.s||'Vendedor')+' Oficial';
  // Update old price and discount badge if those elements exist
  const pdpOld=document.querySelector('.pdp-price-old');
  const pdpOff=document.querySelector('.pdp-price-off');
  if(pdpOld) pdpOld.textContent=formatPrice(p.op||p.p);
  if(pdpOff) pdpOff.textContent='-'+(p.off||0)+'%';
  // v2.9.19: Sync mobile sticky bar prices
  const msbP=document.getElementById('msbPrice');
  const msbO=document.getElementById('msbPriceOld');
  const msbD=document.getElementById('msbPriceOff');
  if(msbP) msbP.textContent=formatPrice(p.p);
  if(msbO) msbO.textContent=formatPrice(p.op||p.p);
  if(msbD) msbD.textContent='-'+Math.floor(p.off||0)+'%';
  // [v2.9.31] Sync linha de parcelas com preço exato do produto
  var _instEl = document.getElementById('pdpInstallmentLine');
  if(_instEl && p.p){
    var _inst = p.p / 12;
    var _instFmt = 'R$ ' + _inst.toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g,'.');
    _instEl.textContent = '💳 12x de ' + _instFmt + ' sem juros';
  }
  // v2.9.19: Sync breadcrumb title
  const bcTitle=document.getElementById('pdpBcTitle');
  if(bcTitle) bcTitle.textContent=(p.n||'').substring(0,40)+(p.n&&p.n.length>40?'…':'');
  document.querySelectorAll('.pdp-thumb').forEach((t,ti)=>{
    t.textContent=['📱','🔋','📷','🎧'][ti]||'📦';
  });
  setTimeout(()=>{
    if(_pdpGeneration !== myGen) return;
    // CRO-02 (v3.0.0): rastreia visualização + renderiza relacionados/vistos recentemente
    wkzTrackRecentlyViewed(i);
    wkzRenderRelatedProducts(i);
    wkzRenderRecentlyViewed(i);
  },90);
  showPage('product');
  // Init interaction panel after page shown — guarded by generation token
  setTimeout(()=>{ if(_pdpGeneration === myGen) initInteractionPanel(i); },100);
}

/* filterCat — definida no bloco WEKZ SEARCH & FILTER SYSTEM abaixo */
/* ═══════════════════════════════════════════════════════════════
   WEKZ SEARCH & FILTER SYSTEM v1.1.0
   ─ filterCatKey  : clique em card de categoria → filtra grid
   ─ filterCat     : retrocompat (banner, nav, trending tags)
   ─ topbarRealTimeSearch : busca em tempo real na topbar
   ─ applyWekzFilter : motor central + "não encontrado"
   ═══════════════════════════════════════════════════════════════ */

