/* ── SVG illustrations for empty states ── */
var _WKZ_NF_SVG_SEARCH = '<svg viewBox="0 0 80 80" width="72" height="72" fill="none" xmlns="http://www.w3.org/2000/svg"><circle cx="34" cy="34" r="22" stroke="rgba(0,180,171,0.35)" stroke-width="3"/><circle cx="34" cy="34" r="14" fill="rgba(0,180,171,0.06)" stroke="rgba(0,180,171,0.15)" stroke-width="1.5"/><line x1="50" y1="50" x2="66" y2="66" stroke="rgba(0,180,171,0.45)" stroke-width="3.5" stroke-linecap="round"/><path d="M29 34 h10 M34 29 v10" stroke="rgba(0,180,171,0.5)" stroke-width="2" stroke-linecap="round"/></svg>';
var _WKZ_NF_SVG_CAT    = '<svg viewBox="0 0 80 80" width="72" height="72" fill="none" xmlns="http://www.w3.org/2000/svg"><rect x="12" y="22" width="56" height="42" rx="6" fill="rgba(124,58,237,0.06)" stroke="rgba(124,58,237,0.3)" stroke-width="2"/><path d="M12 33h56" stroke="rgba(124,58,237,0.2)" stroke-width="1.5"/><rect x="22" y="43" width="14" height="10" rx="3" fill="rgba(124,58,237,0.15)" stroke="rgba(124,58,237,0.35)" stroke-width="1.5"/><rect x="44" y="43" width="14" height="10" rx="3" fill="rgba(124,58,237,0.15)" stroke="rgba(124,58,237,0.35)" stroke-width="1.5"/><path d="M32 16 l8 6 8-6" stroke="rgba(124,58,237,0.3)" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/><circle cx="58" cy="26" r="4" fill="rgba(124,58,237,0.08)" stroke="rgba(124,58,237,0.4)" stroke-width="1.5"/><path d="M57 26 h2 M58 25 v2" stroke="rgba(124,58,237,0.5)" stroke-width="1.2" stroke-linecap="round"/></svg>';

function ensureNotFoundBlock(){
  const g = document.getElementById('productsGrid');
  if(!g || g.querySelector('#wkz-not-found')) return;
  const div = document.createElement('div');
  div.id = 'wkz-not-found';
  // Content set dynamically by _updateNotFoundContent() on each filter run
  g.appendChild(div);
}

function _updateNotFoundContent(isCatFilter){
  const div = document.getElementById('wkz-not-found');
  if(!div) return;
  if(isCatFilter){
    // ── Estado: categoria selecionada mas sem produtos cadastrados ──
    const catLabel = _wkzActiveCat.charAt(0).toUpperCase() + _wkzActiveCat.slice(1);
    div.innerHTML =
      '<div class="nf-svg">' + _WKZ_NF_SVG_CAT + '</div>' +
      '<div class="nf-title">Nenhum produto em <span style=\'color:var(--teal)\'>' + catLabel + '</span> ainda.</div>' +
      '<div class="nf-sub">Estamos ampliando nosso catálogo! Enquanto isso, confira outras categorias ou veja as ofertas do momento.</div>' +
      '<div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;">' +
        '<button class="nf-cta" onclick="clearWekzFilter()" title="Voltar para todos os produtos">' +
          '<svg viewBox=\'0 0 24 24\' width=\'13\' height=\'13\' fill=\'none\' stroke=\'currentColor\' stroke-width=\'2\' stroke-linecap=\'round\' stroke-linejoin=\'round\'><polyline points=\'15,18 9,12 15,6\'/></svg>' +
          ' Ver todos os produtos' +
        '</button>' +
        '<button class="nf-cta" style="background:var(--card2);border:1px solid var(--border);color:var(--text);" onclick="showPage(\'pg-flash\')" title="Ver ofertas relâmpago">⚡ Ofertas Relâmpago</button>' +
      '</div>';
  } else {
    // ── Estado: busca sem resultados ──
    div.innerHTML =
      '<div class="nf-svg">' + _WKZ_NF_SVG_SEARCH + '</div>' +
      '<div class="nf-title">Nenhum produto encontrado.</div>' +
      '<div class="nf-sub">Tente palavras diferentes ou navegue por categoria. Nossas <strong>ofertas relâmpago</strong> podem ter o que você procura com super desconto!</div>' +
      '<div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;">' +
        '<button class="nf-cta" onclick="showPage(\'pg-flash\')">⚡ Ver Ofertas Relâmpago</button>' +
        '<button class="nf-cta" style="background:var(--card2);border:1px solid var(--border);color:var(--text);" onclick="clearWekzFilter()">✕ Limpar Filtros</button>' +
      '</div>';
  }
}

function _updateSectionFilterBadge(){
  const header = document.querySelector('#products-sec .section-header');
  if(!header) return;
  let badge = document.getElementById('wkz-filter-badge');
  if(_wkzActiveCat || _wkzSearchTerm){
    if(!badge){
      badge = document.createElement('span');
      badge.id = 'wkz-filter-badge';
      badge.className = 'wkz-active-filter-badge';
      badge.onclick = clearWekzFilter;
      header.appendChild(badge);
    }
    const catLabel = _wkzActiveCat ? (' ' + (_wkzActiveCat.charAt(0).toUpperCase() + _wkzActiveCat.slice(1))) : '';
    const termLabel = _wkzSearchTerm ? (' "' + _wkzSearchTerm + '"') : '';
    badge.textContent = '✕ Filtro:' + catLabel + termLabel;
  } else {
    if(badge) badge.remove();
  }
}

function applyWekzFilter(){
  const g = document.getElementById('productsGrid');
  if(!g) return;
  ensureNotFoundBlock();

  const cards = Array.from(g.querySelectorAll('.product-card'));
  const term  = _wkzSearchTerm.trim().toLowerCase();
  const cat   = _wkzActiveCat;

  let visibleCount = 0;

  cards.forEach(card => {
    const cardCat  = (card.dataset.category || '').toLowerCase();
    const cardName = (card.dataset.name || '').toLowerCase();
    const catMatch  = !cat  || cardCat === cat;
    const termMatch = !term || cardName.includes(term) || cardCat.includes(term);

    if(catMatch && termMatch){
      card.classList.remove('wkz-hidden');
      card.classList.add('wkz-visible');
      visibleCount++;
    } else {
      card.classList.add('wkz-hidden');
      card.classList.remove('wkz-visible');
    }
  });

  const nf = document.getElementById('wkz-not-found');
  if(nf){
    nf.style.display = visibleCount === 0 ? 'flex' : 'none';
    if(visibleCount === 0) _updateNotFoundContent(!!cat && !term); /* cat-only = category empty state */
  }
  _updateSectionFilterBadge();
}

function filterCatKey(key, label, el){
  if(_wkzActiveCat === key){
    _wkzActiveCat = '';
    document.querySelectorAll('.cat-item').forEach(c => c.classList.remove('cat-active'));
    showToast('✕ Filtro removido');
  } else {
    _wkzActiveCat = key;
    document.querySelectorAll('.cat-item').forEach(c => c.classList.remove('cat-active'));
    if(el) el.classList.add('cat-active');
    showToast('🔍 Categoria: ' + label);
  }
  showPage('home');
  setTimeout(() => {
    const sec = document.getElementById('products-sec');
    if(sec) sec.scrollIntoView({behavior:'smooth'});
    applyWekzFilter();
  }, 120);
}

function filterCat(label){
  const key = CAT_KEY_MAP[label] || label.toLowerCase().replace(/[\s&]/g,'');
  const el  = document.querySelector('.cat-item[data-cat-key="' + key + '"]');
  filterCatKey(key, label, el);
}

function clearWekzFilter(){
  _wkzActiveCat  = '';
  _wkzSearchTerm = '';
  document.querySelectorAll('.cat-item').forEach(c => c.classList.remove('cat-active'));
  const topInp = document.getElementById('topbarSearchInput');
  if(topInp) topInp.value = '';
  applyWekzFilter();
  showToast('🔄 Filtros limpos');
}

function topbarRealTimeSearch(val){
  _wkzSearchTerm = val;
  const homePage = document.getElementById('page-home');
  if(homePage && !homePage.classList.contains('active')){
    showPage('home');
    setTimeout(() => {
      applyWekzFilter();
      const sec = document.getElementById('products-sec');
      if(sec) sec.scrollIntoView({behavior:'smooth'});
    }, 220);
    return;
  }
  applyWekzFilter();
  if(val.trim()){
    const sec = document.getElementById('products-sec');
    if(sec) sec.scrollIntoView({behavior:'smooth', block:'start'});
  }
}

/* Re-apply filter after any re-render */
document.addEventListener('DOMContentLoaded', function(){
  const gridObs = new MutationObserver(function(){
    if(_wkzActiveCat || _wkzSearchTerm){
      requestAnimationFrame(applyWekzFilter);
    }
  });
  const g = document.getElementById('productsGrid');
  if(g) gridObs.observe(g, {childList: true});

  /* Wire up topbar search input */
  const topInput = document.querySelector('[data-wkz-topbar-search]') || document.getElementById('topbarSearchInput');
  if(topInput){
    /* Remove duplicated handler if already wired via inline oninput */
    topInput.addEventListener('input', function(){ topbarRealTimeSearch(this.value); });
    topInput.addEventListener('keydown', function(e){
      if(e.key === 'Escape'){ this.value=''; topbarRealTimeSearch(''); }
    });
  }
});

/* ══════════════════════════════════════════════════════════
   WEKZ v1.3.0 — CART SELECTION + SAVE FOR LATER + OVERLAYS
   ══════════════════════════════════════════════════════════ */

/* ─── DATA ─── */
var savedForLaterData = [];

/* ─── CART ITEM TOGGLE SELECT ─── */
function cartItemToggleSelect(idx, checked) {
  if(!cartItemsData[idx]) return;
  cartItemsData[idx]._selected = checked;
  // Update visual
  const el = document.getElementById('cart-item-' + idx);
  if(el) el.classList.toggle('cart-item-selected', checked);
  syncCartSelection();
}

function cartToggleSelectAll(checked) {
  cartItemsData.forEach(c => { c._selected = checked; });
  renderCart();
  syncCartSelection();
}

function syncCartSelection() {
  const total = cartItemsData.length;
  const selected = cartItemsData.filter(c => c._selected !== false).length;
  const countEl = document.getElementById('cartSelectedCount');
  if(countEl) countEl.textContent = selected + ' selecionado' + (selected !== 1 ? 's' : '');

  // Update select-all checkbox state
  const allCb = document.getElementById('cartSelectAll');
  if(allCb) {
    allCb.indeterminate = selected > 0 && selected < total;
    allCb.checked = selected === total && total > 0;
  }

  // Update selection note in summary
  const noteEl = document.getElementById('cartSelectionNote');
  const noteCntEl = document.getElementById('cartSelectionNoteCount');
  if(noteEl && noteCntEl){
    if(selected < total && selected > 0){
      noteEl.style.display = 'block';
      noteCntEl.textContent = selected;
    } else {
      noteEl.style.display = 'none';
    }
  }
}

/* ─── BUY SELECTED ─── */
function cartBuySelected() {
  const sel = cartItemsData.filter(c => c._selected !== false);
  if(sel.length === 0) return showToast('⚠️ Selecione ao menos um produto');
  openCheckout(false);
}

/* ─── REMOVE SELECTED ─── */
function cartRemoveSelected() {
  const beforeLen = cartItemsData.length;
  for(let i = cartItemsData.length - 1; i >= 0; i--){
    if(cartItemsData[i]._selected !== false) cartItemsData.splice(i, 1);
  }
  const removed = beforeLen - cartItemsData.length;
  if(removed > 0) showToast('🗑️ ' + removed + ' produto(s) removido(s)');
  updateCartUI();
}

/* ─── SAVE FOR LATER ─── */
function cartSaveSelected() {
  const sel = cartItemsData.filter(c => c._selected !== false);
  if(sel.length === 0) return showToast('⚠️ Selecione ao menos um produto');
  sel.forEach(item => savedForLaterData.push({...item}));
  for(let i = cartItemsData.length - 1; i >= 0; i--){
    if(cartItemsData[i]._selected !== false) cartItemsData.splice(i, 1);
  }
  showToast('🔖 ' + sel.length + ' produto(s) salvo(s) para depois!');
  updateCartUI();
}

function cartMoveSaveForLater(idx) {
  if(!cartItemsData[idx]) return;
  savedForLaterData.push({...cartItemsData[idx]});
  const name = cartItemsData[idx].n;
  cartItemsData.splice(idx, 1);
  showToast('🔖 "' + name + '" salvo para depois');
  updateCartUI();
}

function sflMoveToCart(idx) {
  if(!savedForLaterData[idx]) return;
  const item = {...savedForLaterData[idx]};
  item._selected = true;
  cartItemsData.push(item);
  savedForLaterData.splice(idx, 1);
  showToast('🛒 Movido de volta ao carrinho!');
  updateCartUI();
}

function sflRemove(idx) {
  if(!savedForLaterData[idx]) return;
  savedForLaterData.splice(idx, 1);
  renderSavedForLater();
}

function renderSavedForLater() {
  const sec = document.getElementById('savedForLaterSection');
  const cont = document.getElementById('savedForLaterItems');
  const cntEl = document.getElementById('sflCount');
  if(!sec || !cont) return;
  if(savedForLaterData.length === 0){
    sec.style.display = 'none';
    return;
  }
  sec.style.display = 'block';
  if(cntEl) cntEl.textContent = savedForLaterData.length;
  const fmt = v => 'R$ ' + v.toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g,'.');
  cont.innerHTML = savedForLaterData.map((c, i) => `
    <div class="sfl-item">
      <div class="sfl-item-img">${c.e}</div>
      <div class="sfl-item-body">
        <div class="sfl-item-name">${c.n}</div>
        <div class="sfl-item-price">${fmt(c.rawPrice)}</div>
      </div>
      <div class="sfl-item-actions">
        <button class="sfl-btn sfl-btn-move" onclick="sflMoveToCart(${i})"><span class="wkz-icon wkz-icon-cart"><svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 001.99 1.61h9.72a2 2 0 001.99-1.61L23 6H6"/></svg></span> Mover</button>
        <button class="sfl-btn sfl-btn-del" onclick="sflRemove(${i})">✕</button>
      </div>
    </div>`).join('');
}

/* ─── CART CHECKOUT ─── */

// ══════════════════════════════════════════════════════
//  CHECKOUT ENGINE — WeKz v2.6.7
// ══════════════════════════════════════════════════════
var _ckoutStep = 1;
var _ckoutAddr = 1;  // selected address card
var _ckoutPay  = 'pix'; // selected payment

var _SAVED_ADDRS = {
  1: { label:'🏠 Casa', name:'João da Silva', line1:'Rua das Flores, 42, Ap 12', line2:'São Paulo – SP · 01310-100' },
  2: { label:'💼 Trabalho', name:'João da Silva', line1:'Av. Paulista, 1500, Sala 47', line2:'São Paulo – SP · 01311-200' }
};
var _PAY_META = {
  pix:    { icon:'📱', name:'Pix — aprovação em segundos', desc:'5% de desconto aplicado' },
  card:   { icon:'💳', name:'Cartão de Crédito', desc:'Até 12x sem juros' },
  boleto: { icon:'📄', name:'Boleto Bancário', desc:'Vence em 3 dias úteis' },
  crypto: { icon:'₿',  name:'Cripto (BTC/ETH/USDT)', desc:'Pagamento em criptomoeda' }
};

function openCheckout(expressMode) {
  // Populate sidebar from cart
  _ckoutPopulateSidebar();
  _ckoutStep = 1;
  _ckoutGoto(1);
  // Reset to delivery mode on each open
  _ckoutMode = 'delivery';
  _selectedPickup = null;
  setTimeout(function(){ ckoutSetMode('delivery'); _updateShipEstimate(); }, 80);
  showPage('checkout');
  window.scrollTo({top:0,behavior:'smooth'});
}

function _ckoutPopulateSidebar() {
  var sel = (typeof cartItemsData !== 'undefined') ? cartItemsData.filter(c => c._selected !== false) : [];
  var sbItems = document.getElementById('ckoutSbItems');
  var revList  = document.getElementById('ckoutRevItemsList');
  if (!sbItems) return;

  // [v2.9.30 BUGFIX] Reescrito por completo — mesma lógica do carrinho (updateCartUI):
  //   subFull (Subtotal)  = soma do preço de TABELA (op) de cada item
  //   sub     (rawPrice)  = soma do preço JÁ OFERTADO (o que realmente será cobrado, antes de cupom/Pix)
  //   promoDiscount       = subFull - sub  → desconto já anunciado no produto
  //   couponDiscount      = cupom ativo, só sobre itens SEM desconto já anunciado (mesma regra do carrinho)
  //   pixDiscount         = 5% sobre (sub - couponDiscount), e SÓ depois que o usuário chega no step de Pagamento
  //                         (antes disso _ckoutPay='pix' é só um valor-padrão, não uma escolha real do usuário)
  //   Total = subFull − promoDiscount − couponDiscount − pixDiscount  (= sub − couponDiscount − pixDiscount)
  var sub = 0, subFull = 0;
  var itemsHtml = '';
  var revHtml = '';
  var isPromoItem = function(c){ return !!c._isFlash || !!c._isLive || (typeof c.op === 'number' && c.op > c.rawPrice); };
  var couponEligibleBase = 0; // soma de rawPrice dos itens SEM desconto já anunciado

  if (sel.length === 0 && typeof products !== 'undefined') {
    // Express mode — use current PDP product
    var p = products[currentPdpIndex] || products[0];
    if (p) {
      // FIX v2.6.7: p.p é número para produtos regulares; fallback parse para flash items
      sub = (typeof p.p === 'number') ? p.p
            : parseFloat(String(p.p||0).replace(/[^\d,]/g,'').replace(',','.')) || 1249.90;
      var pOp = (typeof p.op === 'number' && p.op > sub) ? p.op : sub;
      subFull = pOp;
      if (pOp <= sub) couponEligibleBase = sub; // sem desconto anunciado → elegível a cupom
      itemsHtml = `<div class="ckout-sb-item"><wkz-product-image class="ckout-sb-img" src="${p.img||''}" emoji="${p.e||'📦'}" alt="${p.n}"></wkz-product-image><div class="ckout-sb-name">${p.n}</div><div class="ckout-sb-price">${typeof formatPrice==='function'?formatPrice(sub):'R$ '+sub.toFixed(2)}</div></div>`;
      revHtml = `<div class="ckout-rev-item"><wkz-product-image class="ckout-rev-img" src="${p.img||''}" emoji="${p.e||'📦'}" alt="${p.n}"></wkz-product-image><div style="flex:1;"><div class="ckout-rev-name">${p.n}</div><div class="ckout-rev-meta">Qtd: 1</div></div><div class="ckout-rev-price">${typeof formatPrice==='function'?formatPrice(sub):'R$ '+sub.toFixed(2)}</div></div>`;
    }
  } else {
    sel.forEach(c => {
      // FIX v2.6.7: usar rawPrice (number) e qty — campos reais de cartItemsData
      var price = (typeof c.rawPrice === 'number') ? c.rawPrice
                  : parseFloat(String(c.rawPrice||c.p||0).replace(/[^\d,]/g,'').replace(',','.')) || 0;
      var qty   = (typeof c.qty === 'number') ? c.qty : (c.q || 1);
      var opPrice = (typeof c.op === 'number' && c.op > price) ? c.op : price;
      var lineVal = price * qty;
      sub += lineVal;
      subFull += opPrice * qty;
      if (!isPromoItem(c)) couponEligibleBase += lineVal;
      itemsHtml += `<div class="ckout-sb-item"><wkz-product-image class="ckout-sb-img" src="${c.img||''}" emoji="${c.e||'📦'}" alt="${c.n}"></wkz-product-image><div class="ckout-sb-name">${c.n}</div><div class="ckout-sb-price">${typeof formatPrice==='function'?formatPrice(lineVal):'R$ '+lineVal.toFixed(2)}</div></div>`;
      revHtml += `<div class="ckout-rev-item"><wkz-product-image class="ckout-rev-img" src="${c.img||''}" emoji="${c.e||'📦'}" alt="${c.n}"></wkz-product-image><div style="flex:1;"><div class="ckout-rev-name">${c.n}</div><div class="ckout-rev-meta">Qtd: ${qty}</div></div><div class="ckout-rev-price">${typeof formatPrice==='function'?formatPrice(lineVal):'R$ '+lineVal.toFixed(2).replace('.',',')}</div></div>`;
    });
  }

  sbItems.innerHTML = itemsHtml || '<div style="font-size:12px;color:var(--muted);">Carregando itens...</div>';
  if (revList) revList.innerHTML = revHtml;

  // Desconto do produto (preço de tabela − preço ofertado)
  var promoDiscount = Math.max(0, subFull - sub);

  // Cupom — só sobre itens sem desconto já anunciado (mesma regra do carrinho)
  var couponDiscount = 0;
  var ac = window._activeCoupon;
  if (ac && couponEligibleBase > 0) {
    if (ac.type === '%')      couponDiscount = couponEligibleBase * (ac.disc / 100);
    else if (ac.type === 'fixed') couponDiscount = Math.min(parseFloat(ac.disc) || 0, couponEligibleBase);
  }

  // Desconto Pix — só conta a partir do step de Pagamento (step>=2), nunca antes
  // do usuário efetivamente chegar/escolher a forma de pagamento.
  var pixApplies = (_ckoutStep >= 2) && (_ckoutPay === 'pix');
  var disc  = pixApplies ? (sub - couponDiscount) * 0.05 : 0;
  var totalDiscount = promoDiscount + couponDiscount + disc;
  var total = Math.max(0, subFull - totalDiscount);

  var fmt = v => typeof formatPrice==='function' ? formatPrice(v) : 'R$ '+v.toFixed(2).replace('.',',');
  var sbSub = document.getElementById('ckoutSbSub'); if(sbSub) sbSub.textContent = fmt(subFull);
  var sbTot = document.getElementById('ckoutSbTotal'); if(sbTot) sbTot.textContent = fmt(total);

  var sbDiscPromo    = document.getElementById('ckoutSbDiscPromo');
  var sbDiscPromoVal = document.getElementById('ckoutSbDiscPromoVal');
  var sbDiscPromoLbl = document.getElementById('ckoutSbDiscPromoLabel');
  var promoPlusCoupon = promoDiscount + couponDiscount;
  if (sbDiscPromo) sbDiscPromo.style.display = promoPlusCoupon > 0 ? 'flex' : 'none';
  if (sbDiscPromoVal) sbDiscPromoVal.textContent = '-' + fmt(promoPlusCoupon);
  if (sbDiscPromoLbl) sbDiscPromoLbl.textContent = couponDiscount > 0 ? 'Desconto (produto + cupom)' : 'Desconto';

  var sbDisc = document.getElementById('ckoutSbDisc');
  var sbDiscVal = document.getElementById('ckoutSbDiscVal');
  if(sbDisc) sbDisc.style.display = pixApplies ? 'flex' : 'none';
  if(sbDiscVal) sbDiscVal.textContent = '-' + fmt(disc);

  // Review totals box
  var totBox = document.getElementById('ckoutTotalsBox');
  if(totBox) totBox.innerHTML = `
    <div class="ckout-tot-row"><span>Preço do Produto <span style="opacity:.65;font-size:10px;">(Vendedor Parceiro)</span></span><span>${fmt(subFull)}</span></div>
    <div class="ckout-tot-row" style="font-size:11px;color:var(--muted);"><span>Taxa de Intermediação / Serviço WeKz</span><span>Já incluída no preço</span></div>
    <div class="ckout-tot-row" style="font-size:11px;color:var(--muted);"><span>Tributos de Importação</span><span>Não aplicável — entrega nacional</span></div>
    <div class="ckout-tot-row"><span>Frete</span><span style="color:#22C55E;">Grátis</span></div>
    ${promoPlusCoupon>0?`<div class="ckout-tot-row" style="color:#FF6B35;"><span>${couponDiscount>0?'Desconto (produto + cupom)':'Desconto'}</span><span>-${fmt(promoPlusCoupon)}</span></div>`:''}
    ${pixApplies?`<div class="ckout-tot-row" style="color:#4ade80;"><span>Desconto Pix (5%)</span><span>-${fmt(disc)}</span></div>`:''}
    <div class="ckout-tot-row grand"><span>Total</span><span>${fmt(total)}</span></div>`;

  // Rev address
  var a = _SAVED_ADDRS[_ckoutAddr] || _SAVED_ADDRS[1];
  var revAddr = document.getElementById('ckoutRevAddr');
  if(revAddr) revAddr.innerHTML = `<strong>${a.name}</strong><br>${a.line1}<br>${a.line2}`;

  // Rev payment
  var pm = _PAY_META[_ckoutPay];
  var revPayIcon = document.getElementById('ckoutRevPayIcon'); if(revPayIcon) revPayIcon.textContent = pm.icon;
  var revPayName = document.getElementById('ckoutRevPayName'); if(revPayName) revPayName.textContent = pm.name;
  var revPayDesc = document.getElementById('ckoutRevPayDesc'); if(revPayDesc) revPayDesc.textContent = pm.desc;
}

function _ckoutGoto(step) {
  _ckoutStep = step;
  [1,2,3,4].forEach(n => {
    var el = document.getElementById('ckoutStep'+n);
    var stepEl = document.getElementById('cstep'+n);
    if(!el || !stepEl) return;
    el.classList.toggle('active', n === step);
    stepEl.classList.remove('active','done');
    if (n < step) stepEl.classList.add('done');
    else if (n === step) stepEl.classList.add('active');
  });
  // connectors
  [['conn12',2],['conn23',3],['conn34',4]].forEach(([id,thr]) => {
    var c = document.getElementById(id); if(c) c.classList.toggle('done', step >= thr);
  });
  // [v2.9.30] Também recalcula ao entrar no step 2 — sem isto, o Total ficava
  // com o valor do step 1 (sem desconto Pix) até o usuário clicar manualmente
  // numa forma de pagamento, mesmo com Pix pré-selecionado visualmente.
  if (step === 2 || step === 3 || step === 4) _ckoutPopulateSidebar();
  window.scrollTo({top:0,behavior:'smooth'});
}

// FIX SEC-03: algoritmo de Luhn para validação de número de cartão de crédito/débito.
// Detecta erros de digitação e números obviamente inválidos antes de enviar ao gateway.
function luhnCheck(num) {
  var digits = String(num).replace(/\D/g, '');
  if (digits.length < 13 || digits.length > 19) return false;
  var sum = 0;
  var shouldDouble = false;
  for (var i = digits.length - 1; i >= 0; i--) {
    var d = parseInt(digits[i], 10);
    if (shouldDouble) {
      d *= 2;
      if (d > 9) d -= 9;
    }
    sum += d;
    shouldDouble = !shouldDouble;
  }
  return (sum % 10) === 0;
}

// FIX SEC-05: verificação de expiração de cartão como função reutilizável.
// Usada no checkout (ckoutNext) e na carteira (cpSaveNewPayment).
function isCardExpired(val) {
  if (!val || val.length < 5) return true;
  var parts = val.split('/');
  if (parts.length !== 2) return true;
  var m = parseInt(parts[0], 10);
  var y = parseInt(parts[1], 10);
  if (isNaN(m) || isNaN(y)) return true;
  var now = new Date();
  var exp = new Date(2000 + y, m - 1, 1);
  return exp < now;
}

// FIX BUG-03: gerar ID de pedido com crypto.randomUUID() para unicidade garantida
function generateOrderId() {
  try {
    var uuid = crypto.randomUUID().slice(0, 8).toUpperCase();
    return '#WKZ-' + uuid;
  } catch(e) {
    // fallback apenas se crypto indisponível (ambiente antigo)
    return '#WKZ-' + Date.now().toString(36).toUpperCase().slice(-8);
  }
}

// FIX BUG-02: validação completa por etapa antes de avançar
function ckoutNext(from) {
  // Etapa 1 — endereço ou ponto de coleta
  if (from === 1) {
    if (_ckoutMode === 'pickup') {
      if (!_selectedPickup) {
        showToast('⚠️ Selecione um ponto de retirada para continuar');
        return;
      }
    } else {
      var nome = (document.getElementById('ckoutNome') || {}).value || '';
      var rua  = (document.getElementById('ckoutRua')  || {}).value || '';
      var num  = (document.getElementById('ckoutNum')  || {}).value || '';
      var cep  = (document.getElementById('ckoutCep')  || {}).value || '';
      if (!nome.trim()) { showToast('⚠️ Informe o nome completo'); return; }
      if (!cep.trim() || cep.replace(/\D/g,'').length < 8) { showToast('⚠️ Informe um CEP válido'); return; }
      if (!rua.trim()) { showToast('⚠️ Informe o logradouro'); return; }
      if (!num.trim()) { showToast('⚠️ Informe o número do endereço'); return; }
    }
  }
  // Etapa 2 — método de pagamento
  if (from === 2) {
    if (!_ckoutPay) {
      showToast('⚠️ Selecione um método de pagamento');
      return;
    }
    if (_ckoutPay === 'card') {
      var cardNum = (document.getElementById('cardNum') || {}).value || '';
      var cardExp = (document.getElementById('cardExp') || {}).value || '';
      var cardCvv = (document.getElementById('cardCvv') || {}).value || '';
      var digits  = cardNum.replace(/\s/g, '');
      if (digits.length < 16) { showToast('⚠️ Número do cartão inválido'); return; }
      // FIX SEC-03: validação Luhn — detecta números estruturalmente inválidos
      if (!luhnCheck(digits)) { showToast('⚠️ Número do cartão inválido — verifique os dígitos'); return; }
      if (!cardExp.trim() || cardExp.length < 5) { showToast('⚠️ Data de validade inválida'); return; }
      // FIX SEC-05: usar isCardExpired() centralizada
      if (isCardExpired(cardExp)) { showToast('⚠️ Cartão expirado — verifique a data de validade'); return; }
      if (!cardCvv.trim() || cardCvv.length < 3) { showToast('⚠️ CVV inválido'); return; }
    }
  }
  // Etapa 3 — confirmação final
  if (from === 3) {
    var orderNum = generateOrderId();
    var now      = new Date();
    var dateStr  = now.toLocaleDateString('pt-BR',{day:'2-digit',month:'long',year:'numeric',hour:'2-digit',minute:'2-digit'});
    var shortDate= now.toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'}).replace(',','');

    // ── Número e data ──
    var on = document.getElementById('ckoutOrderNum'); if(on) on.textContent = orderNum;
    var od = document.getElementById('ckoutOrderDate'); if(od) od.textContent = 'Confirmado em ' + dateStr;

    // ── Produto atual (express ou cart) ──
    var _oProd = null;
    var _oPrice = 0;
    var _oSeller = 'TechStore';
    var _oCat = 'eletronicos';
    if (typeof cartItemsData !== 'undefined' && cartItemsData.length > 0) {
      var _ci = cartItemsData.filter(function(c){ return c._selected !== false; })[0] || cartItemsData[0];
      if (_ci) { _oProd = { e: _ci.e||'📦', n: _ci.n||'Produto', p: _ci.rawPrice||_ci.p||0 }; _oPrice = _oProd.p; _oSeller = _ci.s||'Loja'; }
    }
    if (!_oProd && typeof products !== 'undefined' && typeof currentPdpIndex !== 'undefined') {
      var _pp = products[currentPdpIndex] || products[0];
      if (_pp) { _oProd = { e: _pp.e||'📦', n: _pp.n||'Produto', p: _pp.p||0 }; _oPrice = _pp.p; _oSeller = _pp.s||'Loja'; _oCat = _pp.cat||'eletronicos'; }
    }
    if (!_oProd) { _oProd = { e:'📦', n:'Produto WeKz', p:0 }; }

    // ── Preencher item summary ──
    var confItem = document.getElementById('ckoutConfItemSummary');
    if (confItem) {
      var fmtP = (typeof formatPrice === 'function') ? formatPrice(_oPrice) : 'R$ ' + (_oPrice||0).toFixed(2).replace('.',',');
      confItem.innerHTML = '<div style="font-size:28px;flex-shrink:0;">' + _oProd.e + '</div>' +
        '<div style="flex:1;min-width:0;">' +
          '<div style="font-size:13px;font-weight:700;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + _oProd.n + '</div>' +
          '<div style="font-size:11px;color:var(--muted);margin-top:2px;">Vendido por <strong>' + _oSeller + '</strong></div>' +
        '</div>' +
        '<div style="font-size:16px;font-weight:800;color:var(--teal);flex-shrink:0;">' + fmtP + '</div>';
    }

    // ── Entrega estimada ──
    var delivDays = Math.floor(5 + Math.random() * 6); // 5..10 dias úteis mock
    var delivDate = new Date(now.getTime() + delivDays * 1.4 * 24 * 60 * 60 * 1000); // ~1.4 inclui fins de semana
    var delivStr  = delivDate.toLocaleDateString('pt-BR',{day:'2-digit',month:'long'});
    var confDeliv = document.getElementById('ckoutConfDeliveryText');
    if (confDeliv) confDeliv.innerHTML = 'Entrega prevista até <strong>' + delivStr + '</strong> (' + delivDays + ' dias úteis)';

    // ── NF-e na confirmação ──
    var confNfe = document.getElementById('ckoutConfNfe');
    if (confNfe && typeof WkzFiscalSplit !== 'undefined') {
      confNfe.textContent = WkzFiscalSplit.generateNfe();
    }

    // ── Salvar pedido no estado global _WKZ_ORDERS ──
    if (!window._WKZ_ORDERS) window._WKZ_ORDERS = [];
    var newOrder = {
      id:       orderNum,
      produto:  _oProd.n,
      emoji:    _oProd.e,
      seller:   _oSeller,
      valor:    _oPrice,
      status:   'paid',
      cat:      _oCat,
      date:     shortDate,
      dateISO:  now.toISOString(),
      trk:      null   // código de rastreio: null até despacho
    };
    window._WKZ_ORDERS.unshift(newOrder);

    // ── Guardar último pedido para wkzTrackLastOrder() ──
    window._WKZ_LAST_ORDER = newOrder;

    // ── Injetar no topo da tabela de Pedidos Recebidos (seller view) ──
    var tbody = document.getElementById('ordersTableBody');
    if (tbody) {
      var svgPaid = '<svg viewBox="0 0 24 24" width="11" height="11" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="display:inline;vertical-align:middle;margin-right:3px;"><polyline points="20 6 9 17 4 12"/></svg>';
      var newRow = document.createElement('tr');
      newRow.className = 'order-row-clickable';
      newRow.setAttribute('data-status','paid');
      newRow.setAttribute('data-order-id', newOrder.id);
      var safeName = newOrder.produto.length > 20 ? newOrder.produto.slice(0,18)+'…' : newOrder.produto;
      var fmtVal   = 'R$ ' + Math.round(newOrder.valor).toLocaleString('pt-BR');
      newRow.innerHTML =
        '<td data-label="Pedido">' + newOrder.id + '</td>' +
        '<td data-label="Produto">' + safeName + '</td>' +
        '<td data-label="Comprador">Você</td>' +
        '<td data-label="Valor">' + fmtVal + '</td>' +
        '<td data-label="Status"><span class="order-status status-paid">' + svgPaid + 'Pago</span></td>' +
        '<td data-label="Data">' + newOrder.date + '</td>' +
        '<td class="td-acoes" onclick="event.stopPropagation()">' +
          '<button class="rev-filter" style="padding:4px 10px;font-size:11px;background:rgba(0,180,171,0.12);border-color:rgba(0,180,171,0.4);color:var(--teal);" ' +
            'onclick="wkzSellerConfirmOrderReceipt(\'' + newOrder.id + '\',this)">✅ Confirmar Recebido</button>' +
        '</td>';
      tbody.insertBefore(newRow, tbody.firstChild);
    }

    // ── Injetar no topo do overview recente ──
    var ovBody = document.getElementById('overviewOrdersBody');
    if (ovBody) {
      var svgPaid2 = '<svg viewBox="0 0 24 24" width="11" height="11" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="display:inline;vertical-align:middle;margin-right:3px;"><polyline points="20 6 9 17 4 12"/></svg>';
      var ovRow = document.createElement('tr');
      var safeName2 = newOrder.produto.length > 18 ? newOrder.produto.slice(0,16)+'…' : newOrder.produto;
      ovRow.innerHTML =
        '<td>' + newOrder.id + '</td>' +
        '<td>' + safeName2 + '</td>' +
        '<td>Você</td>' +
        '<td>R$ ' + Math.round(newOrder.valor).toLocaleString('pt-BR') + '</td>' +
        '<td><span class="order-status status-paid">' + svgPaid2 + 'Pago</span></td>' +
        '<td>' + newOrder.date + '</td>';
      ovBody.insertBefore(ovRow, ovBody.firstChild);
      // Trim to max 5 rows
      while (ovBody.rows.length > 5) ovBody.deleteRow(ovBody.rows.length - 1);
    }

    // ── Injetar no _TRK_DATA para rastreamento imediato ──
    // FIX v2.9.35: objeto completo com todos os campos exigidos por loadTracking()
    // (carrier, bannerGrad, statusIcon, statusLabel, progress, etaLabel, etaDate,
    //  product.qty/price/emoji, events com title/desc/time/location/done/active)
    if (typeof _TRK_DATA !== 'undefined') {
      var trkCode = orderNum.replace('#','');
      var _etaDate35 = new Date(); _etaDate35.setDate(_etaDate35.getDate() + 8);
      var _etaLabel35 = _etaDate35.toLocaleDateString('pt-BR',{day:'2-digit',month:'short'});
      _TRK_DATA[trkCode] = {
        orderNum:    orderNum,
        status:      'confirmed',
        statusLabel: 'Pedido Confirmado',
        statusIcon:  '📋',
        bannerGrad:  'linear-gradient(135deg,#7C3AED 0%,#6D28D9 100%)',
        progress:    10,
        etaDate:     _etaDate35,
        etaLabel:    _etaLabel35,
        address:     'Endereço de entrega cadastrado',
        product: {
          name:  newOrder.produto,
          emoji: newOrder.emoji || '📦',
          img:   '',
          qty:   1,
          price: 'R$ ' + (_oPrice||0).toFixed(2).replace('.',',')
        },
        carrier: {
          name: 'Transportadora WeKz',
          code: 'Aguardando código',
          logo: '📦'
        },
        seller: newOrder.seller || { name: 'Vendedor WeKz', rating: 5.0 },
        buyer:  'Você',
        activeStep: 0,
        steps: [
          { label:'Confirmado',      icon:'check', date: shortDate },
          { label:'Em preparação',   icon:'box',   date:'Aguardando' },
          { label:'Despachado',      icon:'truck', date:'Aguardando' },
          { label:'Em trânsito',     icon:'map',   date:'Aguardando' },
          { label:'Saiu p/ entrega', icon:'zap',   date:'Aguardando' },
          { label:'Entregue',        icon:'home',  date:'Aguardando' }
        ],
        events: [
          { title:'Pedido confirmado', desc:'Pagamento aprovado. Vendedor notificado.', time:dateStr, location:'WeKz Shop', done:true,  active:true  },
          { title:'Aguardando vendedor confirmar recebimento', desc:'O vendedor irá confirmar o pedido em breve.', time:'', location:'', done:false, active:false },
          { title:'Em preparação',   desc:'',  time:'', location:'', done:false, active:false },
          { title:'Despachado',      desc:'',  time:'', location:'', done:false, active:false },
          { title:'Em trânsito',     desc:'',  time:'', location:'', done:false, active:false },
          { title:'Entregue',        desc:'',  time:'', location:'', done:false, active:false }
        ],
        isNewOrder: true
      };
    }

    // ── KPIs reativos: Pedidos + Receita ──
    _wkzUpdateSellerKpis(newOrder);

    // FIX FUNC-02: carrinho NÃO é limpo aqui — será limpo em finalizeOrder()
    showToast('🎉 Pedido ' + orderNum + ' confirmado com sucesso!');
  }
  _ckoutGoto(from + 1);
}

function ckoutGoTo(step) { _ckoutGoto(step); }

// FIX FUNC-02: limpeza do carrinho só ocorre quando o utilizador sai conscientemente
// do ecrã de confirmação. Chamada pelos botões "Continuar Comprando" e "Ver Meus Pedidos".
function finalizeOrder(dest) {
  if (typeof cartItemsData !== 'undefined') cartItemsData.length = 0;
  if (typeof updateCartUI === 'function') updateCartUI();
  if (typeof renderCart === 'function') renderCart();
  if (typeof showPage === 'function') showPage(dest);
  // Se foi para client-profile, ativa aba de pedidos automaticamente
  if (dest === 'client-profile') {
    setTimeout(function() {
      var ordersTab = document.querySelector('.sidebar-nav-item[onclick*="orders"]');
      if (ordersTab && typeof switchDashTab === 'function') switchDashTab('orders', ordersTab);
    }, 120);
  }
}

/* ─────────────────────────────────────────────────────────────
   wkzTrackLastOrder()
   Pré-popula a página de rastreamento com o pedido recém-criado
   e navega para ela — sem depender de busca manual do usuário.
──────────────────────────────────────────────────────────────── */
function wkzTrackLastOrder() {
  var o = window._WKZ_LAST_ORDER;
  if (!o) {
    if (typeof MapsTo === 'function') MapsTo('tracking');
    return;
  }
  var trkCode = o.id.replace('#', '');
  // Pré-preenche o input de busca
  var inp = document.getElementById('trkInput');
  if (inp) inp.value = o.id;
  // Navegar para tracking
  finalizeOrder('tracking');
  // Aguarda DOM estar visível antes de executar loadTracking
  setTimeout(function() {
    if (typeof loadTracking === 'function') loadTracking(trkCode);
  }, 150);
}

/* ─────────────────────────────────────────────────────────────
   _wkzUpdateSellerKpis(order)
   Atualiza reativamente os KPI cards do seller overview:
   • Pedidos (mês) — incrementa +1
   • Receita (mês) — soma valor do novo pedido
   • Disputas — não muda (pedido novo = status paid)
──────────────────────────────────────────────────────────────── */
function _wkzUpdateSellerKpis(order) {
  /* ── Pedidos (mês) ── */
  var kpiCards = document.querySelectorAll('.stat-card');
  var kpiPedidos  = null;
  var kpiReceita  = null;
  kpiCards.forEach(function(card) {
    var label = (card.querySelector('.stat-label') || {}).textContent || '';
    if (label.indexOf('Pedidos') !== -1) kpiPedidos = card;
    if (label.indexOf('Receita') !== -1) kpiReceita = card;
  });

  if (kpiPedidos) {
    var valEl = kpiPedidos.querySelector('.stat-value');
    if (valEl) {
      var cur = parseInt(valEl.textContent.replace(/\D/g,''), 10) || 155;
      valEl.textContent = cur + 1;
      // Flash animation
      valEl.style.transition = 'color 0.3s ease';
      valEl.style.color = 'var(--teal)';
      setTimeout(function(){ valEl.style.color = ''; }, 1200);
    }
    var chg = kpiPedidos.querySelector('.stat-change');
    if (chg) {
      var prev = parseInt((chg.textContent.match(/\+(\d+)/) || ['','0'])[1], 10) || 23;
      chg.textContent = '↑ +' + (prev + 1) + ' vs mês anterior';
    }
  }

  if (kpiReceita && order && order.valor) {
    var revEl = kpiReceita.querySelector('.stat-value');
    if (revEl) {
      /* parse current value: "R$48.320" → 48320 */
      var rawRev = (revEl.textContent || '').replace(/[^\d]/g,'');
      var curRev = parseInt(rawRev, 10) || 48320;
      var newRev = curRev + Math.round(order.valor);
      /* format back: 48320 → "R$48.320" */
      revEl.textContent = 'R$' + newRev.toLocaleString('pt-BR');
      revEl.style.transition = 'color 0.3s ease';
      revEl.style.color = '#22C55E';
      setTimeout(function(){ revEl.style.color = ''; }, 1200);
    }
  }

  /* ── Filtros de Meus Pedidos: update "Todos (N)" count ── */
  var allFilterBtn = document.querySelector('#dash-orders .rev-filter.active, #dash-orders .rev-filter:first-child');
  if (allFilterBtn) {
    var txt = allFilterBtn.textContent.trim();
    var m = txt.match(/\((\d+)\)/);
    if (m) {
      var n = parseInt(m[1], 10) + 1;
      allFilterBtn.textContent = txt.replace(/\(\d+\)/, '(' + n + ')');
    }
    /* Also update "Pagos (N)" */
    var paidBtn = document.querySelector('#dash-orders .rev-filter[onclick*="paid"]');
    if (paidBtn) {
      var ptxt = paidBtn.textContent.trim();
      var pm = ptxt.match(/\((\d+)\)/);
      if (pm) {
        var pn = parseInt(pm[1], 10) + 1;
        paidBtn.innerHTML = paidBtn.innerHTML.replace(/\(\d+\)/, '(' + pn + ')');
      }
    }
  }

  wkzLog('[WkzShop v2.9.21] ✓ KPIs atualizados — novo pedido: ' + (order ? order.id : '?'));
}

function selectAddr(n) {
  _ckoutAddr = n;
  [1,2].forEach(i => {
    var c = document.getElementById('addrCard'+i);
    if(c) c.classList.toggle('sel', i===n);
  });
}

function toggleNewAddr() {
  var f = document.getElementById('ckoutNewAddrForm');
  f.style.display = f.style.display === 'none' ? 'block' : 'none';
}

function selectPay(type) {
  _ckoutPay = type;
  ['pix','card','boleto','crypto'].forEach(t => {
    var opt = document.getElementById('pay'+t.charAt(0).toUpperCase()+t.slice(1));
    if(opt) opt.classList.toggle('sel', t===type);
    var det = document.getElementById('payDetail'+t.charAt(0).toUpperCase()+t.slice(1));
    if(det) det.style.display = t===type ? 'block' : 'none';
  });
  // Update pix discount in sidebar
  _ckoutPopulateSidebar();
}

// ── CEP MASK ──
function ckoutCepMask(inp) {
  var v = inp.value.replace(/\D/g,'').slice(0,8);
  inp.value = v.length > 5 ? v.slice(0,5)+'-'+v.slice(5) : v;
}

// ── VIACEP AUTO-FILL ──
async function ckoutFetchCep(cep) {
  var raw = cep.replace(/\D/g,'');
  if(raw.length !== 8) return;
  var spin = document.getElementById('ckoutCepSpin');
  var ok   = document.getElementById('ckoutCepOk');
  var inp  = document.getElementById('ckoutCep');
  if(spin) spin.style.display = 'block';
  if(ok)   ok.style.display   = 'none';
  try {
    var r = await fetch('https://viacep.com.br/ws/'+raw+'/json/');
    var d = await r.json();
    if(d.erro) { showToast('⚠️ CEP não encontrado'); return; }
    var setVal = (id, val) => {
      var el = document.getElementById(id);
      if(el){ el.value = val; el.classList.add('ckout-success'); setTimeout(()=>el.classList.remove('ckout-success'),1200); }
    };
    setVal('ckoutRua',    d.logradouro || '');
    setVal('ckoutBairro', d.bairro     || '');
    setVal('ckoutCidade', d.localidade || '');
    setVal('ckoutUf',     d.uf         || '');
    if(ok) ok.style.display = 'block';
    if(inp) inp.classList.add('ckout-success');
    showToast('✅ Endereço preenchido pelo CEP!');
    // FIX FUNC-03: focar o campo Número para o utilizador completar o endereço
    setTimeout(function() {
      var numEl = document.getElementById('ckoutNum');
      if (numEl) {
        numEl.focus();
        numEl.style.borderColor = 'var(--teal)';
        numEl.style.boxShadow = '0 0 0 3px rgba(0,180,171,0.15)';
        numEl.placeholder = 'Número obrigatório ↑';
        setTimeout(function() {
          numEl.style.borderColor = '';
          numEl.style.boxShadow = '';
          numEl.placeholder = 'Ex: 42';
        }, 3000);
      }
    }, 300);
    // Update saved addr list to show new option
    _SAVED_ADDRS[3] = {
      label: '📍 Novo',
      name: (document.getElementById('ckoutNome')||{}).value || 'Você',
      line1: (d.logradouro||'') + (document.getElementById('ckoutNum')?.value ? ', ' + document.getElementById('ckoutNum').value : ''),
      line2: d.localidade + ' – ' + d.uf + ' · ' + cep
    };
    _ckoutAddr = 3;
  } catch(e) {
    showToast('⚠️ Erro ao buscar CEP. Verifique sua conexão.');
  } finally {
    if(spin) spin.style.display = 'none';
  }
}

// ── CARD MASKS ──
function cardNumMask(inp) {
  var v = inp.value.replace(/\D/g,'').slice(0,16);
  inp.value = v.match(/.{1,4}/g)?.join(' ') || v;
  // Brand detection
  var icon = document.getElementById('cardBrandIcon');
  if(!icon) return;
  if(v.startsWith('4')) icon.textContent = '💙'; // Visa
  else if(v.startsWith('5')) icon.textContent = '🔴'; // Master
  else if(v.startsWith('3')) icon.textContent = '🟢'; // Amex
  else icon.textContent = '💳';
}
function cardExpMask(inp) {
  var v = inp.value.replace(/\D/g,'').slice(0,4);
  inp.value = v.length > 2 ? v.slice(0,2)+'/'+v.slice(2) : v;
}

function cartCheckout() {
  const sel = cartItemsData.filter(c => c._selected !== false);
  if(sel.length === 0) return showToast('⚠️ Selecione ao menos um produto para comprar');
  openCheckout(false);
}

function cartBuyExpressNow(idx) {
  // Buy Now 1-clique — pula o carrinho, vai direto para checkout
  const p = products[idx];
  if (!p) return;
  openCheckout(true);
}

/* ══════════════════════════════════════════════════════════
   KZ PRICE ALERT ENGINE v1.0 — WeKz v2.6.7
   "Me Avise quando o preço baixar"
   ── Store: localStorage kzPriceAlerts (array de objetos)
   ── Cada alerta: { id, productIdx, emoji, name, currentPrice, threshold, notif, createdAt }
   ══════════════════════════════════════════════════════════ */
(function() {

  /* ── STORE ── */
  const STORE_KEY = 'kzPriceAlerts_v1';
  // SEC-01 [negócio — TODO]: alertas de preço contêm intenções de compra do utilizador.
  // Migrar para sessão autenticada no back-end (/api/me/price-alerts) após integração.

  function paLoad() {
    try {
      // Componente 4: lê via wkzSecureStorage; fallback para localStorage legado
      if (typeof wkzSecureStorage !== 'undefined') {
        return wkzSecureStorage.get(STORE_KEY) || [];
      }
      return JSON.parse(localStorage.getItem(STORE_KEY)) || [];
    }
    catch(e) { return []; }
  }

  function paSave(alerts) {
    try {
      // Componente 4: grava via wkzSecureStorage (ofuscado)
      if (typeof wkzSecureStorage !== 'undefined') {
        wkzSecureStorage.set(STORE_KEY, alerts);
      } else {
        localStorage.setItem(STORE_KEY, JSON.stringify(alerts));
      }
    }
    catch(e) { /* quota */ }
  }

  function paGet(productId) {
    return paLoad().find(a => a.id === productId) || null;
  }

  /* ── ESTADO INTERNO ── */
  let _paCurrentIdx    = -1;   // índice do produto atual na PDP
  let _paSelectedNotif = 'push'; // método de notificação selecionado

  /* ── HELPERS ── */
  function _fmtPrice(v) {
    return 'R$ ' + Number(v).toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g,'.');
  }

  function _productId(idx) {
    const p = (typeof products !== 'undefined') ? products[idx] : null;
    return p ? ('prod-' + (p.n||'').replace(/\s/g,'_').toLowerCase().slice(0,30)) : ('prod-idx-'+idx);
  }

  /* ── ABRIR MODAL ── */
  window.kzOpenPriceAlert = function(forceIdx) {
    /* FUNC-06: aceita índice explícito; fallback para currentPdpIndex global */
    const idx = (typeof forceIdx === 'number' && forceIdx >= 0)
      ? forceIdx
      : (typeof currentPdpIndex !== 'undefined' && currentPdpIndex >= 0 ? currentPdpIndex : -1);
    _paCurrentIdx = idx;

    const p   = (typeof products !== 'undefined' && idx >= 0) ? products[idx] : null;
    const pid = _productId(idx);

    // Preencher preview
    const emojiEl = document.getElementById('kzpaModalEmoji');
    const nameEl  = document.getElementById('kzpaModalName');
    const priceEl = document.getElementById('kzpaModalPrice');
    if(emojiEl) {
      emojiEl.setAttribute('emoji', (p && p.e) || '');
      if (p && p.img) { emojiEl.setAttribute('src', p.img); } else { emojiEl.removeAttribute('src'); }
    }
    if(nameEl)  nameEl.textContent  = p ? p.n : 'Produto';
    const curPrice = p ? p.p : 0;
    if(priceEl) priceEl.textContent = _fmtPrice(curPrice);

    // Chips de desconto rápido (5%, 10%, 15%, 20%)
    const chipsEl = document.getElementById('kzpaChips');
    if(chipsEl && curPrice > 0) {
      chipsEl.innerHTML = [5,10,15,20].map(pct => {
        const val = (curPrice * (1 - pct/100)).toFixed(2);
        return `<span class="kzpa-chip" onclick="kzpaApplyChip(${val})">−${pct}% · ${_fmtPrice(val)}</span>`;
      }).join('');
    }

    // Verificar se já existe alerta ativo
    const existing = paGet(pid);
    const inp = document.getElementById('kzpaThresholdInput');
    const removeHint = document.getElementById('kzpaRemoveHint');
    if(inp) inp.value = existing ? existing.threshold : (curPrice > 0 ? (curPrice * 0.9).toFixed(2) : '');
    if(removeHint) removeHint.style.display = existing ? 'block' : 'none';

    // Notif padrão
    _paSelectedNotif = existing ? (existing.notif||'push') : 'push';
    _paRefreshNotifUI();

    // Abrir overlay
    const overlay = document.getElementById('kzPriceAlertOverlay');
    if(overlay) {
      overlay.classList.add('open');
      document.body.style.overflow = 'hidden';
      setTimeout(() => { const i = document.getElementById('kzpaThresholdInput'); if(i) i.focus(); }, 260);
    }
  };

  /* ── FECHAR MODAL ── */
  window.kzClosePriceAlert = function() {
    const overlay = document.getElementById('kzPriceAlertOverlay');
    if(overlay) overlay.classList.remove('open');
    document.body.style.overflow = '';
  };

  /* ── APLICAR CHIP ── */
  window.kzpaApplyChip = function(val) {
    const inp = document.getElementById('kzpaThresholdInput');
    if(inp) { inp.value = Number(val).toFixed(2); inp.focus(); }
  };

  /* ── SELECIONAR NOTIFICAÇÃO ── */
  window.kzpaSelectNotif = function(type) {
    _paSelectedNotif = type;
    _paRefreshNotifUI();
  };

  function _paRefreshNotifUI() {
    ['push','email','sms'].forEach(t => {
      const el = document.getElementById('kzpaNotif' + t.charAt(0).toUpperCase() + t.slice(1));
      if(el) el.classList.toggle('sel', t === _paSelectedNotif);
    });
  }

  /* ── CONFIRMAR ALERTA ── */
  window.kzConfirmPriceAlert = function() {
    const inp = document.getElementById('kzpaThresholdInput');
    if(!inp) return;

    const threshold = parseFloat(inp.value);
    if(isNaN(threshold) || threshold <= 0) {
      if(typeof showToast === 'function') showToast('Informe um valor válido para o alerta.');
      inp.focus();
      return;
    }

    const idx = _paCurrentIdx;
    const p   = (typeof products !== 'undefined' && idx >= 0) ? products[idx] : null;
    const pid = _productId(idx);
    const curPrice = p ? p.p : 0;

    if(curPrice > 0 && threshold >= curPrice) {
      if(typeof showToast === 'function') showToast('O valor precisa ser menor que o preço atual (' + _fmtPrice(curPrice) + ').');
      inp.focus();
      return;
    }

    // Salvar alerta
    const alerts = paLoad().filter(a => a.id !== pid); // remove existente se houver
    alerts.push({
      id: pid,
      productIdx: idx,
      emoji: p ? (p.e||'📦') : '📦',
      name:  p ? p.n : 'Produto',
      currentPrice: curPrice,
      threshold: threshold,
      notif: _paSelectedNotif,
      createdAt: new Date().toISOString()
    });
    paSave(alerts);

    // Atualizar botão da PDP
    _paUpdatePdpBtn(idx);

    // Atualizar card do perfil
    kzRenderProfileAlerts();

    kzClosePriceAlert();

    if(typeof showToast === 'function') {
      showToast('Alerta ativo! Kz IA monitora o preço. Vamos avisar quando chegar em ' + _fmtPrice(threshold) + '.');
    }
  };

  /* ── REMOVER ALERTA ── */
  window.kzRemovePriceAlert = function() {
    const pid = _productId(_paCurrentIdx);
    const alerts = paLoad().filter(a => a.id !== pid);
    paSave(alerts);
    _paUpdatePdpBtn(_paCurrentIdx);
    kzRenderProfileAlerts();
    kzClosePriceAlert();
    if(typeof showToast === 'function') showToast('Alerta de preço removido.');
  };

  window.kzRemovePriceAlertById = function(pid) {
    const alerts = paLoad().filter(a => a.id !== pid);
    paSave(alerts);
    // Atualizar botão da PDP se o produto removido for o atual
    if(typeof currentPdpIndex !== 'undefined') _paUpdatePdpBtn(currentPdpIndex);
    kzRenderProfileAlerts();
    if(typeof showToast === 'function') showToast('Alerta de preço removido.');
  };

  /* ── ATUALIZAR BOTÃO DA PDP ── */
  const KZPA_BELL_SVG = '<svg viewBox="0 0 24 24" width="1em" height="1em" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="vertical-align:-0.15em;"><path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 01-3.46 0"/></svg>';
  function _paUpdatePdpBtn(idx) {
    const btn       = document.getElementById('btnPriceAlert');
    const bellIcon  = document.getElementById('kzpaBellIcon');
    const btnLabel  = document.getElementById('kzpaBtnLabel');
    if(!btn) return;

    const pid      = _productId(idx);
    const existing = paGet(pid);

    if(existing) {
      btn.classList.add('kzpa-active');
      if(bellIcon) { bellIcon.innerHTML = KZPA_BELL_SVG; bellIcon.className = 'kzpa-bell-active'; }
      if(btnLabel) btnLabel.textContent = 'Alerta ativo — ' + _fmtPrice(existing.threshold);
    } else {
      btn.classList.remove('kzpa-active');
      if(bellIcon) { bellIcon.innerHTML = KZPA_BELL_SVG; bellIcon.className = ''; }
      if(btnLabel) btnLabel.textContent = 'Me Avise quando o preço baixar';
    }
  }

  /* ── RENDERIZAR ALERTAS NO PERFIL ── */
  window.kzRenderProfileAlerts = function() {
    const container = document.getElementById('cpPriceAlertsList');
    if(!container) return;

    const alerts = paLoad();

    if(alerts.length === 0) {
      container.innerHTML = `
        <div class="cp-alerts-empty">
          <span><svg viewBox="0 0 24 24" width="1em" height="1em" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 01-3.46 0"/></svg></span>
          Nenhum alerta ativo ainda.<br>
          Acesse um produto e clique em <strong>"Me Avise quando o preço baixar"</strong>.
        </div>`;
      return;
    }

    const now = Date.now();
    container.innerHTML = `<div class="cp-alerts-card">${alerts.map(a => {
      const dateStr = a.createdAt ? new Date(a.createdAt).toLocaleDateString('pt-BR') : '—';
      const diff    = a.currentPrice > 0
        ? Math.round((1 - a.threshold / a.currentPrice) * 100)
        : 0;
      const notifLabel = { push:'Push', email:'E-mail', sms:'SMS' }[a.notif||'push'] || 'Push';
      return `
      <div class="cp-alert-item-row">
        <div class="cp-alert-emoji">${a.emoji||'📦'}</div>
        <div class="cp-alert-body">
          <div class="cp-alert-name">${a.name||'Produto'}</div>
          <div class="cp-alert-meta">
            Alerta em <strong>${_fmtPrice(a.threshold)}</strong>
            · queda de ${diff}%
            · via ${notifLabel}
            · desde ${dateStr}
          </div>
        </div>
        <button class="cp-alert-del" onclick="kzRemovePriceAlertById('${a.id}')">Remover</button>
      </div>`;
    }).join('')}</div>`;
  };

  /* ── HOOK: sincronizar botão PDP quando produto muda ── */
  // Intercepta openProduct para atualizar o botão
  const _origOpenProduct = window.openProduct;
  window.openProduct = function(i) {
    if(typeof _origOpenProduct === 'function') _origOpenProduct(i);
    setTimeout(() => _paUpdatePdpBtn(i), 120);
  };

  /* ── INICIALIZAR no load ── */
  document.addEventListener('DOMContentLoaded', function() {
    // Renderizar alertas no perfil ao carregar
    kzRenderProfileAlerts();
    // Inicializar estado do botão PDP se já houver produto
    if(typeof currentPdpIndex !== 'undefined' && currentPdpIndex >= 0) {
      _paUpdatePdpBtn(currentPdpIndex);
    }
  });

  // Escape fecha modal
  document.addEventListener('keydown', function(e) {
    if(e.key === 'Escape') {
      const overlay = document.getElementById('kzPriceAlertOverlay');
      if(overlay && overlay.classList.contains('open')) kzClosePriceAlert();
    }
  });

})(); // end KZ PRICE ALERT ENGINE

/* ══════════════════════════════════════════════════════════
   KZ COMPARATOR ENGINE v1.0 — WeKz v2.6.7
   Comparador Side-by-Side: até 3 produtos
   ══════════════════════════════════════════════════════════ */
(function() {

  const MAX_ITEMS = 3;
  let _kzcList = []; // array de índices de produtos

  /* ── HELPERS ── */
  function _fmtP(v) {
    return 'R$ ' + Number(v).toFixed(2)
      .replace('.', ',')
      .replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  }
  function _stars(r) {
    const full = Math.round(Number(r));
    return '★'.repeat(Math.max(0, Math.min(5, full)));
  }
  function _prod(idx) {
    return (typeof products !== 'undefined' && products[idx]) ? products[idx] : null;
  }

  /* ── ADICIONAR / REMOVER ── */
  window.kzcToggle = function(idx) {
    const pos = _kzcList.indexOf(idx);
    if (pos !== -1) {
      _kzcList.splice(pos, 1);
    } else {
      if (_kzcList.length >= MAX_ITEMS) {
        if (typeof showToast === 'function')
          showToast('⚠️ Máximo de ' + MAX_ITEMS + ' produtos na comparação. Remova um antes de adicionar outro.');
        return;
      }
      _kzcList.push(idx);
    }
    _kzcRenderAll();
  };

  window.kzcRemove = function(idx) {
    _kzcList = _kzcList.filter(i => i !== idx);
    _kzcRenderAll();
    // Se drawer aberto, re-renderizar
    const drawer = document.getElementById('kzcDrawer');
    if (drawer && drawer.classList.contains('open')) _kzcRenderDrawer();
  };

  window.kzcClearAll = function() {
    _kzcList = [];
    _kzcRenderAll();
    kzcCloseDrawer();
  };

  /* ── ABRIR / FECHAR DRAWER ── */
  window.kzcOpenDrawer = function() {
    if (_kzcList.length < 2) {
      if (typeof showToast === 'function')
        showToast('ℹ️ Adicione pelo menos 2 produtos para comparar.');
      return;
    }
    _kzcRenderDrawer();
    const d = document.getElementById('kzcDrawer');
    if (d) {
      d.classList.add('open');
      document.body.style.overflow = 'hidden';
    }
  };

  window.kzcCloseDrawer = function() {
    const d = document.getElementById('kzcDrawer');
    if (d) d.classList.remove('open');
    document.body.style.overflow = '';
  };

  /* ── RENDERIZAR BARRA FLUTUANTE ── */
  function _kzcRenderBar() {
    const bar     = document.getElementById('kzcBar');
    const slots   = document.getElementById('kzcBarSlots');
    const btn     = document.getElementById('kzcBarCompareBtn');
    if (!bar || !slots) return;

    // Renderizar slots (sempre MAX_ITEMS slots visíveis)
    let html = '';
    for (let i = 0; i < MAX_ITEMS; i++) {
      const idx = _kzcList[i];
      const p   = idx !== undefined ? _prod(idx) : null;
      if (p) {
        html += `<div class="kzc-bar-slot filled" title="${p.n}">
          <wkz-product-image src="${p.img||''}" emoji="${p.e || '📦'}" alt="${p.n}"></wkz-product-image>
          <span class="kzc-slot-x" onclick="kzcRemove(${idx})" title="Remover">×</span>
        </div>`;
      } else {
        html += `<div class="kzc-bar-slot" title="Slot ${i+1} vazio">
          <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="rgba(0,180,171,0.35)" stroke-width="2" stroke-linecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
        </div>`;
      }
    }
    slots.innerHTML = html;

    // Botão comparar
    if (btn) btn.disabled = _kzcList.length < 2;

    // Mostrar / esconder barra
    if (_kzcList.length > 0) {
      bar.classList.add('visible');
    } else {
      bar.classList.remove('visible');
    }
  }

  /* ── ATUALIZAR BADGES NOS CARDS ── */
  function _kzcUpdateCardBadges() {
    // Todos os botões de comparar nos cards
    document.querySelectorAll('.kzc-compare-btn').forEach(btn => {
      const idx = parseInt(btn.dataset.idx, 10);
      const isAdded = _kzcList.includes(idx);
      btn.classList.toggle('added', isAdded);
      btn.innerHTML = isAdded
        ? `<svg viewBox="0 0 24 24" width="10" height="10" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20,6 9,17 4,12"/></svg> Adicionado`
        : `<svg viewBox="0 0 24 24" width="10" height="10" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="3" width="8" height="18" rx="2"/><rect x="14" y="3" width="8" height="18" rx="2"/></svg> Comparar`;
    });
  }

  /* ── RENDER GERAL ── */
  function _kzcRenderAll() {
    _kzcRenderBar();
    _kzcUpdateCardBadges();
    // Se drawer estiver aberto, re-renderizar também
    const drawer = document.getElementById('kzcDrawer');
    if (drawer && drawer.classList.contains('open')) _kzcRenderDrawer();
  }

  // Expose list getter for v2 engine
  window._kzcGetList = function() { return _kzcList.slice(); };

  /* ── RENDERIZAR DRAWER ── */
  function _kzcRenderDrawer() {
    const container = document.getElementById('kzcDrawerContent');
    if (!container) return;
    // Use v2 rich renderer if available
    if (typeof kzcRenderDrawerV2 === 'function') { kzcRenderDrawerV2(container); return; }

    const prods = _kzcList.map(idx => ({ idx, p: _prod(idx) })).filter(x => x.p);

    if (prods.length < 1) {
      container.innerHTML = `
        <div class="kzc-empty">
          <span class="kzc-empty-icon">🔍</span>
          Nenhum produto selecionado para comparação.<br>
          Feche e clique em <strong>"Comparar"</strong> nos cards de produto.
        </div>`;
      return;
    }

    // ── Calcular melhor escolha (maior pontuação ponderada) ──
    const scores = prods.map(({ idx, p }) => {
      const priceScore  = 1 / (p.p || 1);          // menor preço = melhor
      const discScore   = (p.off || 0) / 100;       // maior desconto = melhor
      const ratingScore = (p.r || 0) / 5;           // maior rating = melhor
      const salesScore  = Math.log1p(
        parseInt(String(p.sales || '0').replace(/[^\d]/g, ''), 10)
      ) / 15;
      return { idx, score: priceScore * 0.35 + discScore * 0.25 + ratingScore * 0.25 + salesScore * 0.15 };
    });
    const bestIdx = scores.reduce((a, b) => b.score > a.score ? b : a).idx;
    const bestProd = _prod(bestIdx);

    // ── HTML da tabela ──
    const numCols = prods.length + 1; // 1 label col + N produto cols

    // Cabeçalho de produtos
    let headerCells = `<th></th>`;
    prods.forEach(({ idx, p }) => {
      const isBest = idx === bestIdx;
      headerCells += `
        <th>
          <div class="kzc-prod-card" style="${isBest ? 'border-color:rgba(0,180,171,0.6);box-shadow:0 0 20px rgba(0,180,171,0.12);' : ''}">
            ${isBest ? '<div style="position:absolute;top:-1px;left:50%;transform:translateX(-50%);background:linear-gradient(135deg,var(--teal),#7C3AED);color:#000;font-size:9px;font-weight:800;padding:2px 10px;border-radius:0 0 8px 8px;white-space:nowrap;">⭐ MELHOR ESCOLHA</div>' : ''}
            <wkz-product-image class="kzc-prod-emoji" src="${p.img||''}" emoji="${p.e || '📦'}" alt="${p.n}"></wkz-product-image>
            <div class="kzc-prod-name">${p.n}</div>
            <div class="kzc-prod-store">✅ ${p.s || ''}</div>
            <div class="kzc-prod-price">${_fmtP(p.p)}</div>
            <div class="kzc-prod-off">-${p.off || 0}% OFF</div>
            <button class="kzc-prod-remove" onclick="kzcRemove(${idx})" title="Remover da comparação">✕</button>
          </div>
        </th>`;
    });
    // Slot para adicionar mais (se < MAX_ITEMS)
    if (prods.length < MAX_ITEMS) {
      headerCells += `
        <th>
          <div class="kzc-add-slot" onclick="kzcCloseDrawer();showToast('🔍 Navegue pelos produtos e clique em Comparar para adicionar mais um.')">
            <span class="kzc-add-slot-icon">＋</span>
            Adicionar produto
          </div>
        </th>`;
    }

    // Linhas de atributos
    const rows = [
      { label: 'Preço', key: 'price' },
      { label: 'Desconto', key: 'off' },
      { label: 'Avaliação', key: 'rating' },
      { label: 'Vendas', key: 'sales' },
      { label: 'Loja', key: 'store' },
      { label: 'Frete', key: 'frete' },
    ];

    // Pré-calcular best/worst por campo numérico
    const prices  = prods.map(x => x.p.p || 0);
    const offs    = prods.map(x => x.p.off || 0);
    const ratings = prods.map(x => parseFloat(x.p.r) || 0);

    function _cls(val, arr, higherIsBetter) {
      const sorted = [...arr].sort((a,b) => higherIsBetter ? b-a : a-b);
      if (val === sorted[0]) return 'kzc-val-best';
      if (val === sorted[sorted.length-1] && arr.length > 1) return 'kzc-val-worst';
      return 'kzc-val-mid';
    }

    let rowsHtml = '';
    rows.forEach(({ label, key }) => {
      let cells = `<td>${label}</td>`;
      prods.forEach(({ idx, p }) => {
        let val = '', cls = 'kzc-val-mid';
        switch(key) {
          case 'price':
            val = `<strong>${_fmtP(p.p)}</strong>`;
            cls = _cls(p.p, prices, false);
            break;
          case 'off':
            val = `<span style="color:#FF6B35;font-weight:700;">-${p.off||0}%</span>`;
            cls = _cls(p.off||0, offs, true);
            break;
          case 'rating':
            val = `<span class="kzc-stars">${_stars(p.r)}</span><br><span style="font-size:11px;">${p.r}</span>`;
            cls = _cls(parseFloat(p.r)||0, ratings, true);
            break;
          case 'sales':
            val = p.sales || '—';
            break;
          case 'store':
            val = `<span style="font-size:11px;">✅ ${p.s||'—'}</span>`;
            break;
          case 'frete':
            val = '<span style="color:#22C55E;font-weight:700;">🚚 Grátis</span>';
            break;
        }
        cells += `<td class="${cls}">${val}</td>`;
      });
      // Célula vazia para slot de adicionar
      if (prods.length < MAX_ITEMS) cells += '<td></td>';
      rowsHtml += `<tr class="kzc-row">${cells}</tr>`;
    });

    // Linha CTA (botão adicionar ao carrinho)
    let ctaCells = '<td></td>';
    prods.forEach(({ idx, p }) => {
      ctaCells += `<td><button class="kzc-cart-btn" onclick="kzcCloseDrawer();btnFeedback ? btnFeedback(document.querySelector('.btn-add'), ()=>addToCart(${idx})) : addToCart(${idx});showToast('🛒 ${p.e} Adicionado ao carrinho!')">🛒 Comprar</button></td>`;
    });
    if (prods.length < MAX_ITEMS) ctaCells += '<td></td>';

    // Banner de melhor escolha
    const winnerBanner = bestProd ? `
      <div class="kzc-winner-banner">
        <span style="font-size:20px;">${bestProd.e || '🏆'}</span>
        <div>
          <span class="kzc-winner-badge">🏆 MELHOR CUSTO-BENEFÍCIO</span><br>
          <strong>${bestProd.n}</strong> se destaca com o melhor balanço entre preço, desconto e avaliações dos compradores.
        </div>
      </div>` : '';

    container.innerHTML = `
      ${winnerBanner}
      <div style="overflow-x:auto;">
        <table class="kzc-table">
          <thead>
            <tr class="kzc-header-row">${headerCells}</tr>
          </thead>
          <tbody>
            ${rowsHtml}
            <tr class="kzc-row kzc-row-cta">${ctaCells}</tr>
          </tbody>
        </table>
      </div>`;
  }

  /* ── INJETAR BOTÃO "COMPARAR" NOS CARDS (pós-render) ── */
  window.kzcInjectCompareButtons = function() {
    document.querySelectorAll('.product-card[data-name]').forEach(card => {
      if (card.querySelector('.kzc-compare-btn')) return; // já tem
      // Descobrir índice via onclick do card
      const m = (card.getAttribute('onclick') || '').match(/openProduct\((\d+)\)/);
      if (!m) return;
      const idx = parseInt(m[1], 10);
      if (isNaN(idx)) return;

      const btn = document.createElement('button');
      btn.className = 'kzc-compare-btn';
      btn.dataset.idx = idx;
      const isAdded = _kzcList.includes(idx);
      btn.classList.toggle('added', isAdded);
      btn.innerHTML = isAdded
        ? `<svg viewBox="0 0 24 24" width="10" height="10" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20,6 9,17 4,12"/></svg> Adicionado`
        : `<svg viewBox="0 0 24 24" width="10" height="10" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="3" width="8" height="18" rx="2"/><rect x="14" y="3" width="8" height="18" rx="2"/></svg> Comparar`;
      btn.onclick = function(e) {
        e.stopPropagation();
        e.preventDefault();
        kzcToggle(idx);
      };
      // Inserir no product-img (onde ficam os badges)
      const imgDiv = card.querySelector('.product-img');
      if (imgDiv) imgDiv.appendChild(btn);
    });
  };

  /* ── BOTÃO "COMPARAR" NA PDP ── */
  window.kzcTogglePdp = function() {
    const idx = (typeof currentPdpIndex !== 'undefined') ? currentPdpIndex : -1;
    if (idx < 0) return;
    const wasAdded = _kzcList.includes(idx);
    // [v2.9.29 BUGFIX] O comentário abaixo já documentava a intenção correta,
    // mas o código antigo chamava kzcToggle() incondicionalmente — ou seja,
    // reclicar no MESMO produto removia-o da comparação em vez de abrir o
    // drawer. Agora a remoção só ocorre pelo botão "✕" dedicado (kzcRemovePdp).
    if (wasAdded) { kzcOpenDrawer(); return; }
    kzcToggle(idx);
    _kzcUpdatePdpBtn(idx);
  };

  /* Remover produto da comparação via botão dedicado na PDP */
  window.kzcRemovePdp = function() {
    const idx = (typeof currentPdpIndex !== 'undefined') ? currentPdpIndex : -1;
    if (idx < 0) return;
    kzcRemove(idx);
    _kzcUpdatePdpBtn(idx);
  };

  function _kzcUpdatePdpBtn(idx) {
    const btn = document.getElementById('kzcPdpBtn');
    if (!btn) return;
    const isAdded = _kzcList.includes(idx);
    btn.classList.toggle('kzpa-active', isAdded);
    if (isAdded) {
      btn.innerHTML =
        `<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20,6 9,17 4,12"/></svg>`
        + ` Na comparação`
        + ` · <span style="font-size:11px;text-decoration:underline;opacity:.8;" onclick="event.stopPropagation();kzcOpenDrawer()">Ver comparação</span>`
        + ` · <span style="font-size:11px;opacity:.6;" onclick="event.stopPropagation();kzcRemovePdp()" title="Remover da comparação">✕</span>`;
    } else {
      btn.innerHTML =
        `<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="3" width="8" height="18" rx="2"/><rect x="14" y="3" width="8" height="18" rx="2"/></svg> Adicionar à comparação`;
    }
  }

  /* ── HOOK openProduct ── */
  const _origOpenProductComp = window.openProduct;
  window.openProduct = function(i) {
    if (typeof _origOpenProductComp === 'function') _origOpenProductComp(i);
    setTimeout(() => _kzcUpdatePdpBtn(i), 130);
  };

  /* ── HOOK renderProducts / renderGrid ── */
  // Observar mudanças no productsGrid para injetar botões após re-render
  function _kzcObserveGrid() {
    const grid = document.getElementById('productsGrid');
    if (!grid) return;
    const observer = new MutationObserver(() => {
      setTimeout(kzcInjectCompareButtons, 60);
    });
    observer.observe(grid, { childList: true, subtree: false });
  }

  /* ── TECLA ESCAPE fecha drawer ── */
  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') {
      const d = document.getElementById('kzcDrawer');
      if (d && d.classList.contains('open')) kzcCloseDrawer();
    }
  });

  /* ── INIT ── */
  document.addEventListener('DOMContentLoaded', function() {
    _kzcObserveGrid();
    // Injetar botões no grid inicial após um tick
    setTimeout(kzcInjectCompareButtons, 300);
  });

})(); // end KZ COMPARATOR ENGINE

/* ══════════════════════════════════════════════════════════
   KZ TOUR ENGINE v1.2 — Médio #16 — WeKz v2.6.7
   Modal centralizado · sem posicionamento JS · SVG icons
   ══════════════════════════════════════════════════════════ */
(function(){
  'use strict';

  var STORE_KEY = 'kzTourDone_v1';
  var _step   = 0;
  var _active = false;
  var _prevEl = null;

  /* ── SVG icons ─────────────────────────────────────────── */
  var ICONS = {
    bag:    '<svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M6 2L3 6v14a2 2 0 002 2h14a2 2 0 002-2V6l-3-4z"/><line x1="3" y1="6" x2="21" y2="6"/><path d="M16 10a4 4 0 01-8 0"/></svg>',
    search: '<svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>',
    flash:  '<svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><polygon points="13,2 3,14 12,14 11,22 21,10 12,10 13,2"/></svg>',
    coin:   '<svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="8" y1="12" x2="16" y2="12"/><line x1="12" y1="8" x2="12" y2="16"/></svg>',
    shield: '<svg viewBox="0 0 24 24" width="22" height="22" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/><polyline points="9,12 11,14 15,10"/></svg>',
  };

  /* ── PASSOS ─────────────────────────────────────────────── */
  var STEPS = [
    {
      icon:  'bag',
      title: 'Bem-vindo à WeKz Shop!',
      desc:  'O marketplace com <strong>proteção total ao comprador</strong>. Vamos te mostrar os recursos essenciais em menos de 1 minuto.',
    },
    {
      icon:  'search',
      title: 'Busca Inteligente',
      desc:  'Pesquise qualquer produto. Use os <strong>filtros rápidos</strong> por preço, frete grátis e avaliação.',
      spotlight: 'heroSearchBar',
    },
    {
      icon:  'flash',
      title: 'Flash Sale',
      desc:  'Ofertas relâmpago com descontos de até <strong>70%</strong>. Produtos limitados com contagem regressiva.',
      spotlight: 'flashHeroSection',
    },
    {
      icon:  'coin',
      title: 'WeKz Coins',
      desc:  'Ganhe <strong>1 ponto por R$1</strong> em toda compra (2× em Flash Sale). Troque por descontos e frete grátis.',
    },
    {
      icon:  'shield',
      title: 'Proteção Total',
      desc:  'Toda compra tem <strong>garantia WeKz</strong>: reembolso fácil, disputas resolvidas em 5 dias e suporte 24/7.',
    },
  ];

  /* ── SPOTLIGHT (apenas destaca — não posiciona tooltip) ─── */
  function _spotlight(elId) {
    var hole = document.getElementById('kzTourHole');
    if (!hole) return;
    if (_prevEl) { _prevEl.classList.remove('kzt-highlight'); _prevEl = null; }
    if (!elId) { hole.setAttribute('width','0'); hole.setAttribute('height','0'); return; }
    var el = document.getElementById(elId) || document.querySelector('.' + elId);
    if (!el) { hole.setAttribute('width','0'); hole.setAttribute('height','0'); return; }
    el.classList.add('kzt-highlight');
    _prevEl = el;
    el.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    var r = el.getBoundingClientRect(), P = 10;
    hole.setAttribute('x',      r.left   - P);
    hole.setAttribute('y',      r.top    - P);
    hole.setAttribute('width',  r.width  + P * 2);
    hole.setAttribute('height', r.height + P * 2);
    hole.setAttribute('rx', '12');
  }

  /* ── RENDER DOTS ────────────────────────────────────────── */
  function _dots(cur) {
    var el = document.getElementById('kzTourDots');
    if (!el) return;
    el.innerHTML = STEPS.map(function(_,i){
      return '<span class="kzt-dot' + (i < cur ? ' done' : i === cur ? ' active' : '') + '"></span>';
    }).join('');
  }

  /* ── RENDER STEP ────────────────────────────────────────── */
  function _render(i) {
    var s   = STEPS[i];
    var tip = document.getElementById('kzTourTooltip');
    if (!tip || !s) return;

    document.getElementById('kzTourIcon').innerHTML        = ICONS[s.icon] || ICONS.bag;
    document.getElementById('kzTourStepLabel').textContent = 'Passo ' + (i+1) + ' de ' + STEPS.length;
    document.getElementById('kzTourTitle').textContent     = s.title;
    document.getElementById('kzTourDesc').innerHTML        = s.desc;

    var btn    = document.getElementById('kzTourNextBtn');
    var isLast = i === STEPS.length - 1;
    btn.textContent = isLast ? 'Começar ✓' : 'Próximo →';
    btn.className   = 'kzt-btn-next' + (isLast ? ' finish' : '');

    _dots(i);
    _spotlight(s.spotlight || null);

    setTimeout(function(){ tip.classList.add('visible'); }, 40);
  }

  /* ── API PÚBLICA ────────────────────────────────────────── */
  window.kzTourStart = function(force) {
    if ((typeof wkzSecureStorage!=='undefined'?wkzSecureStorage.get(STORE_KEY):localStorage.getItem(STORE_KEY)) && !force) return; // C4
    _step = 0; _active = true;
    var overlay = document.getElementById('kzTourOverlay');
    if (overlay) overlay.classList.add('active');
    if (typeof showPage === 'function') showPage('home');
    setTimeout(function(){ _render(0); }, 150);
  };

  window.kzTourNext = function() {
    if (!_active) return;
    var tip = document.getElementById('kzTourTooltip');
    tip.classList.remove('visible');
    _step++;
    if (_step >= STEPS.length) { kzTourEnd(); return; }
    setTimeout(function(){ _render(_step); }, 220);
  };

  window.kzTourSkip = function() { kzTourEnd(); };

  window.kzTourEnd = function() {
    _active = false;
    // C4: grava conclusão do tour via wkzSecureStorage
    if(typeof wkzSecureStorage!=='undefined'){wkzSecureStorage.set(STORE_KEY,'1');}else{localStorage.setItem(STORE_KEY,'1');}
    if (_prevEl) { _prevEl.classList.remove('kzt-highlight'); _prevEl = null; }
    var overlay = document.getElementById('kzTourOverlay');
    var tip     = document.getElementById('kzTourTooltip');
    var hole    = document.getElementById('kzTourHole');
    if (overlay) overlay.classList.remove('active');
    if (tip)     tip.classList.remove('visible');
    if (hole)    { hole.setAttribute('width','0'); hole.setAttribute('height','0'); }
    var lb = document.getElementById('kzTourLaunchBtn');
    if (lb) lb.classList.add('visible');
    setTimeout(function(){
      if (typeof showPage === 'function') showPage('home');
      if (typeof showToast === 'function') showToast('🎉 Bem-vindo à WeKz! Boas compras.');
    }, 220);
  };

  document.addEventListener('keydown', function(e){
    if (e.key === 'Escape' && _active) kzTourEnd();
  });

  document.addEventListener('DOMContentLoaded', function(){
    setTimeout(function(){
      if (!(typeof wkzSecureStorage!=='undefined'?wkzSecureStorage.get(STORE_KEY):localStorage.getItem(STORE_KEY))) { // C4
        kzTourStart(false);
      } else {
        var lb = document.getElementById('kzTourLaunchBtn');
        if (lb) lb.classList.add('visible');
      }
    }, 900);
  });

})(); // end KZ TOUR ENGINE

