function changeQty(d){
  const el=document.getElementById('qtyNum');
  if(!el)return;
  const maxStock = typeof window._pdpCurrentStock === 'number' ? window._pdpCurrentStock : 99;
  const maxQty   = maxStock > 0 ? Math.min(maxStock, 99) : 99;
  let v=parseInt(el.textContent)+d;
  if(v<1)v=1;
  if(v>maxQty){
    v=maxQty;
    if(maxStock>0 && maxStock<10) showToast('⚠️ Só ' + maxStock + ' unidades em estoque!');
  }
  el.textContent=v;
}

/* ════════════════════════════════════════════════
   MICRO-INTERAÇÃO GLOBAL — WeKz v1.0.5
   btnFeedback(btn, onSuccess, opts)
   Gerencia spinner → check para QUALQUER botão
   com classes .btn-add, .btn-buy, .btn-flash-buy
   ou o legado .btn-cart
   ════════════════════════════════════════════════ */
function btnFeedback(btn, onSuccess, opts) {
  opts = opts || {};
  if (btn.disabled) return;

  const loadingMs  = opts.loadingMs  || 750;
  const successMs  = opts.successMs  || 1600;
  const isFlash    = btn.classList.contains('btn-flash-buy');

  btn.disabled = true;

  // ── 1. Loading ──
  btn.classList.add('btn-loading');
  if (isFlash) {
    btn.classList.remove('btn-shock');
    btn.style.animationPlayState = 'paused';
  }

  setTimeout(() => {
    // ── 2. Run callback (e.g. addToCart) ──
    if (typeof onSuccess === 'function') onSuccess();

    // ── 3. Success ──
    btn.classList.remove('btn-loading');
    btn.classList.add('btn-success');

    // Flash: add energetic sweep shockwave
    if (isFlash) {
      btn.classList.add('btn-shock');
    }

    // ── 4. Reset ──
    setTimeout(() => {
      btn.classList.remove('btn-success', 'btn-shock');
      btn.disabled = false;
      if (isFlash) btn.style.animationPlayState = '';
    }, successMs);

  }, loadingMs);
}

/* ─── Cart Button Animation (legado + refatorado) ─── */
function animateCartBtn(btn, productIndex) {
  btnFeedback(btn, () => addToCart(productIndex));
}

function addToCart(productIndex){
  /* Resolve product object */
  const p = (productIndex !== undefined && products[productIndex])
    ? products[productIndex]
    : (currentPdpIndex >= 0 ? products[currentPdpIndex] : null);

  const rawPrice = p ? p.p : 0;          // numeric (e.g. 1249.90) — preço já ofertado (com desconto)
  // [v2.9.30 BUGFIX] op = preço de tabela ("De") usado para calcular o Desconto real
  // no carrinho/checkout. Sem isto, o sistema não tinha como saber que o produto já
  // tem um desconto anunciado, e acabava aplicando um desconto extra fixo de 10%
  // sobre o preço que JÁ estava com desconto (dupla contagem).
  const op       = (p && typeof p.op === 'number' && p.op > rawPrice) ? p.op : rawPrice;
  const itemId   = p ? ('prod-' + (p.n||'item').replace(/\s/g,'_').toLowerCase()) : ('fallback-' + Date.now());
  const emoji    = p ? p.e  : '📦';
  const name     = p ? p.n  : 'Produto';
  const store    = p ? (p.s || 'WeKz Shop') : 'Loja WeKz';
  const variant  = 'Padrão';

  /* Check if already in cart → increment qty */
  const existing = cartItemsData.find(c => c.id === itemId);
  if(existing){
    existing.qty++;
    showToast('➕ +1 "' + name + '" no carrinho!');
  } else {
    cartItemsData.push({ id: itemId, e: emoji, n: name, s: store, v: variant, rawPrice, op, qty: 1 });
    showToast('🛒 "' + name + '" adicionado ao carrinho!');
  }

  updateCartUI();
}

function updateCartUI(){
  /* Total qty across all items (e.g. 2 camisetas + 1 fone = 3) */
  const totalQty = cartItemsData.reduce((acc, c) => acc + c.qty, 0);
  const uniqueItems = cartItemsData.length;

  // ── 1. Badge desktop (topo) ──
  const topBadge = document.getElementById('cartBadge');
  if(topBadge){
    topBadge.textContent = totalQty > 99 ? '99+' : totalQty;
    topBadge.style.transition = 'transform 0s';
    topBadge.style.transform  = 'scale(1.6)';
    setTimeout(()=>{
      topBadge.style.transition = 'transform 0.3s cubic-bezier(0.34,1.56,0.64,1)';
      topBadge.style.transform  = 'scale(1)';
    }, 20);
  }

  // ── 2. Badge mobile (bottom nav) ──
  const mobileBadge = document.getElementById('bnavCartBadge');
  const mobileBtn   = document.getElementById('bnav-cart');
  const prevCount   = window._wkzPrevCartCount || 0;

  if(mobileBadge){
    mobileBadge.textContent = totalQty > 99 ? '99+' : totalQty;
    if(totalQty > 0){
      mobileBadge.style.display = 'flex';
      mobileBadge.classList.add('visible');
      if(totalQty > prevCount){
        mobileBadge.classList.remove('badge-pop');
        void mobileBadge.offsetWidth;
        mobileBadge.classList.add('badge-pop');
        setTimeout(()=> mobileBadge.classList.remove('badge-pop'), 480);
        if(mobileBtn){
          mobileBtn.classList.remove('cart-bounce');
          void mobileBtn.offsetWidth;
          mobileBtn.classList.add('cart-bounce');
          setTimeout(()=> mobileBtn.classList.remove('cart-bounce'), 540);
        }
      }
    } else {
      mobileBadge.classList.remove('visible','badge-pop');
      setTimeout(()=>{ if(cartItemsData.length===0) mobileBadge.style.display='none'; }, 220);
    }
  }

  window._wkzPrevCartCount = totalQty;
  window.cartCount = totalQty;

  // ── 3. Cart header count label ──
  const cartHeader = document.querySelector('#page-cart .cart-header h2');
  if(cartHeader){
    const plural = uniqueItems === 1 ? 'item' : 'itens';
    const qtyNote = totalQty !== uniqueItems ? ` · ${totalQty} un.` : '';
    cartHeader.innerHTML = `<span class="wkz-icon wkz-icon-cart"><svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 001.99 1.61h9.72a2 2 0 001.99-1.61L23 6H6"/></svg></span> Meu Carrinho <span style="font-size:14px;color:var(--muted);font-weight:400;">(${uniqueItems} ${plural}${qtyNote})</span>`;
  }

  // ── 4. Calculate totals using selected items only ──
  const selectedItems = cartItemsData.filter(c => c._selected !== false);
  let subtotal = 0;
  selectedItems.forEach(c => {
    const price = typeof c.rawPrice === 'number' ? c.rawPrice : 0;
    subtotal += price * c.qty;
  });

  // Full subtotal for free shipping bar
  let fullSubtotal = 0;
  cartItemsData.forEach(c => {
    const price = typeof c.rawPrice === 'number' ? c.rawPrice : 0;
    fullSubtotal += price * c.qty;
  });

  // ── Cálculo de descontos ──
  // [v2.9.30 BUGFIX] Reformulado por completo. O cálculo anterior tratava
  // rawPrice (preço JÁ COM desconto anunciado, ex: R$3.499,00 de um produto
  // de R$5.299,00) como se fosse o preço cheio, e ainda somava um desconto
  // FIXO de 10% por cima — uma dupla contagem que reduzia o Total para menos
  // do que o vendedor realmente cobra. Agora:
  //   Subtotal = preço de TABELA (op) — o valor "De" antes do desconto anunciado
  //   Desconto = (op - rawPrice) [desconto real do produto] + desconto de cupom
  //   Total    = rawPrice (o preço já ofertado) − desconto de cupom elegível
  // Subtotal − Desconto = Total, sempre.
  const fmt = v => 'R$ ' + v.toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g, '.');

  const ac = window._activeCoupon;

  // Itens com desconto já anunciado (produto, flash ou live) NÃO são elegíveis
  // a cupom adicional — regra de negócio para não empilhar descontos.
  const isPromoItem      = c => !!c._isFlash || !!c._isLive || (typeof c.op === 'number' && c.op > c.rawPrice);
  const promoItems_sel   = selectedItems.filter(isPromoItem);
  const normalItems_sel  = selectedItems.filter(c => !isPromoItem(c));

  // Subtotal = soma do preço de tabela (op, ou rawPrice se não houver desconto)
  let subtotalFull = selectedItems.reduce((s,c) => s + (typeof c.op==='number'?c.op:c.rawPrice) * c.qty, 0);
  // Desconto real já anunciado em cada produto (op - rawPrice)
  let promoDiscount = selectedItems.reduce((s,c) => s + Math.max(0,(typeof c.op==='number'?c.op:c.rawPrice) - c.rawPrice) * c.qty, 0);
  // Base elegível a cupom (itens SEM desconto já anunciado)
  let subtotalNormal = normalItems_sel.reduce((s,c) => s + c.rawPrice * c.qty, 0);

  let couponDiscount = 0;
  let freteGratis    = false;
  let couponBlocked  = false;  // cupom não aplicável (flash/live/produto já com desconto)
  let couponMinFail  = false;  // não atingiu mínimo

  if(ac){
    // Verifica mínimo de compra (sobre o total aplicável)
    const applicableBase = ac.type === 'frete' ? subtotal : subtotalNormal;
    if(ac.minimo > 0 && applicableBase < ac.minimo){
      couponMinFail = true;
    } else if(ac.type === '%'){
      // % só se aplica a itens sem desconto já anunciado
      if(subtotalNormal > 0){
        couponDiscount = subtotalNormal * (ac.disc / 100);
      } else {
        couponBlocked = true;
      }
    } else if(ac.type === 'fixed'){
      if(subtotalNormal > 0){
        couponDiscount = Math.min(parseFloat(ac.disc) || 0, subtotalNormal);
      } else {
        couponBlocked = true;
      }
    } else if(ac.type === 'frete'){
      freteGratis = true;
      // frete grátis válido para TODOS os itens incluindo flash/live/promo
    }
  }

  const totalDiscount = promoDiscount + couponDiscount;
  const total = Math.max(0, subtotal - couponDiscount); // subtotal aqui = soma de rawPrice (preço já ofertado)

  const subtotalEl = document.getElementById('cartSubtotal');
  const totalEl    = document.getElementById('cartTotal');
  if(subtotalEl) subtotalEl.textContent = fmt(subtotalFull);
  if(totalEl)    totalEl.textContent    = fmt(total);

  // Linha de desconto — mostra detalhamento
  const discountRowEl = document.getElementById('cartDiscountRow');
  const discountValEl = document.getElementById('cartDiscountVal');
  if(discountValEl){
    if(totalDiscount > 0){
      discountValEl.textContent = '−' + fmt(totalDiscount);
      discountValEl.style.color = '#FF6B35';
    } else {
      discountValEl.textContent = 'R$ 0,00';
      discountValEl.style.color = '';
    }
  }
  // fallback para summaryRows antigos
  const summaryRows = document.querySelectorAll('#page-cart .summary-row');
  summaryRows.forEach(row => {
    const label = row.querySelector('span:first-child');
    const val   = row.querySelector('span:last-child');
    if(label && val && label.textContent.trim() === 'Desconto'){
      val.textContent = totalDiscount > 0 ? '−' + fmt(totalDiscount) : 'R$ 0,00';
      val.style.color = totalDiscount > 0 ? '#FF6B35' : '';
    }
  });

  // ── 5. Free shipping progress bar ──
  const FREE_SHIPPING_THRESHOLD = 150;
  const cfsbBar = document.getElementById('cartFreeShippingBar');
  const cfsbFill = document.getElementById('cfsbFill');
  const cfsbText = document.getElementById('cfsbText');
  const cfsbBadge = document.getElementById('cfsbBadge');
  if(cfsbBar && cartItemsData.length > 0){
    cfsbBar.style.display = 'block';
    const pct = Math.min(100, (fullSubtotal / FREE_SHIPPING_THRESHOLD) * 100);
    if(cfsbFill) cfsbFill.style.width = pct + '%';
    if(fullSubtotal >= FREE_SHIPPING_THRESHOLD){
      if(cfsbText) cfsbText.style.display = 'none';
      if(cfsbBadge){ cfsbBadge.style.display = 'inline-flex'; }
      if(cfsbFill) cfsbFill.classList.add('cfsb-fill-done');
    } else {
      const remaining = FREE_SHIPPING_THRESHOLD - fullSubtotal;
      if(cfsbText){ cfsbText.style.display=''; cfsbText.innerHTML = `Adicione <strong>R$ ${remaining.toFixed(2).replace('.',',')}</strong> para frete grátis!`; }
      if(cfsbBadge) cfsbBadge.style.display = 'none';
      if(cfsbFill) cfsbFill.classList.remove('cfsb-fill-done');
    }
  } else if(cfsbBar){
    cfsbBar.style.display = 'none';
  }

  // ── 6. Banner informativo do cupom (Shopee/ML style) ──
  const couponInfoEl = document.getElementById('cartCouponInfo');
  if(ac && couponInfoEl){
    let discText = '';
    let bannerColor = 'rgba(0,180,171,0.08)';
    let bannerBorder = 'rgba(0,180,171,0.2)';
    let textColor = 'var(--teal)';

    if(couponMinFail){
      const diff = (ac.minimo - (ac.type==='frete' ? subtotal : subtotalNormal));
      discText = `⚠️ Cupom <strong>${ac.code}</strong> requer mínimo de ${fmt(ac.minimo)}. Faltam ${fmt(diff)}.`;
      bannerColor='rgba(245,158,11,0.08)'; bannerBorder='rgba(245,158,11,0.3)'; textColor='#F59E0B';
    } else if(couponBlocked){
      // [v2.9.30] Mensagem cobre os 3 motivos possíveis de bloqueio: Flash Sale,
      // Live Shopping ou produto regular que já tem desconto anunciado.
      discText = `ℹ️ Cupom <strong>${ac.code}</strong> não se aplica a produtos que já têm desconto anunciado (Flash Sale, Live Shopping ou promoção do produto). Adicione um produto sem desconto para usar este cupom.`;
      bannerColor='rgba(148,163,184,0.08)'; bannerBorder='rgba(148,163,184,0.2)'; textColor='var(--muted)';
    } else if(ac.type==='%'){
      discText = `🏷️ Cupom <strong>${ac.code}</strong>: −${fmt(couponDiscount)} (${ac.disc}% OFF em itens regulares)`;
      if(promoItems_sel.length > 0) discText += ` <span style="font-size:10px;opacity:0.7">· itens com desconto já anunciado mantêm o preço de oferta</span>`;
    } else if(ac.type==='fixed'){
      discText = `🏷️ Cupom <strong>${ac.code}</strong>: −${fmt(couponDiscount)} em itens regulares`;
    } else if(ac.type==='frete'){
      discText = '🚚 <strong>Frete Grátis</strong> aplicado a todos os itens!';
      if(cfsbBadge){ cfsbBadge.style.display='inline-flex'; }
      if(cfsbText)  cfsbText.style.display='none';
    }

    const couponTextEl = document.getElementById('cartCouponText');
    if(couponTextEl) couponTextEl.innerHTML = discText;
    if(discText){
      couponInfoEl.style.display = 'flex';
      couponInfoEl.style.background = bannerColor;
      couponInfoEl.style.borderColor = bannerBorder;
      couponInfoEl.style.color = textColor;
    } else {
      couponInfoEl.style.display = 'none';
    }
  } else if(couponInfoEl){
    couponInfoEl.style.display='none';
  }

  // ── 7. Re-render cart items list ──
  renderCart();
}

function wishToggle(btn, productIndex, evt){
  /* Bloqueia propagação para o card pai (previne abertura do produto no mobile) */
  if(evt){ evt.stopPropagation(); evt.preventDefault(); }

  /* Descobre o índice do produto a partir do botão ou do parâmetro */
  let idx = productIndex;
  if(idx === undefined){
    const card = btn.closest('.product-card');
    if(card){
      const allCards = Array.from(document.querySelectorAll('#productsGrid .product-card'));
      idx = allCards.indexOf(card);
    }
  }
  const product = (idx !== undefined && idx >= 0) ? products[idx] : null;
  const productId = product ? (product.n + '_' + product.p) : null;

  const isWished = btn.textContent === '♥';

  if(!isWished){
    /* Adiciona ao array de favoritos */
    btn.textContent = '♥';
    btn.style.color = '#FF2D7A';
    if(product && productId && !wishlistItems.find(w => (w.n + '_' + w.p) === productId)){
      wishlistItems.push({...product, _wkzIdx: idx});
    }
    showToast('❤️ Adicionado aos favoritos!');
  } else {
    /* Remove do array de favoritos */
    btn.textContent = '♡';
    btn.style.color = '';
    if(productId){
      wishlistItems = wishlistItems.filter(w => (w.n + '_' + w.p) !== productId);
    }
    showToast('💔 Removido dos favoritos');
  }

  /* Atualiza badge e contadores */
  syncWishHearts();

  /* Atualiza contadores das abas se visíveis */
  const cntP = document.getElementById('wtCountProducts');
  if(cntP) cntP.textContent = wishlistItems.length;

  /* Se estiver na página de favoritos, re-renderiza imediatamente */
  const wishPage = document.getElementById('page-wishlist');
  if(wishPage && wishPage.classList.contains('active')){
    renderWishlist();
  }
}

// ─── LOGIN — FIX BUG-AUTH01 ───
// Substituiu: showToast('Login realizado com sucesso!')
// Agora valida e-mail, senha obrigatória e informa que
// a integração com servidor está pendente.
function doLogin() {
  /* FIX Sprint M5 (Hardening): rate limit client-side — máx. 5 tentativas
     por minuto. Mitigação básica de UX contra tentativas grosseiras
     repetidas; não substitui rate limiting real do servidor. */
  if (typeof wkzRateLimit === 'function' && !wkzRateLimit('login', 5, 60000)) {
    showToast('⚠️ Muitas tentativas de login. Aguarde um minuto e tente novamente.');
    return;
  }

  var email = (document.getElementById('loginEmail') || {}).value || '';
  var pw    = (document.getElementById('loginPassword') || {}).value || '';
  email = email.trim();

  if (!email) {
    showToast('⚠️ Informe o seu e-mail ou telefone');
    document.getElementById('loginEmail').focus();
    return;
  }
  if (email.indexOf('@') > -1 && !validateEmail(email)) {
    showToast('⚠️ E-mail inválido — verifique o formato');
    document.getElementById('loginEmail').focus();
    return;
  }
  if (!pw) {
    showToast('⚠️ Informe a sua senha');
    document.getElementById('loginPassword').focus();
    return;
  }
  // Futuro: fetch('/api/auth/login', { method:'POST', body: JSON.stringify({email, pw}) })
  // Por ora — integração com servidor ainda não disponível
  // [v2.9.13] Login mock: ativa o estado "comprador logado" para liberar
  // elementos buyer-only (ex.: "Meus Favoritos") já no front-end, mesmo
  // sem resposta real de servidor.
  if (typeof window.wkzSetBuyerLoggedIn === 'function') window.wkzSetBuyerLoggedIn(true);
  showToast('🔄 Login pendente de integração com servidor');
}

// ─── AUTH TABS ───
function switchAuthTab(tab,el){
  document.querySelectorAll('.auth-tab').forEach(t=>t.classList.remove('active'));
  el.classList.add('active');
  /* FIX Sprint M2: #auth-seller foi removido de wkz-buyer.html (virou
     navegação cross-file pro wkz-seller.html — ver page-auth). Sem este
     guard, getElementById('auth-seller') retorna null e quebra até a
     troca para 'login'/'register', que continuam existindo aqui. */
  ['login','register','seller'].forEach(t=>{
    var el2 = document.getElementById('auth-'+t);
    if (el2) el2.style.display = (t===tab?'block':'none');
  });
}

