// ══════════════════════════════════════════════════════
//  STOCK ENGINE v1 — Notificação de Estoque Baixo na PDP
// ══════════════════════════════════════════════════════

// Níveis: critical (1-4), low (5-14), moderate (15-29), normal (>=30), out (0)
function _stockLevel(stock) {
  if (stock === 0)   return 'out';
  if (stock <= 4)    return 'critical';
  if (stock <= 14)   return 'low';
  if (stock <= 29)   return 'moderate';
  return 'normal';
}

function _stockConfig(level, stock, productName) {
  const configs = {
    out: {
      label: 'Esgotado temporariamente',
      icon: '😔', accentColor: '#64748B',
      toastTitle: 'Produto esgotado',
      toastSub: `"${productName}" está fora de estoque. Ative o alerta para ser avisado quando voltar.`,
      copy: 'Este produto está temporariamente fora de estoque. Ative o alerta para ser o primeiro a saber quando voltar.',
      showBar: false, showToast: false,
    },
    critical: {
      label: `Restam apenas ${stock} unidades!`,
      icon: '🔥', accentColor: '#EF4444',
      toastTitle: `🔥 Quase esgotando — só ${stock} ${stock === 1 ? 'unidade' : 'unidades'}!`,
      toastSub: `"${productName}" está acabando. Várias pessoas estão olhando agora.`,
      copy: `<strong>Alta demanda!</strong> Com ${stock} ${stock === 1 ? 'unidade restante' : 'unidades restantes'} e múltiplos compradores ativos, este produto pode esgotar a qualquer momento.`,
      showBar: true, showToast: true,
    },
    low: {
      label: `Estoque baixo — ${stock} unidades`,
      icon: '⚠️', accentColor: '#FF6B35',
      toastTitle: `⚠️ Estoque baixo — ${stock} unidades`,
      toastSub: `"${productName}" está com poucas unidades. Garanta o seu antes que acabe.`,
      copy: `<strong>${stock} unidades disponíveis.</strong> Produto com alta saída — garanta o seu antes que esgote.`,
      showBar: true, showToast: true,
    },
    moderate: {
      label: `${stock} unidades disponíveis`,
      icon: '📦', accentColor: '#F59E0B',
      toastTitle: null, // não dispara toast para moderado
      toastSub: null,
      copy: `Produto disponível com ${stock} unidades em estoque.`,
      showBar: true, showToast: false,
    },
    normal: {
      label: 'Em estoque',
      icon: '✅', accentColor: '#22C55E',
      toastTitle: null,
      toastSub: null,
      copy: 'Disponível. Envio em 1-2 dias úteis após confirmação do pagamento.',
      showBar: false, showToast: false,
    },
  };
  return configs[level];
}

// Render the stock widget into #pdpStockWidget
function renderStockWidget(productIdx) {
  var el = document.getElementById('pdpStockWidget');
  if (!el) return;

  var p = products[productIdx];
  if (!p) { el.innerHTML = ''; return; }

  var stock    = typeof p.stock    === 'number' ? p.stock    : 99;
  var stockMax = typeof p.stockMax === 'number' ? p.stockMax : 100;
  var level    = _stockLevel(stock);
  var cfg      = _stockConfig(level, stock, p.n.split(' — ')[0]);

  // ── Per-product social proof seeding ──────────────────────────────────────
  // Seeded pseudo-random from productIdx for deterministic but varied values
  var _seed = (productIdx * 137 + 41) % 100;
  var seedViewers = 120 + (_seed * 3) % 230; // 120–349
  var seedSold    =   8 + (_seed * 7) % 47;  // 8–54

  var lvEl = document.getElementById('liveViewers');
  if (lvEl) lvEl.textContent = seedViewers;
  window._pdpViewerBase = seedViewers; // used by animateViewers

  var scEl = document.getElementById('pdpSoldCount');
  if (scEl) {
    if (stock > 0) {
      var _scVal = document.getElementById('pdpSoldCountVal'); if (_scVal) { _scVal.textContent = seedSold + ' vendidos nas últimas 2h'; } else { scEl.textContent = seedSold + ' vendidos nas últimas 2h'; }
      scEl.style.display = '';
    } else {
      scEl.style.display = 'none';
    }
  }
  // ─────────────────────────────────────────────────────────────────────────

  // Update qty control max
  var qtyNum = document.getElementById('qtyNum');
  if (qtyNum) {
    var cur = parseInt(qtyNum.textContent) || 1;
    if (stock > 0 && cur > stock) qtyNum.textContent = stock;
  }
  // Store for changeQty
  window._pdpCurrentStock = stock;

  // [v2.9.18] Removida a sincronização do scarcity-bar-wrap legado —
  // o elemento HTML correspondente foi removido; #pdpStockWidget
  // (abaixo) é agora a única fonte de verdade para a mensagem de estoque.

  if (level === 'out') {
    el.className = 'pdp-stock-widget level-out';
    el.innerHTML = `
      <div class="pdp-stock-top">
        <div class="pdp-stock-dot"></div>
        <div class="pdp-stock-label">Produto esgotado</div>
      </div>
      <div class="pdp-stock-out-cta">
        <div class="pdp-stock-copy">Este produto está <strong>temporariamente fora de estoque</strong>. Ative o alerta e seja o primeiro a saber quando voltar.</div>
        <button class="pdp-stock-notify-btn" id="stkNotifyBtn" onclick="toggleStockNotify(this, ${productIdx})">
          <svg viewBox="0 0 24 24" width="15" height="15" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 01-3.46 0"/></svg>
          Me Avisar Quando Chegar
        </button>
      </div>`;
    return;
  }

  var barPct = stockMax > 0 ? Math.max(4, Math.round((stock / stockMax) * 100)) : 50;

  el.className = 'pdp-stock-widget level-' + level;
  el.innerHTML = `
    <div class="pdp-stock-top">
      <div class="pdp-stock-dot"></div>
      <div class="pdp-stock-label">${cfg.label}</div>
      ${level !== 'normal' ? `<div class="pdp-stock-count">${stock} un.</div>` : ''}
    </div>
    ${cfg.showBar ? `
    <div class="pdp-stock-bar-wrap">
      <div class="pdp-stock-bar">
        <div class="pdp-stock-fill" style="width:${barPct}%;"></div>
      </div>
      <div class="pdp-stock-bar-labels">
        <span>${stock} restantes</span>
        <span>${stockMax - stock} vendidos</span>
      </div>
    </div>` : ''}
    <div class="pdp-stock-copy">${cfg.copy}</div>`;

  // Fire toast for critical/low (once per product per session)
  if (cfg.showToast) {
    var toastKey = 'stk_shown_' + productIdx;
    if (!window[toastKey]) {
      window[toastKey] = true;
      setTimeout(() => showStockToast(level, cfg, productIdx), 900);
    }
  }

  // ── Social Proof Ticker ────────────────────────────────────────────────────
  _startSocialTicker(productIdx, level, stock, seedViewers, seedSold);
}

// ── SOCIAL PROOF TICKER ENGINE ────────────────────────────────────────────────
var _socialTickerTimer = null;
var _socialTickerIdx   = 0;

function _startSocialTicker(productIdx, level, stock, viewers, sold) {
  var tickerEl  = document.getElementById('pdpSocialTicker');
  var msgEl     = document.getElementById('pdpSocialTickerMsg');
  var dotEl     = document.getElementById('pdpSocialTickerDot');
  if (!tickerEl || !msgEl) return;

  // Only show ticker when stock is not normal (moderate/low/critical/out)
  if (level === 'normal') { tickerEl.style.display = 'none'; return; }

  // Build message pool based on product seed
  var p = products[productIdx];
  var name = p ? p.n.split(' ')[0] : 'produto';
  var msgs = [];

  if (level !== 'out') {
    msgs.push({ text: viewers + ' pessoas estão vendo este produto agora', color: '#FF6B35' });
    msgs.push({ text: sold + ' unidades vendidas nas últimas 2 horas', color: '#FF6B35' });
    if (level === 'critical') {
      msgs.push({ text: '🔥 Múltiplos compradores adicionaram ao carrinho agora', color: '#EF4444' });
      msgs.push({ text: '⚠️ Com ' + stock + ' unidades restantes, pode esgotar a qualquer momento', color: '#EF4444' });
    }
    if (level === 'low' || level === 'critical') {
      msgs.push({ text: '🛒 Última compra há ' + (2 + (productIdx % 8)) + ' minutos', color: '#FF6B35' });
    }
    msgs.push({ text: '📦 ' + (sold + 3) + ' unidades foram vendidas só hoje', color: '#F59E0B' });
  } else {
    msgs.push({ text: 'Este produto é muito procurado — ative o alerta de reposição', color: '#94A3B8' });
  }

  // Stop previous ticker
  if (_socialTickerTimer) clearInterval(_socialTickerTimer);
  _socialTickerIdx = 0;

  function _showMsg(i) {
    var m = msgs[i % msgs.length];
    tickerEl.style.opacity = '0';
    setTimeout(function() {
      msgEl.textContent = m.text;
      tickerEl.style.borderColor = m.color.replace(')', ',0.25)').replace('rgb','rgba').replace('#', 'rgba(').replace('rgba(','rgba(') || 'rgba(255,107,53,0.2)';
      tickerEl.style.background  = m.color.replace(')', ',0.06)').replace('#','rgba(').replace('rgba(','rgba(');
      msgEl.style.color = m.color;
      if (dotEl) dotEl.style.background = m.color;
      tickerEl.style.opacity = '1';
    }, 200);
  }

  tickerEl.style.display = 'flex';
  _showMsg(0);
  _socialTickerTimer = setInterval(function() {
    _socialTickerIdx++;
    _showMsg(_socialTickerIdx);
  }, 5000);
}

// ── STOCK TOAST ──
var _stkToastTimer   = null;
var _stkProgressTimer = null;
var _stkDuration     = 5000;

function showStockToast(level, cfg, productIdx) {
  var el = document.getElementById('stockToast');
  if (!el) return;

  var colors = {
    critical: { accent: '#EF4444', iconBg: 'rgba(239,68,68,0.12)' },
    low:      { accent: '#FF6B35', iconBg: 'rgba(255,107,53,0.1)'  },
  };
  var c = colors[level] || colors.low;

  // Fill elements
  document.getElementById('stkAccent').style.background   = c.accent;
  document.getElementById('stkIcon').style.background     = c.iconBg;
  document.getElementById('stkIcon').textContent          = cfg.icon;
  document.getElementById('stkTitle').textContent         = cfg.toastTitle;
  document.getElementById('stkSub').textContent           = cfg.toastSub;
  var prog = document.getElementById('stkProgress');

  el.style.display = 'block';
  el.classList.remove('out');

  // Progress bar drain
  if (_stkProgressTimer) clearInterval(_stkProgressTimer);
  if (prog) {
    prog.style.background = c.accent;
    prog.style.width = '100%';
    prog.style.transition = 'none';
    setTimeout(() => {
      prog.style.transition = `width ${_stkDuration}ms linear`;
      prog.style.width = '0%';
    }, 30);
  }

  if (_stkToastTimer) clearTimeout(_stkToastTimer);
  _stkToastTimer = setTimeout(hideStockToast, _stkDuration);
}

function hideStockToast() {
  var el = document.getElementById('stockToast');
  if (!el) return;
  el.classList.add('out');
  setTimeout(() => { el.style.display = 'none'; el.classList.remove('out'); }, 260);
  if (_stkToastTimer) clearTimeout(_stkToastTimer);
}

function toggleStockNotify(btn, productIdx) {
  var active = btn.classList.toggle('active');
  btn.innerHTML = active
    ? `<svg viewBox="0 0 24 24" width="15" height="15" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg> Alerta Ativado! Você será avisado`
    : `<svg viewBox="0 0 24 24" width="15" height="15" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 01-3.46 0"/></svg> Me Avisar Quando Chegar`;
  showToast(active ? '🔔 Alerta de reposição ativado!' : '🔕 Alerta cancelado');
}


// ══════════════════════════════════════════════════════
//  PRICE HISTORY ENGINE v1 — WeKz PDP
// ══════════════════════════════════════════════════════

// Gera uma série de preços historicamente plausível
// baseada no preço atual e no preço original
function _phGenerateSeries(currentPrice, originalPrice, days) {
  var points = [];
  var now    = Date.now();
  var msDay  = 86400000;

  // Pontos âncora: começa perto do preço original, desce até o atual
  // com ruído realista, promoções em picos e quedas bruscas (flash sale)
  var seed = currentPrice * 13.7; // determinístico por produto
  function seededRand(i) {
    var x = Math.sin(seed + i * 127.1) * 43758.5453;
    return x - Math.floor(x);
  }

  // Preço base varia ao longo do tempo
  var range  = originalPrice - currentPrice;
  var step   = days <= 30 ? 1 : days <= 90 ? 3 : days <= 180 ? 6 : 14;
  var nPts   = Math.floor(days / step);

  for (var i = 0; i < nPts; i++) {
    var t    = i / (nPts - 1);                       // 0 → 1
    // Tendência descendente com curva
    var trend = originalPrice - range * Math.pow(t, 0.6);
    // Ruído (±4%)
    var noise  = (seededRand(i) - 0.5) * 0.08 * trend;
    // Evento de promoção: queda brusca em pontos aleatórios
    var promo  = (seededRand(i + 300) < 0.08) ? -trend * 0.12 : 0;
    var price  = Math.max(currentPrice * 0.92, trend + noise + promo);
    // Arredondar para .90 ou .00 (realismo de e-commerce)
    price = Math.round(price / 10) * 10 - 0.10;
    if (price < 10) price = Math.round(price * 100) / 100;

    var ts = now - (nPts - 1 - i) * step * msDay;
    points.push({ ts: ts, price: price });
  }

  // Garantir que o último ponto é o preço atual exato
  if (points.length > 0) points[points.length - 1].price = currentPrice;
  return points;
}

var _phSeries  = [];
var _phPeriod  = 30;
var _phProduct = null;
var _phRAF     = null;

function initPriceHistory(productIdx) {
  _phProduct = products[productIdx];
  if (!_phProduct) return;
  _phPeriod = 30;
  document.querySelectorAll('.ph-period').forEach((b,i) => b.classList.toggle('active', i===0));
  _phRender();
}

function phSetPeriod(days, el) {
  _phPeriod = days;
  document.querySelectorAll('.ph-period').forEach(b => b.classList.remove('active'));
  el.classList.add('active');
  _phRender();
}

function _phFmt(v) {
  return 'R$ ' + v.toLocaleString('pt-BR', {minimumFractionDigits:2, maximumFractionDigits:2});
}

function _phFmtDate(ts, period) {
  var d = new Date(ts);
  if (period <= 30)  return d.toLocaleDateString('pt-BR',{day:'2-digit',month:'short'});
  if (period <= 90)  return d.toLocaleDateString('pt-BR',{day:'2-digit',month:'short'});
  return d.toLocaleDateString('pt-BR',{month:'short',year:'2-digit'});
}

function _phRender() {
  if (!_phProduct) return;
  var p   = _phProduct;
  var series = _phGenerateSeries(p.p, p.op, _phPeriod);
  _phSeries = series;

  var prices  = series.map(s => s.price);
  var minP    = Math.min(...prices);
  var maxP    = Math.max(...prices);
  var avgP    = prices.reduce((a,b) => a+b, 0) / prices.length;
  var curP    = p.p;

  // KPIs
  var kpis = document.getElementById('phKpis');
  if (kpis) kpis.innerHTML = `
    <div class="ph-kpi"><div class="ph-kpi-label">Atual</div><div class="ph-kpi-value current">${_phFmt(curP)}</div></div>
    <div class="ph-kpi"><div class="ph-kpi-label">Mínimo</div><div class="ph-kpi-value low">${_phFmt(minP)}</div><div class="ph-kpi-sub">nos últimos ${_phPeriod}d</div></div>
    <div class="ph-kpi"><div class="ph-kpi-label">Máximo</div><div class="ph-kpi-value high">${_phFmt(maxP)}</div></div>
    <div class="ph-kpi"><div class="ph-kpi-label">Média</div><div class="ph-kpi-value avg">${_phFmt(avgP)}</div></div>`;

  // AI insight
  var diffFromMin = ((curP - minP) / minP * 100).toFixed(1);
  var diffFromAvg = ((curP - avgP) / avgP * 100).toFixed(1);
  var isGoodDeal  = curP <= avgP * 1.02;
  var isAtMin     = curP <= minP * 1.03;

  var deal = document.getElementById('phDealBadge');
  if (deal) {
    if (isAtMin) {
      deal.innerHTML = `<div class="ph-deal-badge">
        <svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
        Menor preço dos últimos ${_phPeriod} dias — ótima hora para comprar!
      </div>`;
    } else if (isGoodDeal) {
      deal.innerHTML = `<div class="ph-deal-badge">
        <svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
        Preço abaixo da média — bom momento para comprar
      </div>`;
    } else {
      deal.innerHTML = `<div class="ph-deal-badge not-deal">
        ⚡ Preço +${diffFromMin}% acima do mínimo histórico
      </div>`;
    }
  }

  var aiEl = document.getElementById('phAiText');
  if (aiEl) {
    if (isAtMin) {
      aiEl.innerHTML = `<strong>Kz AI:</strong> Este produto está no menor preço registrado nos últimos ${_phPeriod} dias. A média foi ${_phFmt(avgP)} e o preço caiu <strong style="color:#4ade80;">${Math.abs(diffFromAvg)}%</strong> abaixo dela. Historicamente, preços nesse nível duram menos de 72h.`;
    } else if (isGoodDeal) {
      aiEl.innerHTML = `<strong>Kz AI:</strong> Preço ${Math.abs(diffFromAvg)}% abaixo da média dos últimos ${_phPeriod} dias (${_phFmt(avgP)}). O mínimo histórico foi ${_phFmt(minP)}. Tendência de queda — preço pode baixar mais.`;
    } else {
      aiEl.innerHTML = `<strong>Kz AI:</strong> Preço atual ${diffFromAvg > 0 ? '+' : ''}${diffFromAvg}% em relação à média (${_phFmt(avgP)}). Mínimo histórico: ${_phFmt(minP)}. Ative o alerta de preço para ser notificado quando chegar ao mínimo.`;
    }
  }

  // Canvas draw
  _phDrawCanvas(series, minP, maxP, curP);
}

function _phDrawCanvas(series, minP, maxP, curP) {
  var canvas = document.getElementById('phCanvas');
  if (!canvas) return;
  var wrap   = document.getElementById('phCanvasWrap');
  var dpr    = window.devicePixelRatio || 1;

  canvas.width  = wrap.clientWidth  * dpr;
  canvas.height = wrap.clientHeight * dpr;
  canvas.style.width  = wrap.clientWidth  + 'px';
  canvas.style.height = wrap.clientHeight + 'px';

  var ctx    = canvas.getContext('2d');
  ctx.scale(dpr, dpr);

  var W   = wrap.clientWidth;
  var H   = wrap.clientHeight;
  var PAD = { top:14, right:16, bottom:30, left:62 };
  var cW  = W - PAD.left - PAD.right;
  var cH  = H - PAD.top  - PAD.bottom;
  var n   = series.length;
  if (n < 2) return;

  // Padding price range
  var pRange  = maxP - minP || 1;
  var pPad    = pRange * 0.15;
  var pMin    = minP - pPad;
  var pMax    = maxP + pPad;

  var xOf = i  => PAD.left + (i / (n-1)) * cW;
  var yOf = pv => PAD.top  + (1 - (pv - pMin) / (pMax - pMin)) * cH;

  ctx.clearRect(0, 0, W, H);

  // ── Grid lines ──
  ctx.strokeStyle = 'rgba(255,255,255,0.05)';
  ctx.lineWidth   = 1;
  for (var gi = 0; gi <= 4; gi++) {
    var gy = PAD.top + (gi / 4) * cH;
    ctx.beginPath(); ctx.moveTo(PAD.left, gy); ctx.lineTo(PAD.left + cW, gy); ctx.stroke();
  }

  // ── Y-axis labels ──
  ctx.fillStyle  = 'rgba(148,163,184,0.7)';
  ctx.font       = `${10 * dpr / dpr}px DM Sans, sans-serif`;
  ctx.textAlign  = 'right';
  for (var li = 0; li <= 3; li++) {
    var lv   = pMin + (li / 3) * (pMax - pMin);
    var ly   = PAD.top + (1 - li/3) * cH;
    ctx.fillText('R$' + Math.round(lv).toLocaleString('pt-BR'), PAD.left - 6, ly + 3.5);
  }

  // ── X-axis labels ──
  ctx.textAlign = 'center';
  var labelStep = Math.max(1, Math.floor(n / 5));
  for (var xi = 0; xi < n; xi += labelStep) {
    ctx.fillText(_phFmtDate(series[xi].ts, _phPeriod), xOf(xi), H - 4);
  }

  // ── Gradient fill under line ──
  var grad = ctx.createLinearGradient(0, PAD.top, 0, PAD.top + cH);
  grad.addColorStop(0,   'rgba(0,180,171,0.25)');
  grad.addColorStop(0.6, 'rgba(0,180,171,0.05)');
  grad.addColorStop(1,   'rgba(0,180,171,0)');
  ctx.beginPath();
  ctx.moveTo(xOf(0), yOf(series[0].price));
  for (var i = 1; i < n; i++) {
    // Smooth curve
    var x0 = xOf(i-1), y0 = yOf(series[i-1].price);
    var x1 = xOf(i),   y1 = yOf(series[i].price);
    var cpx = (x0+x1)/2;
    ctx.bezierCurveTo(cpx,y0, cpx,y1, x1,y1);
  }
  ctx.lineTo(xOf(n-1), PAD.top + cH);
  ctx.lineTo(xOf(0),   PAD.top + cH);
  ctx.closePath();
  ctx.fillStyle = grad;
  ctx.fill();

  // ── Line ──
  ctx.beginPath();
  ctx.moveTo(xOf(0), yOf(series[0].price));
  for (var i = 1; i < n; i++) {
    var x0 = xOf(i-1), y0 = yOf(series[i-1].price);
    var x1 = xOf(i),   y1 = yOf(series[i].price);
    var cpx = (x0+x1)/2;
    ctx.bezierCurveTo(cpx,y0, cpx,y1, x1,y1);
  }
  ctx.strokeStyle = '#00B4AB';
  ctx.lineWidth   = 2.5;
  ctx.lineJoin    = 'round';
  ctx.stroke();

  // ── Min marker ──
  var minIdx = series.reduce((a, s, i) => s.price < series[a].price ? i : a, 0);
  ctx.beginPath();
  ctx.arc(xOf(minIdx), yOf(series[minIdx].price), 5, 0, Math.PI*2);
  ctx.fillStyle   = '#22C55E';
  ctx.strokeStyle = '#fff';
  ctx.lineWidth   = 1.5;
  ctx.fill(); ctx.stroke();

  // ── Current price dot ──
  ctx.beginPath();
  ctx.arc(xOf(n-1), yOf(curP), 6, 0, Math.PI*2);
  ctx.fillStyle   = '#00B4AB';
  ctx.strokeStyle = '#fff';
  ctx.lineWidth   = 2;
  ctx.fill(); ctx.stroke();

  // ── Horizontal dashed line at current price ──
  ctx.beginPath();
  ctx.setLineDash([4, 4]);
  ctx.moveTo(PAD.left, yOf(curP));
  ctx.lineTo(PAD.left + cW, yOf(curP));
  ctx.strokeStyle = 'rgba(0,180,171,0.3)';
  ctx.lineWidth   = 1;
  ctx.stroke();
  ctx.setLineDash([]);

  // Store xOf/yOf for tooltip
  canvas._phXOf  = xOf;
  canvas._phYOf  = yOf;
  canvas._phPAD  = PAD;
  canvas._phN    = n;
}

// ── Tooltip on mousemove / touchmove ──
(function() {
  function attachPHTooltip() {
    var canvas = document.getElementById('phCanvas');
    if (!canvas) return;

    function findNearest(clientX) {
      var rect = canvas.getBoundingClientRect();
      var dpr  = window.devicePixelRatio || 1;
      var mx   = clientX - rect.left;
      if (!canvas._phXOf) return -1;
      var best = -1, bDist = Infinity;
      for (var i = 0; i < (_phSeries.length || 0); i++) {
        var d = Math.abs(canvas._phXOf(i) - mx);
        if (d < bDist) { bDist = d; best = i; }
      }
      return best;
    }

    function showTip(idx, clientX) {
      if (idx < 0 || !_phSeries[idx]) return;
      var tip   = document.getElementById('phTooltip');
      var wrap  = document.getElementById('phCanvasWrap');
      if (!tip || !wrap) return;
      var rect  = wrap.getBoundingClientRect();
      var xPx   = canvas._phXOf(idx);
      var s     = _phSeries[idx];
      document.getElementById('phTipPrice').textContent = _phFmt(s.price);
      document.getElementById('phTipDate').textContent  = new Date(s.ts).toLocaleDateString('pt-BR',{day:'2-digit',month:'short',year:'numeric'});
      // Position tooltip
      var tipW  = 130;
      var left  = xPx - tipW/2;
      var top   = (canvas._phYOf(s.price) || 20) - 64;
      tip.style.left = Math.max(0, Math.min(left, rect.width - tipW)) + 'px';
      tip.style.top  = Math.max(0, top) + 'px';
      tip.classList.add('visible');
    }

    canvas.addEventListener('mousemove', function(e) { showTip(findNearest(e.clientX), e.clientX); });
    canvas.addEventListener('mouseleave', function()  { var t = document.getElementById('phTooltip'); if(t) t.classList.remove('visible'); });
    canvas.addEventListener('touchmove',  function(e) { if(e.touches[0]) showTip(findNearest(e.touches[0].clientX), e.touches[0].clientX); }, {passive:true});
    canvas.addEventListener('touchend',   function()  { var t = document.getElementById('phTooltip'); if(t) t.classList.remove('visible'); });
  }

  // Attach after DOM ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', attachPHTooltip);
  } else {
    attachPHTooltip();
  }
})();


// ══════════════════════════════════════════════════════
//  REWARDS ENGINE v1 — WeKz Pontos & Cashback
// ══════════════════════════════════════════════════════

const WKZ_REWARDS = {
  earnRate:    1,      // 1 ponto por R$ 1 gasto
  redeemRate:  0.05,   // R$ 0,05 por ponto resgatado
  maxRedeemPct:0.20,   // máx 20% do total pode vir de pontos
  levels: [
    { name:'Bronze',     emoji:'🥉', icon:'award',   min:0,     max:499,      color:'#CD7F32', bg:'rgba(205,127,50,0.15)',  perks:'1pt/R$1 · Frete grátis acima R$150' },
    { name:'Silver',     emoji:'🥈', icon:'award',   min:500,   max:1999,     color:'#94A3B8', bg:'rgba(148,163,184,0.15)', perks:'1.2pt/R$1 · Frete grátis · 5% extra' },
    { name:'Gold',       emoji:'🥇', icon:'award',   min:2000,  max:4999,     color:'#F59E0B', bg:'rgba(245,158,11,0.12)',  perks:'1.5pt/R$1 · Frete grátis · 10% extra' },
    { name:'Cyber',      emoji:'⚡', icon:'cyclone', min:5000,  max:9999,     color:'#00B4AB', bg:'rgba(0,180,171,0.12)',   perks:'2pt/R$1 · Frete express · 15% extra' },
    { name:'Neon Cyber', emoji:'💎', icon:'zap',     min:10000, max:Infinity, color:'#A78BFA', bg:'rgba(167,139,250,0.15)', perks:'3pt/R$1 · Frete express · 20% extra + acesso VIP' },
  ],
  /* [v3.0] Categoria em destaque com taxa de pontos reforçada — alimenta o
     CTA do Guia de Níveis Kz. Pode futuramente vir do backend/admin. */
  bonusCategory: { name:'Eletrônicos', rate:'2x', note:'Esta semana, Eletrônicos rende pontos em dobro em qualquer nível.' },
};

// Estado do usuário (mock — em produção viria do Supabase)
let userPoints = {
  balance:   1240,
  lifetime:  8340,
  redeemNow: 0,    // pontos sendo usados no pedido atual
};

function _wkzLevel(pts) {
  return WKZ_REWARDS.levels.slice().reverse().find(l => pts >= l.min) || WKZ_REWARDS.levels[0];
}

function _wkzNextLevel(pts) {
  return WKZ_REWARDS.levels.find(l => l.min > pts) || null;
}

function _wkzEarnPts(totalBRL) {
  var level    = _wkzLevel(userPoints.balance);
  var rate     = level.name === 'Silver'    ? 1.2
               : level.name === 'Gold'      ? 1.5
               : level.name === 'Cyber'     ? 2
               : level.name === 'Neon Cyber'? 3 : 1;
  return Math.floor(totalBRL * rate);
}

function _wkzFmtPts(n) {
  return n.toLocaleString('pt-BR') + ' pts';
}

// ── PDP badge ──
function renderPdpPointsBadge(productIdx) {
  var el = document.getElementById('pdpPtsBadge');
  if (!el) return;
  var p = products[productIdx];
  if (!p) { el.innerHTML=''; return; }
  var pts      = _wkzEarnPts(p.p);
  var cashback = (pts * WKZ_REWARDS.redeemRate).toFixed(2).replace('.', ',');
  var level    = _wkzLevel(userPoints.balance);
  el.innerHTML = `
    <div class="pdp-pts-badge">
      <div class="pdp-pts-badge-icon">⭐</div>
      <div class="pdp-pts-badge-text">
        Ganhe <strong>+${pts.toLocaleString('pt-BR')} pontos</strong> nesta compra<br>
        <span style="font-size:10px;color:var(--muted);">Nível ${level.emoji||''} ${level.name} · taxa ${level.name==='Silver'?'1.2x':level.name==='Gold'?'1.5x':level.name==='Cyber'?'2x':level.name==='Neon Cyber'?'3x':'1x'}</span>
      </div>
      <div class="pdp-pts-cashback">= R$ ${cashback}</div>
    </div>`;
}

// ── Cart: pontos a ganhar + resgate ──
function renderCartPoints(subtotal) {
  var earnEl   = document.getElementById('cartPtsEarn');
  var redeemEl = document.getElementById('cartPtsRedeem');
  if (!earnEl || !redeemEl) return;

  var pts      = _wkzEarnPts(subtotal);
  var cashback = (pts * WKZ_REWARDS.redeemRate).toFixed(2).replace('.', ',');

  earnEl.innerHTML = `
    <div class="cart-pts-earn-icon">⭐</div>
    <div class="cart-pts-earn-text">
      Você vai ganhar <strong>+${pts.toLocaleString('pt-BR')} pontos</strong> nesta compra
      <br><span style="color:var(--muted);font-size:10px;">= R$ ${cashback} em cashback futuro · Saldo atual: ${_wkzFmtPts(userPoints.balance)}</span>
    </div>`;

  // Redeem slider
  var maxRedeem     = Math.min(userPoints.balance, Math.floor(subtotal * WKZ_REWARDS.maxRedeemPct / WKZ_REWARDS.redeemRate));
  var redeemDisc    = (userPoints.redeemNow * WKZ_REWARDS.redeemRate).toFixed(2).replace('.', ',');
  var isOn          = userPoints.redeemNow > 0;

  redeemEl.innerHTML = `
    <div class="cart-pts-redeem-header" onclick="togglePtsRedeem()">
      <div class="cart-pts-redeem-title">
        <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="#A78BFA" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
        Usar Pontos como Desconto
      </div>
      <div class="cart-pts-redeem-bal">${_wkzFmtPts(userPoints.balance)} disponíveis</div>
      <div class="cart-pts-toggle${isOn?' on':''}" id="ptsToggle"></div>
    </div>
    <div class="cart-pts-redeem-body${isOn?' open':''}" id="ptsRedeemBody">
      <div class="cart-pts-slider-wrap">
        <input type="range" class="cart-pts-slider" id="ptsSlider"
          min="0" max="${maxRedeem}" value="${userPoints.redeemNow}" step="10"
          oninput="updatePtsRedeem(this.value)">
        <div class="cart-pts-slider-labels">
          <span>0 pts</span>
          <span>${maxRedeem.toLocaleString('pt-BR')} pts (máx 20%)</span>
        </div>
        <div class="cart-pts-discount-row">
          <span style="font-size:12px;color:var(--muted);">Desconto aplicado:</span>
          <span class="cart-pts-discount-val" id="ptsDiscountVal">-R$ ${redeemDisc}</span>
        </div>
      </div>
    </div>`;
}

function togglePtsRedeem() {
  var body   = document.getElementById('ptsRedeemBody');
  var toggle = document.getElementById('ptsToggle');
  if (!body) return;
  var isOpen = body.classList.toggle('open');
  if (toggle) toggle.classList.toggle('on', isOpen);
  if (!isOpen) {
    userPoints.redeemNow = 0;
    var slider = document.getElementById('ptsSlider');
    if (slider) slider.value = 0;
    var discVal = document.getElementById('ptsDiscountVal');
    if (discVal) discVal.textContent = '-R$ 0,00';
    updateCartUI();
  }
}

function updatePtsRedeem(val) {
  userPoints.redeemNow = parseInt(val) || 0;
  var disc = (userPoints.redeemNow * WKZ_REWARDS.redeemRate).toFixed(2).replace('.', ',');
  var el = document.getElementById('ptsDiscountVal');
  if (el) el.textContent = '-R$ ' + disc;
  updateCartUI();
}

// ── Loyalty level bar in cart ──
function renderCartLoyaltyBar() {
  var el = document.getElementById('cartLoyaltyBar');
  if (!el) return;
  var level    = _wkzLevel(userPoints.balance);
  var next     = _wkzNextLevel(userPoints.balance);
  var pct      = next
    ? Math.round(((userPoints.balance - level.min) / (next.min - level.min)) * 100)
    : 100;
  var ptsToNext = next ? (next.min - userPoints.balance).toLocaleString('pt-BR') : null;

  el.innerHTML = `
    <div class="clb-header">
      <div class="clb-avatar" style="background:${level.bg};">${level.emoji}</div>
      <div>
        <div class="clb-name">João da Silva</div>
        <div style="font-size:11px;color:var(--muted);">${_wkzFmtPts(userPoints.balance)} · ${level.perks.split('·')[0].trim()}</div>
      </div>
      <div class="clb-level-badge" style="background:${level.bg};color:${level.color};border:1px solid ${level.color}33;">${level.emoji} ${level.name}</div>
    </div>
    <div class="clb-progress-wrap">
      <div class="clb-progress-bar">
        <div class="clb-progress-fill" style="width:${pct}%;background:${level.color};"></div>
      </div>
      <div class="clb-progress-labels">
        <span>${level.emoji} ${level.name}</span>
        ${next ? `<span style="color:var(--text);">${ptsToNext} pts para ${next.emoji} ${next.name}</span>` : '<span style="color:#A78BFA;">⚡ Nível máximo!</span>'}
      </div>
    </div>`;
}

// ── Checkout: pontos ganhos na confirmação ──
function renderCheckoutPtsEarned(totalBRL) {
  var el = document.getElementById('ckoutPtsEarned');
  if (!el) return;
  var pts      = _wkzEarnPts(totalBRL);
  var newBal   = userPoints.balance - userPoints.redeemNow + pts;
  var level    = _wkzLevel(newBal);
  el.innerHTML = `
    <div class="ckout-pts-earned">
      <div class="ckout-pts-icon">⭐</div>
      <div class="ckout-pts-text">
        <div class="ckout-pts-title">+${pts.toLocaleString('pt-BR')} pontos ganhos!</div>
        <div class="ckout-pts-sub">Novo saldo: ${newBal.toLocaleString('pt-BR')} pts · Nível ${level.emoji} ${level.name}</div>
      </div>
    </div>`;
  // Update balance for the session
  userPoints.balance = newBal;
  userPoints.redeemNow = 0;
}

// Patch updateCartUI to include points
var _origUpdateCartUI = null;
function _patchCartForPoints() {
  if (typeof updateCartUI !== 'function') return;
  if (_origUpdateCartUI) return; // already patched
  _origUpdateCartUI = updateCartUI;
  updateCartUI = function() {
    _origUpdateCartUI.apply(this, arguments);
    // Recalculate subtotal after original update
    setTimeout(function() {
      var subEl = document.getElementById('cartSubtotal');
      if (!subEl) return;
      var raw = subEl.textContent.replace(/[^\d,]/g,'').replace(',','.');
      var sub = parseFloat(raw) || 0;
      // Apply points discount
      if (userPoints.redeemNow > 0) {
        var disc    = userPoints.redeemNow * WKZ_REWARDS.redeemRate;
        var totalEl = document.getElementById('cartTotal');
        if (totalEl) {
          var rawTotal = totalEl.textContent.replace(/[^\d,]/g,'').replace(',','.');
          var total    = parseFloat(rawTotal) || 0;
          // Show pts discount row
          var ptsRow = document.getElementById('cartPtsDiscountRow');
          if (ptsRow) {
            ptsRow.style.display = 'flex';
            ptsRow.querySelector('span:last-child').textContent = '-R$ ' + disc.toFixed(2).replace('.',',');
            totalEl.textContent = 'R$ ' + Math.max(0, total - disc).toFixed(2).replace('.',',');
          }
        }
      } else {
        var ptsRow = document.getElementById('cartPtsDiscountRow');
        if (ptsRow) ptsRow.style.display = 'none';
      }
      renderCartPoints(sub);
      renderCartLoyaltyBar();
    }, 20);
  };
}


