// ── Filtro de linhas do comparador ──
let _kzcShowOnlyDiff = false;

function kzcToggleOnlyDiff(el) {
  _kzcShowOnlyDiff = el.checked;
  // Re-render se drawer aberto
  var drawer = document.getElementById('kzcDrawer');
  if (drawer && drawer.classList.contains('open')) {
    var container = document.getElementById('kzcDrawerContent');
    if (container) kzcRenderDrawerV2(container);
  }
}

// ── Compartilhar comparação ──
function kzcShare() {
  var list = window._kzcGetList ? window._kzcGetList() : [];
  if (!list.length) return;
  var names = list.map(function(idx) {
    return products[idx] ? products[idx].n.split('—')[0].trim() : '';
  }).filter(Boolean).join(' vs ');
  var text = '🔍 Comparando na WeKz Shop: ' + names + ' — confira o melhor custo-benefício!';
  if (navigator.clipboard) {
    navigator.clipboard.writeText(text);
    showToast('📋 Resumo da comparação copiado!');
  } else {
    showToast('🔗 ' + names);
  }
}

// ── Render enriquecido do drawer ──
function kzcRenderDrawerV2(container) {
  var list = window._kzcGetList ? window._kzcGetList() : [];
  var prods = list.map(function(idx) {
    return { idx: idx, p: (typeof products !== 'undefined' && products[idx]) ? products[idx] : null };
  }).filter(function(x) { return x.p; });

  if (!prods.length) return;

  // Score calculation (mesmo algoritmo do engine original)
  var scores = prods.map(function(x) {
    var p = x.p;
    var priceScore  = 1 / (p.p || 1);
    var discScore   = (p.off || 0) / 100;
    var ratingScore = (p.r || 0) / 5;
    var salesScore  = Math.log1p(parseInt(String(p.sales||'0').replace(/[^\d]/g,''), 10)) / 15;
    var score = priceScore*0.35 + discScore*0.25 + ratingScore*0.25 + salesScore*0.15;
    return { idx: x.idx, score: score };
  });
  var maxScore = Math.max.apply(null, scores.map(function(s){return s.score;}));
  var bestIdx  = scores.reduce(function(a,b){return b.score>a.score?b:a;}).idx;

  function _fmtP(v) { return 'R$ '+Number(v).toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g,'.'); }
  function _stars(r) { var f=Math.round(Number(r)); return '★'.repeat(Math.max(0,Math.min(5,f))); }
  function _cls(val, arr, higher) {
    var sorted=[].concat(arr).sort(function(a,b){return higher?b-a:a-b;});
    if(val===sorted[0])return 'kzc-val-best';
    if(val===sorted[sorted.length-1]&&arr.length>1)return 'kzc-val-worst';
    return 'kzc-val-mid';
  }

  // Filter toolbar
  var filterBar = '<div class="kzc-filter-bar">' +
    '<label class="kzc-filter-chip' + (_kzcShowOnlyDiff?' active':'') + '">' +
    '<input type="checkbox"' + (_kzcShowOnlyDiff?' checked':'') + ' onchange="kzcToggleOnlyDiff(this)"> Só diferenças</label>' +
    '<button class="kzc-share-btn" onclick="kzcShare()">' +
    '<svg viewBox="0 0 24 24" width="12" height="12" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg>' +
    'Compartilhar</button></div>';

  // Header cards
  var headerCells = '<th></th>';
  prods.forEach(function(x) {
    var isBest = x.idx === bestIdx;
    var sc = scores.find(function(s){return s.idx===x.idx;});
    var scPct = maxScore > 0 ? Math.round((sc.score/maxScore)*100) : 50;
    headerCells += '<th><div class="kzc-prod-card" style="' + (isBest?'border-color:rgba(0,180,171,0.6);box-shadow:0 0 20px rgba(0,180,171,0.12);':'') + '">' +
      (isBest ? '<div style="position:absolute;top:-1px;left:50%;transform:translateX(-50%);background:linear-gradient(135deg,var(--teal),#7C3AED);color:#000;font-size:9px;font-weight:800;padding:2px 10px;border-radius:0 0 8px 8px;white-space:nowrap;">⭐ MELHOR ESCOLHA</div>' : '') +
      '<wkz-product-image class="kzc-prod-emoji" src="' + (x.p.img||'') + '" emoji="' + (x.p.e||'📦') + '" alt="' + x.p.n + '"></wkz-product-image>' +
      '<div class="kzc-prod-name">' + x.p.n + '</div>' +
      '<div class="kzc-prod-store">✅ ' + (x.p.s||'') + '</div>' +
      '<div class="kzc-prod-price">' + _fmtP(x.p.p) + '</div>' +
      '<div class="kzc-prod-off">-' + (x.p.off||0) + '% OFF</div>' +
      '<div class="kzc-score-bar-wrap" style="margin-top:8px;">' +
        '<div class="kzc-score-bar"><div class="kzc-score-fill" style="width:' + scPct + '%;background:' + (isBest?'var(--teal)':'rgba(148,163,184,0.5)') + ';"></div></div>' +
        '<div class="kzc-score-num" style="color:' + (isBest?'var(--teal)':'var(--muted)') + ';">' + scPct + '</div>' +
      '</div>' +
      '<button class="kzc-prod-remove" onclick="kzcRemove(' + x.idx + ')" title="Remover">✕</button>' +
      '</div></th>';
  });
  if (prods.length < 3) {
    headerCells += '<th><div class="kzc-add-slot" onclick="kzcCloseDrawer();showToast(\'🔍 Navegue e clique em Comparar para adicionar mais um produto.\')"><span class="kzc-add-slot-icon">＋</span>Adicionar produto</div></th>';
  }

  // Base rows
  var prices  = prods.map(function(x){return x.p.p||0;});
  var offs    = prods.map(function(x){return x.p.off||0;});
  var ratings = prods.map(function(x){return parseFloat(x.p.r)||0;});

  var baseRows = [
    { label:'Preço',   key:'price'  },
    { label:'Desconto',key:'off'    },
    { label:'Avaliação',key:'rating'},
    { label:'Vendas',  key:'sales'  },
    { label:'Loja',    key:'store'  },
    { label:'Frete',   key:'frete'  },
    { label:'⭐ Pontos',key:'pts'   },
    { label:'Estoque', key:'stock'  },
  ];

  var rowsHtml = '';
  baseRows.forEach(function(row) {
    var vals = [];
    var cells = '<td>' + row.label + '</td>';
    prods.forEach(function(x) {
      var p = x.p; var val='', cls='kzc-val-mid', raw=null;
      switch(row.key) {
        case 'price':  raw=p.p||0; val='<strong>'+_fmtP(p.p)+'</strong>'; cls=_cls(p.p,prices,false); break;
        case 'off':    raw=p.off||0; val='<span style="color:#FF6B35;font-weight:700;">-'+raw+'%</span>'; cls=_cls(raw,offs,true); break;
        case 'rating': raw=parseFloat(p.r)||0; val='<span class="kzc-stars">'+_stars(p.r)+'</span><br><span style="font-size:11px;">'+p.r+'</span>'; cls=_cls(raw,ratings,true); break;
        case 'sales':  val=p.sales||'—'; raw=parseInt(String(p.sales||'0').replace(/[^\d]/g,''),10); break;
        case 'store':  val='<span style="font-size:11px;">✅ '+(p.s||'—')+'</span>'; break;
        case 'frete':  val='<span style="color:#22C55E;font-weight:700;">🚚 Grátis</span>'; break;
        case 'pts':    var pts=Math.floor((p.p||0)); val='<span style="color:#A78BFA;font-weight:700;">+'+pts.toLocaleString('pt-BR')+' pts</span>'; break;
        case 'stock':  var st=p.stock; val = st===0?'<span style="color:var(--muted);">Esgotado</span>':st<=4?'<span style="color:#EF4444;font-weight:700;">'+st+' restantes</span>':st<=14?'<span style="color:#FF6B35;font-weight:700;">'+st+' un.</span>':'<span style="color:#4ade80;">'+st+' un.</span>'; break;
      }
      vals.push(raw);
      cells += '<td class="'+cls+'">'+val+'</td>';
    });
    if (prods.length < 3) cells += '<td></td>';
    // Filter: hide row if all same and "only diffs" active
    if (_kzcShowOnlyDiff && vals.filter(Boolean).length > 1) {
      var uniq = vals.filter(function(v){return v!==null&&v!==undefined;});
      if (uniq.length > 1 && uniq.every(function(v){return v===uniq[0];})) return;
    }
    rowsHtml += '<tr class="kzc-row">' + cells + '</tr>';
  });

  // Specs rows
  var allSpecKeys = {};
  prods.forEach(function(x) {
    var sp = KZC_SPECS[x.idx] || {};
    Object.keys(sp).forEach(function(k){allSpecKeys[k]=true;});
  });
  var specRowsHtml = '';
  Object.keys(allSpecKeys).forEach(function(specKey) {
    var cells = '<td class="kzc-spec-icon">'+specKey+'</td>';
    var vals  = [];
    prods.forEach(function(x) {
      var sp   = KZC_SPECS[x.idx] || {};
      var data = sp[specKey];
      if (data) {
        vals.push(data[0]);
        cells += '<td><span style="font-size:12px;font-weight:600;">'+data[0]+'</span><br><span style="font-size:10px;color:var(--muted);">'+data[1]+'</span></td>';
      } else {
        vals.push(null);
        cells += '<td style="color:var(--muted);">—</td>';
      }
    });
    if (prods.length < 3) cells += '<td></td>';
    if (_kzcShowOnlyDiff) {
      var nonNull = vals.filter(function(v){return v!==null;});
      if (nonNull.length > 1 && nonNull.every(function(v){return v===nonNull[0];})) return;
    }
    specRowsHtml += '<tr class="kzc-row specs">' + cells + '</tr>';
  });

  // CTA row
  var ctaCells = '<td></td>';
  prods.forEach(function(x) {
    ctaCells += '<td><button class="kzc-cart-btn" onclick="kzcCloseDrawer();addToCart('+x.idx+');showToast(\'🛒 '+x.p.e+' Adicionado!\')">🛒 Comprar</button></td>';
  });
  if (prods.length < 3) ctaCells += '<td></td>';

  // Winner banner
  var bestProd = products[bestIdx];
  var winnerBanner = bestProd ? '<div class="kzc-winner-banner"><span style="font-size:20px;">'+(bestProd.e||'🏆')+'</span><div><span class="kzc-winner-badge">🏆 MELHOR CUSTO-BENEFÍCIO</span><br><strong>'+bestProd.n+'</strong> — melhor equilíbrio entre preço, avaliações e popularidade.</div></div>' : '';

  container.innerHTML = filterBar + winnerBanner +
    '<div style="overflow-x:auto;"><table class="kzc-table"><thead><tr class="kzc-header-row">' + headerCells + '</tr></thead><tbody>' +
    rowsHtml +
    (specRowsHtml ? '<tr><td colspan="'+(prods.length+1+(prods.length<3?1:0))+'"><div class="kzc-section-label">📋 Especificações Técnicas</div></td></tr>' + specRowsHtml : '') +
    '<tr class="kzc-row kzc-row-cta">' + ctaCells + '</tr>' +
    '</tbody></table></div>';
}

// Expose getter for list (bridge to existing engine IIFE)
window._kzcGetList = window._kzcGetList || function() { return []; };


/* ── _wkzNavHooks: registro centralizado de hooks de navegação ────────────
   Substitui o padrão de múltiplos showPage wraps que criava loops de escopo.
   Cada módulo chama window.registerNavHook(fn) em vez de sobrescrever showPage.
   MapsTo itera o array de forma segura com try/catch por hook. ── */
/* FIX (achado via test-m3.html real): window._wkzNavHooks já existe
   (Proxy do WkzBus, congelado por wkzFreezeApp() após o boot) por volta
   da hora em que este código roda. O guard "window._wkzNavHooks || []"
   ainda EXECUTA a atribuição mesmo quando o valor não muda — e atribuir
   a uma propriedade congelada lança TypeError independente do valor.
   Corrigido para só atribuir se realmente não existir. */
(function bootstrapNavRegistry() {
  if (!window._wkzNavHooks) window._wkzNavHooks = [];
  if (!window.registerNavHook) {
    window.registerNavHook = function(fn) {
      if (typeof fn === 'function' && window._wkzNavHooks.indexOf(fn) === -1) {
        window._wkzNavHooks.push(fn);
      }
    };
  }
})();

