// State
let _qaCurrentPdp   = 0;
let _qaFilter       = 'all';
let _qaSearchQuery  = '';
let _qaVisible      = 5;
let _qaData         = [];

function initQA(productIdx) {
  _qaCurrentPdp  = productIdx;
  _qaFilter      = 'all';
  _qaSearchQuery = '';
  _qaVisible     = 5;
  _qaData        = QA_DATA[productIdx] || QA_DATA['default'];
  // Reset filters UI
  document.querySelectorAll('.qa-filter').forEach(function(b,i){b.classList.toggle('active',i===0);});
  var inp = document.getElementById('qaSectionSearch');
  if (inp) inp.value = '';
  renderQA();
}

function qaSetFilter(filter, el) {
  _qaFilter = filter;
  _qaVisible = 5;
  document.querySelectorAll('.qa-filter').forEach(function(b){b.classList.remove('active');});
  el.classList.add('active');
  renderQA();
}

function qaSearch(q) {
  _qaSearchQuery = q.trim().toLowerCase();
  _qaVisible = 5;
  renderQA();
}

function qaLoadMore() {
  _qaVisible += 5;
  renderQA();
}

// Sprint 0.1 fix A1: _highlight duplicado removido — manter definição em ~L27669

function renderQA() {
  var list = document.getElementById('qaList');
  var countEl = document.getElementById('qaCount');
  var loadBtn = document.getElementById('qaLoadMore');
  if (!list) return;

  // Filter
  var filtered = _qaData.filter(function(q) {
    if (_qaFilter === 'answered')   return q.answer;
    if (_qaFilter === 'unanswered') return !q.answer;
    if (_qaFilter === 'seller')     return q.answer && q.answer.isSeller;
    if (_qaFilter === 'top')        return q.votes >= 10;
    return true;
  });

  // Search
  if (_qaSearchQuery) {
    filtered = filtered.filter(function(q) {
      return q.text.toLowerCase().includes(_qaSearchQuery) ||
        (q.answer && q.answer.text.toLowerCase().includes(_qaSearchQuery));
    });
  }

  // Sort by votes desc
  filtered = filtered.slice().sort(function(a,b){return b.votes-a.votes;});

  if (countEl) countEl.textContent = _qaData.length + ' ' + (_qaData.length === 1 ? 'pergunta' : 'perguntas');

  if (!filtered.length) {
    list.innerHTML = '<div class="qa-empty"><div class="qa-empty-icon">🔍</div><div class="qa-empty-text">Nenhuma pergunta encontrada' +
      (_qaSearchQuery ? ' para <strong>"' + _qaSearchQuery + '"</strong>' : '') +
      '.<br>Seja o primeiro a perguntar!</div></div>';
    if (loadBtn) loadBtn.style.display = 'none';
    return;
  }

  var visible = filtered.slice(0, _qaVisible);
  list.innerHTML = visible.map(function(q) {
    var qText = _highlight(q.text, _qaSearchQuery);
    var upCls  = q.userVote ===  1 ? ' voted-up'   : '';
    var downCls= q.userVote === -1 ? ' voted-down' : '';

    var answerHtml = '';
    if (q.answer) {
      var aText = _highlight(q.answer.text, _qaSearchQuery);
      var icon  = q.answer.isSeller ? '🏪' : '👤';
      answerHtml = '<div class="qa-answer">' +
        '<div class="qa-a-row">' +
          '<div class="qa-a-icon">' + icon + '</div>' +
          '<div class="qa-a-body">' +
            '<div class="qa-a-text">' + aText + '</div>' +
            '<div class="qa-a-meta">' +
              (q.answer.isSeller ? '<span class="qa-seller-badge">🏪 Vendedor Oficial</span>' : '<span style="font-size:10px;">👤 ' + q.answer.by + '</span>') +
              '<span>' + q.answer.date + '</span>' +
            '</div>' +
            '<div class="qa-helpful-row">' +
              '<span style="font-size:11px;color:var(--muted);">Útil?</span>' +
              '<button class="qa-helpful-btn' + (q._helpfulClicked ? ' active' : '') + '" onclick="qaMarkHelpful(\'' + q.id + '\',this)">👍 Sim (' + q.helpfulCount + ')</button>' +
              '<button class="qa-helpful-btn" onclick="showToast(\'👎 Registrado\')">👎 Não</button>' +
            '</div>' +
          '</div>' +
        '</div>' +
      '</div>';
    } else {
      answerHtml = '<div class="qa-no-answer"><div class="qa-no-answer-dot"></div>Ainda sem resposta — vendedor normalmente responde em até 24h</div>';
    }

    return '<div class="qa-item' + (q.highlighted ? ' highlighted' : '') + '" id="qaItem_' + q.id + '">' +
      '<div class="qa-q-row">' +
        '<div class="qa-q-icon">P</div>' +
        '<div class="qa-q-body">' +
          '<div class="qa-q-text">' + qText + '</div>' +
          '<div class="qa-q-meta">' +
            '<span class="qa-q-user">👤 ' + q.user + '</span>' +
            '<span class="qa-q-date">' + q.date + '</span>' +
            (q.highlighted ? '<span class="qa-q-badge">🔥 Mais votada</span>' : '') +
          '</div>' +
        '</div>' +
        '<div class="qa-votes">' +
          '<button class="qa-vote-btn' + upCls + '" onclick="qaVote(\'' + q.id + '\',1)" title="Útil">▲</button>' +
          '<div class="qa-vote-count" id="qaVotes_' + q.id + '">' + q.votes + '</div>' +
          '<button class="qa-vote-btn' + downCls + '" onclick="qaVote(\'' + q.id + '\',-1)" title="Não útil">▼</button>' +
        '</div>' +
      '</div>' +
      answerHtml +
    '</div>';
  }).join('');

  if (loadBtn) loadBtn.style.display = filtered.length > _qaVisible ? 'block' : 'none';
  // FIX FUNC-01: sincronizar também o botão qaListLoadMore (secção pdp-interaction-card)
  var loadBtn2 = document.getElementById('qaListLoadMore');
  if (loadBtn2) loadBtn2.style.display = filtered.length > _qaVisible ? 'block' : 'none';
}

function qaVote(id, dir) {
  var q = _qaData.find(function(x){return x.id===id;});
  if (!q) return;
  if (q.userVote === dir) {
    // Undo vote
    q.votes -= dir;
    q.userVote = 0;
  } else {
    // Change or new vote
    q.votes -= q.userVote; // remove previous
    q.votes += dir;
    q.userVote = dir;
  }
  // Update count
  var el = document.getElementById('qaVotes_' + id);
  if (el) el.textContent = q.votes;
  // Update button states
  var item = document.getElementById('qaItem_' + id);
  if (item) {
    var upBtn   = item.querySelectorAll('.qa-vote-btn')[0];
    var downBtn = item.querySelectorAll('.qa-vote-btn')[1];
    if (upBtn)   upBtn.className   = 'qa-vote-btn' + (q.userVote === 1  ? ' voted-up'   : '');
    if (downBtn) downBtn.className = 'qa-vote-btn' + (q.userVote === -1 ? ' voted-down' : '');
  }
  if (q.userVote !== 0) showToast(dir === 1 ? '▲ Voto registrado — obrigado!' : '▼ Feedback registrado');
}

function qaMarkHelpful(id, btn) {
  var q = _qaData.find(function(x){return x.id===id;});
  if (!q || q._helpfulClicked) return;
  q._helpfulClicked = true;
  q.helpfulCount++;
  btn.classList.add('active');
  btn.textContent = '👍 Sim (' + q.helpfulCount + ')';
  showToast('👍 Obrigado pelo feedback!');
}

function qaSubmitQuestion() {
  var inp = document.getElementById('qaAskInput');
  var text = (inp ? inp.value : '').trim();
  if (!text) return showToast('⚠️ Digite sua pergunta antes de enviar');
  if (text.length < 10) return showToast('⚠️ Pergunta muito curta — adicione mais detalhes');
  // Prepend to _qaData
  var newQ = {
    id: 'q_' + Date.now(),
    user: 'Você',
    date: new Date().toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit',year:'numeric'}),
    votes: 0, userVote: 0,
    text: text,
    answer: null, helpfulCount: 0,
  };
  _qaData.unshift(newQ);
  if (inp) inp.value = '';
  // Reset filter to all
  _qaFilter = 'all';
  document.querySelectorAll('.qa-filter').forEach(function(b,i){b.classList.toggle('active',i===0);});
  renderQA();
  // Scroll to new question
  setTimeout(function() {
    var el = document.getElementById('qaItem_' + newQ.id);
    if (el) el.scrollIntoView({behavior:'smooth', block:'center'});
    el.style.boxShadow = '0 0 0 2px var(--teal)';
    setTimeout(function(){if(el) el.style.boxShadow='';}, 2000);
  }, 100);
  showToast('✅ Pergunta enviada! O vendedor responde em até 24h.');
}


