// ══════════════════════════════════════════════════════

// Cupons estendidos com metadata para a gaveta
const COUPON_CATALOG = [
  { code:'WEKZ10',  emoji:'🏷️',  disc:'10% OFF',  desc:'10% de desconto em toda a loja',            type:'%',     val:10, minimo:0,    expiry:'31/12/2026', limitUses:0    },
  { code:'WEKZ20',  emoji:'⚡',  disc:'20% OFF',  desc:'20% de desconto exclusivo WeKz',             type:'%',     val:20, minimo:150,  expiry:'31/07/2026', limitUses:500  },
  { code:'FRETE0',  emoji:'🚚',  disc:'Frete Grátis', desc:'Entrega grátis para qualquer endereço', type:'frete', val:0,  minimo:0,    expiry:'31/12/2026', limitUses:0    },
  { code:'NOVO15',  emoji:'🎉',  disc:'15% OFF',  desc:'Desconto de boas-vindas — 1ª compra',        type:'%',     val:15, minimo:0,    expiry:'31/08/2026', limitUses:1    },
  { code:'FLASH50', emoji:'🔥',  disc:'50% OFF',  desc:'Oferta relâmpago — estoque limitado',        type:'%',     val:50, minimo:200,  expiry:'30/06/2026', limitUses:100  },
  { code:'BOOST20', emoji:'🚀',  disc:'20% OFF',  desc:'WeKz Boost ativado — 20% em tudo',           type:'%',     val:20, minimo:100,  expiry:'31/12/2026', limitUses:0    },
  { code:'CYBER30', emoji:'🌀',  disc:'30% OFF',  desc:'Cupom Cyber — nível Gold ou acima',          type:'%',     val:30, minimo:300,  expiry:'15/07/2026', limitUses:200  },
  { code:'FRETENEW',emoji:'📦',  disc:'Frete Grátis', desc:'Frete grátis para novos endereços',     type:'frete', val:0,  minimo:80,   expiry:'31/12/2026', limitUses:0    },
];

// State
var _couponDrawerOpen = false;

// ── Gaveta de cupons ──
function toggleCouponDrawer() {
  _couponDrawerOpen = !_couponDrawerOpen;
  var drawer = document.getElementById('couponDrawer');
  var arrow  = document.getElementById('couponDrawerArrow');
  if (!drawer) return;
  if (_couponDrawerOpen) {
    drawer.classList.add('open');
    arrow && arrow.classList.add('open');
    renderCouponDrawer();
  } else {
    drawer.classList.remove('open');
    arrow && arrow.classList.remove('open');
  }
}

function renderCouponDrawer() {
  var inner = document.getElementById('couponDrawerInner');
  if (!inner) return;

  var sub = _getCartSubtotal();
  var used = window._usedCoupons || {};
  var active = window._activeCoupon;

  // Separate by type
  var pct   = COUPON_CATALOG.filter(function(c){return c.type==='%';});
  var frete = COUPON_CATALOG.filter(function(c){return c.type==='frete';});

  function buildCard(c) {
    var isUsed   = used[c.code] && !(active && active.code === c.code);
    var isActive = active && active.code === c.code;
    var needMore = c.minimo > 0 && sub < c.minimo;
    var missing  = c.minimo > 0 ? Math.max(0, c.minimo - sub) : 0;
    var typeLabel = c.type === 'frete' ? '#22C55E' : c.type === '%' && c.val >= 30 ? '#EF4444' : 'var(--teal)';

    return '<div class="coupon-card' + (isUsed?' used':'') + '" onclick="' + (isUsed?'':('couponApplyFromDrawer(\'' + c.code + '\')')) + '">' +
      '<div class="coupon-card-emoji">' + c.emoji + '</div>' +
      '<div class="coupon-card-body">' +
        '<div class="coupon-card-discount" style="color:' + typeLabel + ';">' + c.disc + '</div>' +
        '<div class="coupon-card-desc">' + c.desc + '</div>' +
        '<div class="coupon-card-meta">' +
          (c.expiry ? '<span class="coupon-card-expiry">Válido até ' + c.expiry + '</span>' : '') +
          (c.minimo ? '<span class="coupon-card-min">⚠️ Mín. R$ ' + c.minimo.toFixed(2).replace('.',',') + '</span>' : '') +
          (needMore ? '<span style="font-size:10px;color:#F59E0B;">Faltam R$ ' + missing.toFixed(2).replace('.',',') + '</span>' : '') +
          (isActive ? '<span style="font-size:10px;font-weight:700;color:#4ade80;">✅ Aplicado</span>' : '') +
        '</div>' +
      '</div>' +
      '<div class="coupon-card-right">' +
        '<div class="coupon-card-code">' + c.code + '</div>' +
        (isUsed ? '<span style="font-size:10px;color:var(--muted);">Usado</span>' :
          isActive ? '<span style="font-size:10px;color:#4ade80;">Ativo</span>' :
          '<button class="coupon-use-btn" onclick="event.stopPropagation();couponApplyFromDrawer(\'' + c.code + '\')">Usar</button>') +
      '</div>' +
    '</div>';
  }

  inner.innerHTML =
    '<div class="coupon-section-label">🏷️ Desconto em produtos</div>' +
    pct.map(buildCard).join('') +
    '<div class="coupon-section-label" style="margin-top:8px;">🚚 Frete grátis</div>' +
    frete.map(buildCard).join('');
}

function couponApplyFromDrawer(code) {
  var inp = document.getElementById('cartCouponField');
  if (inp) inp.value = code;
  toggleCouponDrawer(); // close drawer
  applyCartCouponV2(code);
}

// ── Autocomplete ──
function couponAutoComplete(val) {
  var ac = document.getElementById('couponAC');
  if (!ac) return;
  var q = val.trim().toUpperCase();
  if (!q) { ac.classList.remove('open'); return; }

  var matches = COUPON_CATALOG.filter(function(c){
    return c.code.startsWith(q) && c.code !== q;
  });
  if (!matches.length) { ac.classList.remove('open'); return; }

  ac.innerHTML = matches.slice(0,4).map(function(c) {
    var badge = c.type==='frete' ? 'background:rgba(34,197,94,0.12);color:#4ade80;border:1px solid rgba(34,197,94,0.2);'
              : c.val>=30 ? 'background:rgba(239,68,68,0.1);color:#EF4444;border:1px solid rgba(239,68,68,0.2);'
              : 'background:rgba(0,180,171,0.1);color:var(--teal);border:1px solid rgba(0,180,171,0.2);';
    return '<div class="coupon-ac-item" onclick="couponACFill(\'' + c.code + '\')">' +
      '<div class="coupon-ac-code">' + c.code + '</div>' +
      '<div class="coupon-ac-desc">' + c.desc + '</div>' +
      '<div class="coupon-ac-type" style="' + badge + '">' + c.disc + '</div>' +
    '</div>';
  }).join('');
  ac.classList.add('open');
}

function couponACFill(code) {
  var inp = document.getElementById('cartCouponField');
  if (inp) { inp.value = code; inp.focus(); }
  var ac = document.getElementById('couponAC');
  if (ac) ac.classList.remove('open');
}

// Close autocomplete on click outside
document.addEventListener('click', function(e) {
  var ac = document.getElementById('couponAC');
  var wrap = document.querySelector('.coupon-input-wrap');
  if (ac && wrap && !wrap.contains(e.target)) ac.classList.remove('open');
});

// ── Apply coupon v2 (with inline feedback + banner) ──
function applyCartCouponV2(code) {
  var inp = document.getElementById('cartCouponField');
  var ac  = document.getElementById('couponAC');
  if (!code) code = inp ? inp.value.trim().toUpperCase() : '';
  if (!code) { showCouponFeedback('⚠️ Digite um código de cupom', 'err'); return; }
  if (ac) ac.classList.remove('open');

  // Already active
  if (window._activeCoupon && window._activeCoupon.code === code) {
    showCouponFeedback('ℹ️ Cupom ' + code + ' já está aplicado', 'ok'); return;
  }

  // Already used this session
  window._usedCoupons = window._usedCoupons || {};
  if (window._usedCoupons[code]) {
    showCouponFeedback('❌ Cupom ' + code + ' já foi utilizado nesta sessão', 'err'); return;
  }

  var coupon = (typeof WEKZ_COUPONS !== 'undefined' && WEKZ_COUPONS[code])
            || (typeof SELLER_COUPONS !== 'undefined' && SELLER_COUPONS[code]);

  if (!coupon) {
    showCouponFeedback('❌ Cupom inválido. Tente: WEKZ10, FRETE0, NOVO15', 'err');
    var field = document.getElementById('cartCouponField');
    if (field) field.classList.add('invalid');
    setTimeout(function(){ if(field) field.classList.remove('invalid'); }, 1500);
    return;
  }

  // Expiry
  if (coupon.validade && new Date(coupon.validade) < new Date()) {
    showCouponFeedback('❌ Cupom expirado em ' + new Date(coupon.validade).toLocaleDateString('pt-BR'), 'err');
    return;
  }

  // Usos globais esgotados
  if (coupon.usos > 0 && (coupon._used||0) >= coupon.usos) {
    showCouponFeedback('❌ Cupom esgotado', 'err'); return;
  }

  // [v2.9.30] Bloqueia cupons de %/valor fixo quando todo o carrinho já tem
  // desconto anunciado — mesma regra de applyCartCoupon().
  if (coupon.type !== 'frete' && _wkzCouponEligibleSubtotal() <= 0) {
    showCouponFeedback(_wkzCouponBlockedMsg(), 'err'); return;
  }

  // Minimum check
  var sub = _getCartSubtotal();
  if (coupon.minimo > 0 && sub < coupon.minimo) {
    var missing = (coupon.minimo - sub).toFixed(2).replace('.',',');
    showCouponFeedback('⚠️ Adicione mais R$ ' + missing + ' para usar este cupom', 'err');
    renderCouponMinProgress(sub, coupon.minimo, code);
    return;
  }

  // Apply
  coupon._used = (coupon._used||0) + 1;
  window._usedCoupons[code] = true;
  window._activeCoupon = Object.assign({ code: code }, coupon);

  var field = document.getElementById('cartCouponField');
  if (field) { field.value = ''; field.classList.add('valid'); setTimeout(function(){ field.classList.remove('valid'); }, 1500); }

  var discText = coupon.type === 'frete' ? 'Frete Grátis'
               : coupon.type === '%'     ? coupon.disc + '% OFF'
               : 'R$ ' + coupon.disc.toFixed(2).replace('.',',') + ' de desconto';
  showCouponFeedback('✅ ' + discText + ' aplicado!', 'ok');
  renderCouponActiveBanner();
  hideCouponMinProgress();
  if (typeof updateCartUI === 'function') updateCartUI();
}

// Sprint 0.1 fix A1: stub removido — implementação completa em applyCartCoupon() abaixo (~L35040)
// ── Active coupon banner ──
function renderCouponActiveBanner() {
  var el = document.getElementById('couponActiveBanner');
  if (!el) return;
  var ac = window._activeCoupon;
  if (!ac) { el.style.display = 'none'; return; }

  var discText = ac.type === 'frete' ? '🚚 Frete Grátis'
               : ac.type === '%'     ? ac.disc + '% OFF'
               : '-R$ ' + (ac.disc||0).toFixed(2).replace('.',',');
  var desc = ac.label || ac.desc || discText;

  el.style.display = 'block';
  el.innerHTML = '<div class="coupon-active-banner">' +
    '<div class="coupon-active-icon">🏷️</div>' +
    '<div class="coupon-active-body">' +
      '<div class="coupon-active-code">' + ac.code + ' — ' + discText + '</div>' +
      '<div class="coupon-active-desc">' + desc + '</div>' +
    '</div>' +
    '<button class="coupon-active-remove" onclick="removeCouponV2()" title="Remover cupom">✕</button>' +
  '</div>';
}

function removeCouponV2() {
  // Limpar o flag de "já utilizado" para o cupom ativo — permite reaplicar
  if (window._activeCoupon && window._activeCoupon.code) {
    var code = window._activeCoupon.code;
    if (window._usedCoupons) delete window._usedCoupons[code];
    // Decrementar counter interno do cupom
    var coupon = (typeof WEKZ_COUPONS !== 'undefined' && WEKZ_COUPONS[code])
              || (typeof SELLER_COUPONS !== 'undefined' && SELLER_COUPONS[code]);
    if (coupon && coupon._used > 0) coupon._used--;
  }
  window._activeCoupon = null;
  var el = document.getElementById('couponActiveBanner');
  if (el) el.style.display = 'none';
  hideCouponMinProgress();
  showToast('🗑️ Cupom removido');
  if (typeof updateCartUI === 'function') updateCartUI();
}

// Sprint 0.1 fix A1: stub removido — implementação completa em removeCoupon() abaixo (~L35098)
// ── Minimum progress bar ──
function renderCouponMinProgress(current, minimo, code) {
  var el = document.getElementById('couponMinProgress');
  if (!el) return;
  var pct     = Math.min(100, Math.round((current / minimo) * 100));
  var missing = (minimo - current).toFixed(2).replace('.',',');
  el.style.display = 'block';
  el.innerHTML = '<div class="coupon-min-progress">' +
    '<div class="coupon-min-label">⚠️ Para usar ' + code + ': adicione R$ ' + missing + ' ao carrinho</div>' +
    '<div class="coupon-min-bar"><div class="coupon-min-fill" style="width:' + pct + '%;"></div></div>' +
    '<div class="coupon-min-sub">' + pct + '% do mínimo atingido (R$ ' + current.toFixed(2).replace('.',',') + ' de R$ ' + minimo.toFixed(2).replace('.',',') + ')</div>' +
  '</div>';
}

function hideCouponMinProgress() {
  var el = document.getElementById('couponMinProgress');
  if (el) el.style.display = 'none';
}

// ── Inline feedback ──
function showCouponFeedback(msg, type) {
  var el = document.getElementById('couponFeedbackInline');
  if (!el) return;
  el.textContent = msg;
  el.className = 'coupon-feedback ' + type;
  el.style.display = 'block';
  if (type === 'ok') setTimeout(function(){ el.style.display='none'; }, 3000);
}

// ── Get cart subtotal helper ──
function _getCartSubtotal() {
  if (typeof cartItemsData === 'undefined') return 0;
  return cartItemsData.filter(function(c){return c._selected!==false;})
    .reduce(function(s,c){return s + (c.rawPrice||0)*(c.qty||1);}, 0);
}

// [v2.9.30] Regra de negócio: produtos que já têm desconto anunciado (promoção
// do produto, Flash Sale ou Live Shopping) não acumulam com cupom — evita
// empilhar descontos e prejudicar a margem do vendedor/site. Usado por todas
// as funções de aplicar cupom (applyCartCoupon, applyCartCouponV2, applyWekzCoupon).
function _wkzCouponEligibleSubtotal() {
  if (typeof cartItemsData === 'undefined') return 0;
  return cartItemsData.filter(function(c){
      if (c._selected === false) return false;
      var isPromo = !!c._isFlash || !!c._isLive || (typeof c.op === 'number' && c.op > c.rawPrice);
      return !isPromo;
    })
    .reduce(function(s,c){ return s + (c.rawPrice||0)*(c.qty||1); }, 0);
}
function _wkzCouponBlockedMsg() {
  return '❌ Este cupom não pode ser usado: todos os produtos no carrinho já têm desconto anunciado. Cupons de % ou valor fixo não acumulam com promoções existentes.';
}

// Patch updateCartUI to also refresh coupon banner
var _origUpdateCartUIForCoupon = null;
function _patchCartUIForCoupon() {
  if (typeof updateCartUI !== 'function' || _origUpdateCartUIForCoupon) return;
  _origUpdateCartUIForCoupon = updateCartUI;
  updateCartUI = function() {
    _origUpdateCartUIForCoupon.apply(this, arguments);
    setTimeout(function() {
      renderCouponActiveBanner();
      if (_couponDrawerOpen) renderCouponDrawer();
    }, 25);
  };
}


