// ══════════════════════════════════════════════════════
//  RETURN MODAL ENGINE v1 — Pontos de Coleta & Devolução
//  Reutiliza PICKUP_POINTS (FIX BUG-N01 aplica-se aqui também:
//  pontos demonstrativos até integração com Kangu/Pegaki/Correios)
// ══════════════════════════════════════════════════════

const RETURN_REASONS = [
  { id:'defeito',   label:'🔧 Produto com defeito ou avariado' },
  { id:'diferente', label:'📦 Produto diferente do anunciado' },
  { id:'arrependimento', label:'↩️ Não gostei / desisti da compra' },
  { id:'outro',     label:'✏️ Outro motivo' },
];

var _retOrder = null;
var _retReason = null;
var _retPoint = null;

function openReturnModal(orderId, productName) {
  _retOrder = { id: orderId, name: productName };
  _retReason = null;
  _retPoint = null;
  renderReturnStep1();
  document.getElementById('wkzReturnModalOv').classList.add('open');
}

function closeReturnModal() {
  document.getElementById('wkzReturnModalOv').classList.remove('open');
}

function renderReturnStep1() {
  var body = document.getElementById('wkzRetBody');
  var footer = document.getElementById('wkzRetFooter');

  body.innerHTML =
    '<div class="wkz-ret-order-chip">Pedido <strong>' + _retOrder.id + '</strong> — ' + _retOrder.name + '</div>' +
    '<div class="wkz-ret-step-label">1. Qual o motivo da devolução?</div>' +
    '<div class="wkz-ret-reasons" id="wkzRetReasons">' +
      RETURN_REASONS.map(function(r) {
        return '<label class="wkz-ret-reason' + (_retReason===r.id?' sel':'') + '" id="wkzRetReason_'+r.id+'" onclick="selectReturnReason(\''+r.id+'\')">' +
          '<input type="radio" name="wkzRetReason"' + (_retReason===r.id?' checked':'') + '>' +
          '<span>' + r.label + '</span>' +
        '</label>';
      }).join('') +
    '</div>' +
    '<div class="wkz-ret-step-label">2. Escolha um ponto de entrega para devolução</div>' +
    '<div class="wkz-ret-points-list" id="wkzRetPointsList">' +
      PICKUP_POINTS.slice().sort(function(a,b){return a.distNum-b.distNum;}).map(function(p) {
        return '<div class="wkz-ret-point' + (_retPoint===p.id?' sel':'') + '" id="wkzRetPt_'+p.id+'" onclick="selectReturnPoint(\''+p.id+'\')">' +
          '<div class="wkz-ret-point-icon" style="background:'+p.color+'22;">' + p.icon + '</div>' +
          '<div style="flex:1;min-width:0;">' +
            '<div class="wkz-ret-point-name">' + p.name + '</div>' +
            '<div class="wkz-ret-point-addr">' + p.addr + '</div>' +
            '<div class="wkz-ret-point-meta"><span>📍 ' + p.dist + '</span><span>⏰ ' + p.hours + '</span></div>' +
          '</div>' +
        '</div>';
      }).join('') +
    '</div>';

  footer.innerHTML =
    '<button class="wkz-ret-btn secondary" onclick="closeReturnModal()">Cancelar</button>' +
    '<button class="wkz-ret-btn primary" id="wkzRetConfirmBtn" onclick="confirmReturnRequest()"' + ((_retReason&&_retPoint)?'':' disabled') + '>Confirmar Devolução</button>';
}

function selectReturnReason(id) {
  _retReason = id;
  RETURN_REASONS.forEach(function(r) {
    var el = document.getElementById('wkzRetReason_'+r.id);
    if (!el) return;
    el.classList.toggle('sel', r.id===id);
    var inp = el.querySelector('input');
    if (inp) inp.checked = (r.id===id);
  });
  var btn = document.getElementById('wkzRetConfirmBtn');
  if (btn) btn.disabled = !(_retReason && _retPoint);
}

function selectReturnPoint(id) {
  _retPoint = id;
  PICKUP_POINTS.forEach(function(p) {
    var el = document.getElementById('wkzRetPt_'+p.id);
    if (el) el.classList.toggle('sel', p.id===id);
  });
  var btn = document.getElementById('wkzRetConfirmBtn');
  if (btn) btn.disabled = !(_retReason && _retPoint);
}

function confirmReturnRequest() {
  if (!_retReason || !_retPoint) return;
  var pt = PICKUP_POINTS.find(function(p){return p.id===_retPoint;});
  var reason = RETURN_REASONS.find(function(r){return r.id===_retReason;});
  var code = 'WKZDEV' + Math.floor(10000000 + Math.random()*89999999) + 'BR';

  var body = document.getElementById('wkzRetBody');
  var footer = document.getElementById('wkzRetFooter');

  body.innerHTML =
    '<div class="wkz-ret-success">' +
      '<div class="wkz-ret-success-icon">' +
        '<svg viewBox="0 0 24 24" width="26" height="26" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>' +
      '</div>' +
      '<div style="font-weight:800;font-size:15px;margin-bottom:6px;">Devolução solicitada!</div>' +
      '<div style="font-size:12px;color:var(--muted2);line-height:1.6;">Pedido <strong style="color:var(--text)">' + _retOrder.id + '</strong> — ' + reason.label + '<br>Leve o produto, com embalagem original, ao ponto selecionado:</div>' +
      '<div style="margin:12px 0;padding:12px;background:var(--card2);border:1px solid var(--border);border-radius:10px;text-align:left;">' +
        '<div style="font-size:12.5px;font-weight:700;">' + pt.icon + ' ' + pt.name + '</div>' +
        '<div style="font-size:11px;color:var(--muted);margin-top:3px;">' + pt.addr + '</div>' +
        '<div style="font-size:11px;color:var(--muted);margin-top:3px;">⏰ ' + pt.hours + '</div>' +
      '</div>' +
      '<div class="wkz-ret-success-code">' + code + '</div>' +
      '<div style="font-size:11px;color:var(--muted);">Apresente este código no balcão · Retirada/devolução sempre gratuita</div>' +
    '</div>';

  footer.innerHTML =
    '<button class="wkz-ret-btn secondary" onclick="closeReturnModal()">Fechar</button>' +
    '<button class="wkz-ret-btn primary" onclick="closeReturnModal();MapsTo(\'client-profile\')">Ver Meus Pedidos</button>';

  showToast('↩️ Devolução solicitada · Código ' + code);
}

/* FIX Sprint M2 (Patch 3 — consolidação de showToast): a definição V1
   original de showToast(msg) (DOM #toast/#toastMsg, sem progress bar,
   3s fixo) foi REMOVIDA daqui. No monólito ela era funcionalmente morta
   — sempre sobrescrita pelo showToast V2 (initToastV2, com progress bar)
   que roda em DOMContentLoaded depois de qualquer script síncrono, então
   V2 sempre "ganhava" por último. Mantê-la aqui seria recriar o mesmo
   padrão de "duplicata silenciosa" (last-write-wins) já flagrado como
   risco recorrente deste codebase — e na nova ordem de carregamento
   modular (core → buyer) isso ficaria ainda mais frágil de rastrear.
   window.showToast (V2) já é fornecido por wkz-core.js; nada aqui precisa
   redeclará-lo. `toastTimeout` (var órfã, só usada por este showToast V1)
   também foi removida por não ter mais nenhuma outra referência no
   monólito (confirmado via grep antes da remoção). */



/* ── 2.3: Busca/Frete/Categoria/Loja/Rastreio/Ajuda ──────────────────────
   tick() [countdown flash sale — FIX: guard de nulo adicionado pros 3
   elementos que não tinham, consistente com os outros 6 já guardados],
   filtros de grid, dropdowns de busca (hero + topbar), cálculo de CEP/
   frete nacional e internacional, openCategory/renderCatProducts,
   openStore/renderStores, rastreamento de pedido, central de ajuda/FAQ.
   Origem monólito: linhas 28106–30242
   ─────────────────────────────────────────────────────────────────────── */
// ─── COUNTDOWN (FUNC-07: timestamp fixo, não-aleatório) ───
const FLASH_END = new Date('2025-06-15T23:59:59');
function tick(){
  let diff = FLASH_END - new Date();
  if (diff <= 0) diff = 0;
  const h=Math.floor(diff/3600000);
  const m=Math.floor((diff%3600000)/60000);
  const s=Math.floor((diff%60000)/1000);
  /* FIX Sprint M2 (achado via teste real, não estava no plano): tick()
     roda em setInterval GLOBAL, em qualquer página — mas só a Home tem
     os elementos #ch/#cm/#cs. Sem guard de nulo, isso lançava erro a
     cada 1s em qualquer outra página (PDP, Carrinho, Perfil...). Os
     outros 6 elementos (fsCh/fsCm/fsCs/fhCh/fhCm/fhCs), duas linhas
     abaixo, já seguiam esse guard — só faltava aqui. Comportamento
     visual idêntico na Home (onde #ch/#cm/#cs sempre existem). */
  const ch=document.getElementById('ch'); if(ch) ch.textContent=String(h).padStart(2,'0');
  const cm=document.getElementById('cm'); if(cm) cm.textContent=String(m).padStart(2,'0');
  const cs=document.getElementById('cs'); if(cs) cs.textContent=String(s).padStart(2,'0');
  // Sync flash sale page countdown
  const fsCh=document.getElementById('fsCh'); if(fsCh) fsCh.textContent=String(h).padStart(2,'0');
  const fsCm=document.getElementById('fsCm'); if(fsCm) fsCm.textContent=String(m).padStart(2,'0');
  const fsCs=document.getElementById('fsCs'); if(fsCs) fsCs.textContent=String(s).padStart(2,'0');
  // Sync flash hero section countdown
  const fhCh=document.getElementById('fhCh'); if(fhCh) fhCh.textContent=String(h).padStart(2,'0');
  const fhCm=document.getElementById('fhCm'); if(fhCm) fhCm.textContent=String(m).padStart(2,'0');
  const fhCs=document.getElementById('fhCs'); if(fhCs) fhCs.textContent=String(s).padStart(2,'0');
}
setInterval(tick,1000);
  _patchCartForPoints();
  _patchCartUIForCoupon();
  // _patchCkoutNextForPickup() — removido: validação de pickup integrada em ckoutNext() (BUG-02 fix)
// Price chart redraws on resize
window.addEventListener('resize', function() {
  if (typeof _phSeries !== 'undefined' && _phSeries.length && typeof _phProduct !== 'undefined' && _phProduct) {
    var prices = _phSeries.map(function(s){return s.price;});
    _phDrawCanvas(_phSeries, Math.min.apply(null,prices), Math.max.apply(null,prices), _phProduct.p);
  }
});


