// ─── FILTER BAR TOGGLE ───
let filterBarOpen=false;
function toggleFilterBar(){
  const fb=document.getElementById('filterBar');
  const btn=document.getElementById('heroFilterToggle');
  if(filterBarOpen){ _closeFilterBar(); return; }
  filterBarOpen=true;
  fb.style.display='block';
  fb.style.opacity='0';
  fb.style.transform='translateY(-10px)';
  fb.style.transition='opacity 0.24s ease, transform 0.24s cubic-bezier(0.34,1.3,0.64,1)';
  requestAnimationFrame(()=>requestAnimationFrame(()=>{
    fb.style.opacity='1';
    fb.style.transform='translateY(0)';
  }));
  btn.classList.add('active');
  document.getElementById('filterToggleIcon').innerHTML='<svg viewBox="0 0 24 24" width="13" height="13" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="vertical-align:middle;"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>';
  renderFilterChips();
}

function _closeFilterBar(){
  if(!filterBarOpen)return;
  const fb=document.getElementById('filterBar');
  const btn=document.getElementById('heroFilterToggle');
  fb.style.transition='opacity 0.18s ease, transform 0.18s ease';
  fb.style.opacity='0';
  fb.style.transform='translateY(-8px)';
  btn.classList.remove('active');
  document.getElementById('filterToggleIcon').innerHTML='<svg viewBox="0 0 24 24" width="13" height="13" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" style="vertical-align:middle;flex-shrink:0;"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 00.33 1.82l.06.06a2 2 0 010 2.83 2 2 0 01-2.83 0l-.06-.06a1.65 1.65 0 00-1.82-.33 1.65 1.65 0 00-1 1.51V21a2 2 0 01-4 0v-.09A1.65 1.65 0 009 19.4a1.65 1.65 0 00-1.82.33l-.06.06a2 2 0 01-2.83-2.83l.06-.06A1.65 1.65 0 004.68 15a1.65 1.65 0 00-1.51-1H3a2 2 0 010-4h.09A1.65 1.65 0 004.6 9a1.65 1.65 0 00-.33-1.82l-.06-.06a2 2 0 012.83-2.83l.06.06A1.65 1.65 0 009 4.68a1.65 1.65 0 001-1.51V3a2 2 0 014 0v.09a1.65 1.65 0 001 1.51 1.65 1.65 0 001.82-.33l.06-.06a2 2 0 012.83 2.83l-.06.06A1.65 1.65 0 0019.4 9a1.65 1.65 0 001.51 1H21a2 2 0 010 4h-.09a1.65 1.65 0 00-1.51 1z"/></svg>';
  setTimeout(()=>{
    fb.style.display='none';
    fb.style.transition='';
    fb.style.opacity='';
    fb.style.transform='';
    filterBarOpen=false;
  }, 190);
}

function renderFilterChips(){
  const chips=document.getElementById('filterChips');
  if(!chips)return;
  const cats=['Eletrônicos','Moda','Casa & Deco','Beleza','Games','Esportes','Automotivo','Pet Shop'];
  chips.innerHTML=cats.map(c=>`<span class="filter-chip" onclick="toggleFilterChip(this,'${c}')">${c}</span>`).join('');
}

function toggleFilterChip(el,cat){
  el.classList.toggle('active');
}

let filterStarMin=0;
function setFilterStar(val,el){
  filterStarMin=val;
  document.querySelectorAll('.filter-star-btn').forEach(b=>b.classList.remove('active'));
  el.classList.add('active');
}

function toggleFilterTag(el,tag){
  el.classList.toggle('active');
  const active = el.classList.contains('active');
  if(tag==='frete-gratis'){
    const grid = document.getElementById('productsGrid');
    if(!grid) return;
    grid.querySelectorAll('.product-card').forEach(card=>{
      if(!active){ card.style.display=''; return; }
      // mostra apenas cards com badge frete
      const hasFrete = card.querySelector('.badge-frete');
      card.style.display = hasFrete ? '' : 'none';
    });
    if(active) showToast('🚚 A mostrar apenas produtos com Frete Grátis');
    else showToast('🔍 Filtro removido');
  }
}

function applyFilters(){
  const sort=document.getElementById('fSort').value;
  const minP=parseFloat(document.getElementById('fPriceMin').value)||0;
  const maxP=parseFloat(document.getElementById('fPriceMax').value)||Infinity;
  let list=[...products].filter(p=>p.p>=minP&&p.p<=maxP&&p.r>=filterStarMin);
  if(sort==='price-asc')list.sort((a,b)=>a.p-b.p);
  else if(sort==='price-desc')list.sort((a,b)=>b.p-a.p);
  else if(sort==='rating')list.sort((a,b)=>b.r-a.r);
  else if(sort==='sales')list.sort((a,b)=>parseFloat(b.sales)-parseFloat(a.sales));
  renderProducts(list);
  showToast(`🎯 ${list.length} produto${list.length!==1?'s':''} encontrado${list.length!==1?'s':''}`);
  /* Fechar o painel com animação */
  _closeFilterBar();
  setTimeout(()=>document.getElementById('products-sec').scrollIntoView({behavior:'smooth'}),320);
}

function clearFilters(){
  document.getElementById('fPriceMin').value='';
  document.getElementById('fPriceMax').value='';
  document.getElementById('fSort').value='';
  filterStarMin=0;
  document.querySelectorAll('.filter-star-btn').forEach((b,i)=>{b.classList.toggle('active',i===0);});
  document.querySelectorAll('.filter-tag-btn,.filter-chip').forEach(b=>b.classList.remove('active'));
  renderProducts();
  showToast('🔄 Filtros limpos — a mostrar todos os produtos');
  _closeFilterBar();
}

// ─── ACTIVE SEARCH RESULT STATE ───
let activeSearchQuery='';
function setActiveSearchResult(q,cat){
  activeSearchQuery=q;
  const existing=document.getElementById('searchResultBar');
  if(existing)existing.remove();
  if(!q&&!cat)return;
  const secHdr=document.querySelector('#products-sec .section-header');
  if(!secHdr)return;
  const bar=document.createElement('div');
  bar.id='searchResultBar';
  bar.className='search-result-bar';
  const safeQ = escapeHtml(q); const safeCat = escapeHtml(cat); // Sprint 0.1 fix S1
  bar.innerHTML=`<div class="srb-query">Resultados para: <strong>"${safeQ||safeCat}"</strong> ${safeCat?`<span style="font-size:12px;color:var(--muted);">em ${safeCat}</span>`:''}</div>
    <span class="srb-count">${products.length} produtos encontrados</span>
    <span class="srb-clear" onclick="clearSearch()">✕ Limpar busca</span>`;
  secHdr.after(bar);
}
function clearSearch(){
  document.getElementById('searchInput').value='';
  document.getElementById('heroSearchInput').value='';
  const bar=document.getElementById('searchResultBar');
  if(bar)bar.remove();
  renderProducts();
}

// ─── HERO QUICK FILTER ───
function heroQuickFilter(label,el){
  document.querySelectorAll('.hfc-chip').forEach(c=>c.classList.remove('active'));
  el.classList.add('active');
  if(label==='Mais vendidos'){renderProducts([...products].sort((a,b)=>parseFloat(b.sales)-parseFloat(a.sales)));}
  else if(label==='4★ ou mais'){renderProducts(products.filter(p=>p.r>=4));}
  else if(label==='Até R$100'){renderProducts(products.filter(p=>p.p<=100));}
  else if(label==='Novidades'){renderProducts(products.filter(p=>p.badge==='new'));}
  else{renderProducts();}
  showToast(`🎯 Filtro: ${label}`);
  setTimeout(()=>document.getElementById('products-sec').scrollIntoView({behavior:'smooth'}),200);
}

