const SDR_TRENDING = ['Smartphone 5G','Notebook Gamer','Tênis Running','Smartwatch GPS','Fone ANC','Monitor 4K','Console 2025'];
const SDR_CATS = [
  {i:'📱',n:'Eletrônicos'},{i:'👗',n:'Moda'},{i:'🏠',n:'Casa'},{i:'💄',n:'Beleza'},
  {i:'🎮',n:'Games'},{i:'🏃',n:'Esportes'},{i:'📷',n:'Câmeras'},{i:'🪑',n:'Móveis'},
];

// In-memory history (survives session, not page reload — intentional for SPA)
let _searchHistory = ['Smartphone Ultra','Fone Bluetooth','Monitor 144Hz'];

function _pushHistory(term) {
  term = term.trim();
  if (!term) return;
  _searchHistory = _searchHistory.filter(h => h.toLowerCase() !== term.toLowerCase());
  _searchHistory.unshift(term);
  if (_searchHistory.length > 8) _searchHistory.pop();
}

function _removeHistory(term, ev) {
  if (ev) { ev.stopPropagation(); }
  _searchHistory = _searchHistory.filter(h => h !== term);
}

function _fmtPrice(v) {
  return 'R$ ' + v.toLocaleString('pt-BR', {minimumFractionDigits: 2, maximumFractionDigits: 2});
}

function _highlight(text, query) {
  if (!query) return text;
  var re = new RegExp('(' + query.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + ')', 'gi');
  return text.replace(re, '<mark>$1</mark>');
}

function _buildRichItem(s, query, fillFn) {
  // [v2.9.31] Usa wkzExactOff para cálculo sem arredondamento; exibe floor no badge
  var off = s.op ? Math.floor(wkzExactOff(s.p, s.op)) : (s.off || 0);
  var stars = '★'.repeat(Math.round(s.r || 4.5)) + '☆'.repeat(5 - Math.round(s.r || 4.5));
  return `<div class="sdr-item" onclick="${fillFn}('${s.t.replace(/'/g,"\\'")}')">
    <div class="sdr-thumb">${s.i}</div>
    <div class="sdr-info">
      <div class="sdr-name">${_highlight(s.t, query)}</div>
      <div class="sdr-meta">
        <span class="sdr-price">${_fmtPrice(s.p)}</span>
        ${s.op ? `<span class="sdr-price-old">${_fmtPrice(s.op)}</span>` : ''}
        ${off > 0 ? `<span class="sdr-off">-${off}%</span>` : ''}
        <span class="sdr-stars">${stars}</span>
        <span class="sdr-sales">${s.sales || ''} vendas</span>
      </div>
    </div>
    <span class="sdr-cat">${s.c}</span>
  </div>`;
}

function _buildDropdownBody(filtered, query, fillFn, showHistory, showCats) {
  var html = '';

  // History section (only when input is empty)
  if (showHistory && _searchHistory.length) {
    html += `<div class="sdr-label">
      <svg viewBox="0 0 24 24" width="11" height="11" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
      Buscas recentes
    </div>
    <div class="sdr-history">
      ${_searchHistory.map(h => `
        <div class="sdr-hist-chip" onclick="${fillFn}('${h.replace(/'/g,"\\'")}')">
          <svg viewBox="0 0 24 24" width="10" height="10" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
          <span>${h}</span>
          <span class="sdr-hist-rm" onclick="_removeHistory('${h.replace(/'/g,"\\'")}',event);_refreshBothDropdowns();">×</span>
        </div>`).join('')}
    </div>
    <div class="sdr-divider"></div>`;
  }

  // Suggestions / results
  if (filtered.length) {
    if (!showHistory) {
      html += `<div class="sdr-label">
        <svg viewBox="0 0 24 24" width="11" height="11" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
        ${query ? 'Resultados para "' + query + '"' : 'Produtos em destaque'}
      </div>`;
    } else {
      html += `<div class="sdr-label">
        <svg viewBox="0 0 24 24" width="11" height="11" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/></svg>
        Produtos populares
      </div>`;
    }
    html += filtered.slice(0, 6).map(s => _buildRichItem(s, query, fillFn)).join('');
  } else if (query) {
    const _safeQ = (typeof wkzSanitizeHTML === 'function') ? wkzSanitizeHTML(query, true) : escapeHtml(query); // C2: userContent=true
    html += `<div class="sdr-empty">Nenhum resultado para <strong>"${_safeQ}"</strong><br><span style="font-size:11px;">Tente: ${SDR_TRENDING.slice(0,3).join(', ')}</span></div>`;
  }

  // Category shortcuts (only when empty input)
  if (showCats) {
    html += `<div class="sdr-divider"></div>
    <div class="sdr-label">
      <svg viewBox="0 0 24 24" width="11" height="11" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>
      Categorias
    </div>
    <div class="sdr-cats">
      ${SDR_CATS.map(c => `<div class="sdr-cat-btn" onclick="${fillFn}('${c.n}')">${c.i} ${c.n}</div>`).join('')}
    </div>`;
  }

  // Trending
  html += `<div class="sdr-trending">
    <span class="sdr-trending-label">🔥 Em alta:</span>
    ${SDR_TRENDING.slice(0, 5).map(t => `<span class="sdr-trend-tag" onclick="${fillFn}('${t}')">${t}</span>`).join('')}
  </div>`;

  // Footer
  if (_searchHistory.length) {
    html += `<div class="sdr-footer">
      <span>${filtered.length} sugestões</span>
      <span class="sdr-footer-clear" onclick="_searchHistory=[];_refreshBothDropdowns();">Limpar histórico</span>
    </div>`;
  }

  return html;
}

function _refreshBothDropdowns() {
  var heroVal = (document.getElementById('heroSearchInput') || {}).value || '';
  var topVal  = (document.getElementById('searchInput') || {}).value || '';
  var hd = document.getElementById('heroDropdown');
  var td = document.getElementById('topSearchDropdown');
  if (hd && hd.style.display !== 'none') heroSearchType(heroVal);
  if (td && td.style.display !== 'none') topSearchType(topVal);
}

// ── HERO SEARCH ──
function heroSearchType(val) {
  var drop = document.getElementById('heroDropdown');
  if (!drop) return;
  var filtered = val.trim()
    ? searchSuggestions.filter(s => s.t.toLowerCase().includes(val.toLowerCase()) || s.c.toLowerCase().includes(val.toLowerCase()))
    : searchSuggestions.filter((_, i) => i < 5);
  drop.innerHTML = _buildDropdownBody(filtered, val.trim(), 'heroFill', !val.trim(), !val.trim());
  drop.style.display = 'block';
}

function showHeroDropdown() {
  heroSearchType((document.getElementById('heroSearchInput') || {}).value || '');
}

function hideHeroDropdown() {
  var d = document.getElementById('heroDropdown');
  if (d) d.style.display = 'none';
}

function heroFill(val) {
  var inp = document.getElementById('heroSearchInput');
  if (inp) inp.value = val;
  hideHeroDropdown();
  heroSearchSubmit();
}

function heroSearchSubmit() {
  var val = ((document.getElementById('heroSearchInput') || {}).value || '').trim();
  if (!val) return showToast('🔍 Digite o que procura...');
  _pushHistory(val);
  hideHeroDropdown();
  setActiveSearchResult(val, '');
  setTimeout(() => {
    var sec = document.getElementById('products-sec');
    if (sec) sec.scrollIntoView({behavior:'smooth'});
  }, 400);
}

// ── TOP NAV SEARCH ──
function topSearchType(val) {
  var drop = document.getElementById('topSearchDropdown');
  if (!drop) return;
  var filtered = val.trim()
    ? searchSuggestions.filter(s => s.t.toLowerCase().includes(val.toLowerCase()) || s.c.toLowerCase().includes(val.toLowerCase()))
    : searchSuggestions.filter((_, i) => i < 5);
  drop.innerHTML = _buildDropdownBody(filtered, val.trim(), 'topFill', !val.trim(), false);
  drop.style.display = 'block';
}

function showTopDropdown() {
  topSearchType((document.getElementById('searchInput') || {}).value || '');
}

function hideTopDropdown() {
  var d = document.getElementById('topSearchDropdown');
  if (d) d.style.display = 'none';
}

function topFill(val) {
  var inp = document.getElementById('searchInput');
  if (inp) inp.value = val;
  hideTopDropdown();
  topSearchSubmit();
}

function topSearchSubmit() {
  var q = ((document.getElementById('searchInput') || {}).value || '').trim();
  var cat = ((document.getElementById('searchCat') || {}).value || '');
  if (!q && !cat) return showToast('🔍 Digite algo para buscar');
  _pushHistory(q);
  showPage('home');
  setActiveSearchResult(q, cat);
  setTimeout(() => {
    var sec = document.getElementById('products-sec');
    if (sec) sec.scrollIntoView({behavior:'smooth'});
  }, 200);
  hideTopDropdown();
}


