function cepMask(input){
  // Detect if looks like a zip/postal from other countries (letters = international)
  let v=input.value.replace(/\D/g,'');
  if(v.length>8)v=v.slice(0,8);
  if(v.length>5)v=v.slice(0,5)+'-'+v.slice(5);
  input.value=v;
}

