function calcCep(){
  const raw=document.getElementById('cepInput').value.replace(/\D/g,'');
  const resultEl=document.getElementById('cepResult');
  const optionsEl=document.getElementById('cepOptions');

  if(raw.length<5){
    resultEl.innerHTML='<div class="cep-error">⚠️ Digite um CEP válido (ex: 01310-100)</div>';
    resultEl.style.display='block';
    optionsEl.style.display='none';
    return;
  }

  // Show loading
  resultEl.innerHTML='<div class="cep-loading"><div class="cep-spinner"></div> Consultando endereço...</div>';
  resultEl.style.display='block';
  optionsEl.style.display='none';

  setTimeout(()=>{
    const prefix=raw.slice(0,2);
    const regionInfo=cepDeliveryData[prefix];
    const state=regionInfo?regionInfo[0]:'SP';
    const city=regionInfo?regionInfo[1]:'Sua cidade';
    const deadlines=regionDeadlines[state]||regionDeadlines['SP'];

    // Calc arrival dates
    function addDays(str){
      const days=parseInt(str.split('-')[1]||str)||7;
      const d=new Date();d.setDate(d.getDate()+days);
      return d.toLocaleDateString('pt-BR',{day:'2-digit',month:'short'});
    }

    resultEl.innerHTML=`
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;">
        <span style="font-size:16px;">📍</span>
        <div>
          <div style="font-size:13px;font-weight:600;">CEP <strong>${document.getElementById('cepInput').value}</strong> encontrado</div>
          <div style="font-size:12px;color:var(--muted);">${city}</div>
        </div>
        <span style="margin-left:auto;font-size:11px;color:#22C55E;font-weight:600;">✅ CEP válido</span>
      </div>
      <div style="font-size:12px;color:var(--muted);">Escolha a modalidade de entrega:</div>`;
    resultEl.style.display='block';

    optionsEl.innerHTML=`
      <div class="cep-option" onclick="selectShipping('PAC',this)">
        <div class="cep-opt-label">📦 PAC / Econômico</div>
        <div class="cep-opt-eta">${deadlines.pac[0]} dias úteis</div>
        <div style="display:flex;justify-content:space-between;align-items:center;">
          <div class="cep-opt-price">Previsão: até ${addDays(deadlines.pac[0])}</div>
          <div style="font-size:12px;font-weight:700;color:${deadlines.pac[1]==='Grátis'?'#22C55E':'var(--teal)'};">${deadlines.pac[1]}</div>
        </div>
      </div>
      <div class="cep-option" onclick="selectShipping('SEDEX',this)">
        <div class="cep-opt-label">🚀 SEDEX / Expresso</div>
        <div class="cep-opt-eta">${deadlines.sedex[0]} dias úteis</div>
        <div style="display:flex;justify-content:space-between;align-items:center;">
          <div class="cep-opt-price">Previsão: até ${addDays(deadlines.sedex[0])}</div>
          <div style="font-size:12px;font-weight:700;color:var(--teal);">${deadlines.sedex[1]}</div>
        </div>
      </div>
      <div class="cep-option" onclick="selectShipping('EXPRESS',this)">
        <div class="cep-opt-label">⚡ WeKz Express</div>
        <div class="cep-opt-eta">${deadlines.express[0]}</div>
        <div style="display:flex;justify-content:space-between;align-items:center;">
          <div class="cep-opt-price">Mais rápido disponível</div>
          <div style="font-size:12px;font-weight:700;color:var(--purple);">${deadlines.express[1]}</div>
        </div>
      </div>`;
    optionsEl.style.display='grid';
  },900);
}

function selectShipping(type,el){
  document.querySelectorAll('.cep-option').forEach(o=>o.style.borderColor='');
  el.style.borderColor='var(--teal)';
  el.style.background='rgba(0,180,171,0.06)';
  showToast(`✅ Frete ${type} selecionado!`);
}

