// ─── CATEGORY TEMPLATE ───
function openCategory(name, icon){
  const cat = DB.categories.find(c=>c.name===name) || {name,icon,count:'—',desc:`Produtos em ${name}`};
  document.getElementById('catBreadcrumb').textContent = name;
  document.getElementById('catTemplateIcon').innerHTML = wkzCatIconSVG(icon || cat.icon);
  document.getElementById('catTemplateTitle').textContent = name;
  document.getElementById('catTemplateSub').textContent = `${cat.count}+ produtos · Vendedores verificados · Frete grátis em muitos itens`;
  renderCatProducts();
  showPage('category');
}

function renderCatProducts(){
  const g = document.getElementById('catProductsGrid');
  const rb = document.getElementById('catResultBar');
  if(!g) return;
  const sort = document.getElementById('catSortSelect').value;
  let list = [...products];
  const maxPrice = parseFloat(document.getElementById('catPriceSlider').value)||5000;
  const ratingVal = document.querySelector('input[name="catRating"]:checked')?.value||0;
  list = list.filter(p => p.p <= maxPrice && p.r >= parseFloat(ratingVal));
  if(sort==='price-asc') list.sort((a,b)=>a.p-b.p);
  else if(sort==='price-desc') list.sort((a,b)=>b.p-a.p);
  else if(sort==='rating') list.sort((a,b)=>b.r-a.r);
  else if(sort==='sales') list.sort((a,b)=>parseFloat(b.sales)-parseFloat(a.sales));

  rb.innerHTML = `<div class="search-result-bar"><span class="srb-count"><strong>${list.length}</strong> produtos encontrados</span><span style="font-size:12px;color:var(--muted);">Ordenado por: ${sort||'Relevância'}</span></div>`;

  g.innerHTML = list.map((p,i)=>`
    <div class="product-card" onclick="openProduct(${products.indexOf(p)})">
      <div class="product-img"><wkz-product-image src="${p.img||''}" emoji="${p.e}" alt="${p.n}"></wkz-product-image>
        <div class="product-badges">
          ${p.badge==='sale'?'<span class="badge badge-sale">SALE</span>':''}
          ${p.badge==='new'?'<span class="badge badge-new">NOVO</span>':''}
          ${p.badge==='hot'?'<span class="badge badge-hot">HOT</span>':''}
          ${p._sponsored?'<span class="badge badge-ad">📢 Patrocinado</span>':''}
          ${p._frete||FRETE_GRATIS_SELLERS.includes(p.s)?'<span class="badge badge-frete">🚚 Grátis</span>':''}
          ${Object.values(SELLER_COUPONS).some(c=>c.seller===p.s)?'<span class="badge badge-coupon">🏷️ Cupom</span>':''}
        </div>
        <button class="product-wish" onclick="event.stopPropagation();event.preventDefault();wishToggle(this,${products.indexOf(p)},event)">♡</button>
      </div>
      <div class="product-info">
        <div class="product-name">${p.n}</div>
        <div class="product-store"><span class="store-verified">✅</span>${p.s}${isOfficialStore(p.s)?'<span class="store-official-tag">🏅 Loja Oficial</span>':''}</div>
        <div class="product-price"><span class="price-main">${formatPrice(p.p)}</span><span class="price-old">${formatPrice(p.op)}</span><span class="price-off">-${p.off}%</span></div>
        <div class="product-meta"><div class="product-stars"><span class="stars">★★★★★</span> ${p.r}</div><div class="product-sales">${p.sales} vendidos</div></div>
        <button class="btn-add" onclick="event.stopPropagation();btnFeedback(this,()=>addToCart(${i}))"><span class="btn-spinner"></span><span class="btn-check">✓</span><span class="btn-label"><span class="wkz-icon wkz-icon-cart"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 001.99 1.61h9.72a2 2 0 001.99-1.61L23 6H6"/></svg></span> Adicionar ao carrinho</span></button>
        <button class="btn-buy" onclick="event.stopPropagation();btnFeedback(this,()=>{addToCart(${i});setTimeout(()=>showPage('cart'),400)},{loadingMs:500,successMs:600})"><span class="btn-spinner"></span><span class="btn-check">✓</span><span class="btn-label"><span class="wkz-icon wkz-icon-zap"><svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polygon points="13,2 3,14 12,14 11,22 21,10 12,10 13,2"/></svg></span> Comprar Agora</span></button>
      </div>
    </div>`).join('');

  // Pagination
  const pag = document.getElementById('catPagination');
  pag.innerHTML = [1,2,3,'...',8,9,10].map(n=>
    `<button style="padding:8px 14px;border-radius:8px;border:1px solid ${n===1?'var(--teal)':'var(--border)'};background:${n===1?'rgba(0,180,171,0.1)':'var(--card)'};color:${n===1?'var(--teal)':'var(--muted)'};cursor:pointer;font-size:13px;transition:var(--transition);" onclick="showToast('📄 Página ${n}')">${n}</button>`
  ).join('');
}

function updatePriceRange(v){
  document.getElementById('catPriceLabel').textContent = `R$ ${parseFloat(v).toLocaleString()}`;
}

function clearCatFilters(){
  document.getElementById('catPriceSlider').value=5000;
  document.getElementById('catPriceLabel').textContent='R$ 5.000';
  document.getElementById('catSortSelect').value='';
  document.querySelectorAll('input[name="catRating"]').forEach((r,i)=>{r.checked=i===2;});
  renderCatProducts();
  showToast('🔄 Filtros limpos');
}

// ─── POLICY ICON HELPER ───
function getPolicyIcon(label){
  const l = (label||'').toLowerCase();
  if(l.includes('devolu') || l.includes('troca') || l.includes('tamanh'))
    return '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="1,4 1,10 7,10"/><path d="M3.51 15a9 9 0 102.13-9.36L1 10"/></svg>';
  if(l.includes('original') || l.includes('autên') || l.includes('verific') || l.includes('serial') || l.includes('certif') || l.includes('nota fiscal'))
    return '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="20,6 9,17 4,12"/></svg>';
  if(l.includes('envio') || l.includes('frete') || l.includes('entrega') || l.includes('embalagem'))
    return '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="1" y="3" width="15" height="13"/><polygon points="16,8 20,8 23,11 23,16 16,16 16,8"/><circle cx="5.5" cy="18.5" r="2.5"/><circle cx="18.5" cy="18.5" r="2.5"/></svg>';
  if(l.includes('resp') || l.includes('chat') || l.includes('suport') || l.includes('imedi'))
    return '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg>';
  if(l.includes('lacrado') || l.includes('anti-fraude') || l.includes('fraude') || l.includes('segur') || l.includes('shield'))
    return '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>';
  if(l.includes('aval') || l.includes('star') || l.includes('rating'))
    return '<svg viewBox="0 0 24 24" width="20" height="20" fill="#F59E0B" stroke="#F59E0B" stroke-width="1"><polygon points="12,2 15.09,8.26 22,9.27 17,14.14 18.18,21.02 12,17.77 5.82,21.02 7,14.14 2,9.27 8.91,8.26"/></svg>';
  if(l.includes('cruelty') || l.includes('sustent') || l.includes('eco') || l.includes('natural'))
    return '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 2a10 10 0 000 20"/><path d="M12 2c2.76 0 5 4.48 5 10S14.76 22 12 22"/><path d="M2 12h20"/></svg>';
  // default: checkmark
  return '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12,8 12,12 14,14"/></svg>';
}

// ─── STORE DETAIL TEMPLATE ───
function openStore(storeId){
  const s = DB.stores.find(st=>st.id===storeId) || DB.stores[0];
  document.getElementById('storeTplName').textContent = s.name;
  document.getElementById('storeTplBanner').textContent = s.banner;
  document.getElementById('storeTplAvatar').textContent = s.avatar;
  document.getElementById('storeTplTitle').textContent = s.name;
  document.getElementById('storeTplNameTitle').textContent = s.name;

  document.getElementById('storeTplStats').innerHTML = [
    {v:s.sales,l:'Vendas'},
    {v:s.followers,l:'Seguidores'},
    {v:s.products,l:'Produtos'},
    {v:s.rating+'★',l:'Avaliação'},
  ].map(st=>`<div class="store-stat"><div class="store-stat-val">${st.v}</div><div class="store-stat-label">${st.l}</div></div>`).join('');

  document.getElementById('storePolicies').innerHTML = s.policies.map(p=>`
    <div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:14px;text-align:center;">
      <div style="display:flex;justify-content:center;align-items:center;margin-bottom:6px;height:28px;color:var(--teal);">${getPolicyIcon(p.t)}</div>
      <div style="font-size:12px;font-weight:600;">${p.t}</div>
    </div>`).join('');

  document.getElementById('storeProductsGrid').innerHTML = products.slice(0,6).map((p,i)=>`
    <div class="product-card" onclick="openProduct(${i})">
      <div class="product-img"><wkz-product-image src="${p.img||''}" emoji="${p.e}" alt="${p.n}"></wkz-product-image>
        <div class="product-badges">${p.badge==='sale'?'<span class="badge badge-sale">SALE</span>':''}</div>
      </div>
      <div class="product-info">
        <div class="product-name">${p.n}</div>
        <div class="product-price"><span class="price-main">${formatPrice(p.p)}</span></div>
        <div style="display:flex;gap:6px;margin-top:10px;">
          <button class="btn-add" style="flex:1;" onclick="event.stopPropagation();addToCart();showToast('Adicionado ao carrinho!')">
            <span class="btn-spinner"></span>
            <span class="btn-check">&#10003;</span>
            <span class="btn-label" style="display:flex;align-items:center;justify-content:center;gap:5px;">
              <span class="wkz-icon wkz-icon-cart"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 001.99 1.61h9.72a2 2 0 001.99-1.61L23 6H6"/></svg></span>
              Adicionar
            </span>
          </button>
          <button class="btn-buy" style="flex:1;" onclick="event.stopPropagation();openProduct(${i});showToast('Redirecionando para compra...')">
            <span style="display:flex;align-items:center;justify-content:center;gap:5px;">
              <span class="wkz-icon wkz-icon-zap"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><polygon points="13,2 3,14 12,14 11,22 21,10 12,10 13,2"/></svg></span>
              Comprar
            </span>
          </button>
        </div>
      </div>
    </div>`).join('');

  document.getElementById('storeReviewsList').innerHTML = DB.reviews.map(r=>`
    <div style="border-top:1px solid var(--border);padding:16px 0;display:flex;gap:14px;">
      <div style="width:36px;height:36px;border-radius:50%;background:var(--grad2);display:flex;align-items:center;justify-content:center;font-weight:800;font-size:14px;flex-shrink:0;">${r.a}</div>
      <div>
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px;">
          <span style="font-size:13px;font-weight:600;">${r.name}</span>
          <span style="color:#F59E0B;font-size:12px;">${'★'.repeat(r.r)}</span>
          ${r.verified?'<span style="font-size:10px;color:var(--teal);background:rgba(0,180,171,0.1);padding:2px 8px;border-radius:50px;display:inline-flex;align-items:center;gap:3px;"><svg viewBox=\'0 0 24 24\' width=\'10\' height=\'10\' fill=\'none\' stroke=\'currentColor\' stroke-width=\'2.5\' stroke-linecap=\'round\' stroke-linejoin=\'round\'><polyline points=\'20,6 9,17 4,12\'/></svg> Compra verificada</span>':''}
        </div>
        <div style="font-size:13px;color:var(--muted);">${r.text}</div>
      </div>
    </div>`).join('');

  /* Atualiza o botão "Seguir" do template com estado real */
  const tplFollowBtn = document.querySelector('.store-tpl-actions .btn-follow, .store-tpl-actions .btn-unfollow');
  if(tplFollowBtn){
    const isAlreadyFollowed = followedStores.some(fs => fs.n === s.name);
    tplFollowBtn.textContent = isAlreadyFollowed ? '💔 Deixar de Seguir' : '+ Seguir';
    tplFollowBtn.className = isAlreadyFollowed ? 'btn-unfollow' : 'btn-follow';
    tplFollowBtn.onclick = function(){ toggleFollowStoreByName(s.name, this); };
  }

  setTimeout(initFormSelects, 30); // converte storeSortSelect ao abrir loja
  showPage('store-detail');
}

// patch stores grid to open store detail
function renderStores(){
  ['storesGrid','storesGridFull'].forEach(id=>{
    const g=document.getElementById(id);
    if(!g)return;
    g.innerHTML=DB.stores.map(s=>{
      const isFollowed = followedStores.some(fs => fs.n === s.name);
      const safeId = 'store-card-' + s.id;
      return `
      <div class="store-card" id="${safeId}" onclick="openStore('${s.id}')">
        <div class="store-avatar">${s.avatar}</div>
        <div class="store-name">${s.name}</div>
        <div class="store-info">${s.category} · ${s.rating} ★ · ${s.sales} vendas</div>
        <div class="store-tags"><span class="store-tag" style="display:inline-flex;align-items:center;gap:3px;"><svg viewBox='0 0 24 24' width='10' height='10' fill='none' stroke='currentColor' stroke-width='2.5' stroke-linecap='round' stroke-linejoin='round'><polyline points='20,6 9,17 4,12'/></svg> Verificado</span><span class="store-tag" style="display:inline-flex;align-items:center;gap:3px;"><svg viewBox='0 0 24 24' width='10' height='10' fill='none' stroke='currentColor' stroke-width='2.5' stroke-linecap='round' stroke-linejoin='round'><polygon points='13,2 3,14 12,14 11,22 21,10 12,10'/></svg> Rápido</span></div>
        <button class="${isFollowed?'btn-unfollow':'btn-follow'}" onclick="event.stopPropagation();toggleFollowStoreByName('${s.name.replace(/'/g,'&#39;')}',this)">${isFollowed?'Deixar de Seguir':'Seguir Loja'}</button>
      </div>`;
    }).join('');
  });
}

