function _lglRenderFaq() {
  var el = document.getElementById('lglFaqAccordion');
  if (!el || el.children.length > 0) return;
  var faqs = [
    { q: 'Quanto custa o frete internacional?', a: 'O valor é calculado automaticamente no carrinho com base no peso do produto e no endereço de entrega. Para a maioria dos países europeus e americanos, o frete começa a partir de R$ 35. Muitos vendedores oferecem frete grátis acima de um valor mínimo.' },
    { q: 'Meu produto pode ser retido na alfândega?', a: 'Produtos abaixo de US$ 50 (ou equivalente) geralmente passam com isenção na maioria dos países. Para valores acima disso, a WeKz gera automaticamente a documentação fiscal necessária e envia alertas de alíquota antes da compra. Nossa equipe de suporte aduaneiro atua proativamente em caso de retenção.' },
    { q: 'Como rastrear um pedido internacional?', a: 'Acesse "Rastrear Pedido" no menu ou no seu Perfil → Meus Pedidos. O código de rastreio é enviado por e-mail e notificação push assim que o pedido é despachado. A linha do tempo visual é atualizada em tempo real.' },
    { q: 'Posso devolver um produto comprado internacionalmente?', a: 'Sim. O prazo para devolução é de 15 dias após o recebimento. Abra uma disputa pelo Kz Copilot — a IA guia o processo passo a passo e o reembolso é feito via Pix ou carteira WeKz em até 5 dias úteis após a aprovação.' },
    { q: 'O câmbio pode mudar entre a compra e o débito?', a: 'Não. O Kz FX Guard trava o câmbio no momento em que você confirma o pedido. O valor exato cobrado em BRL (ou na sua moeda local) não muda, independentemente de variações de mercado.' },
    { q: 'Quais países têm entrega expressa disponível?', a: 'Brasil, Portugal, EUA, Canadá, Reino Unido, Alemanha, França, Espanha, Japão e Austrália têm opções de entrega expressa (3–10 dias úteis). Para demais países, a modalidade padrão rastreada está disponível.' },
  ];
  el.innerHTML = faqs.map(function(f, i) {
    var id = 'lglFaq' + i;
    return '<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;overflow:hidden;">' +
      '<button onclick="_lglToggleFaq(\'' + id + '\')" style="width:100%;display:flex;align-items:center;justify-content:space-between;gap:12px;padding:14px 16px;background:none;border:none;color:var(--text);cursor:pointer;text-align:left;">' +
        '<span style="font-family:\'DM Sans\',sans-serif;font-size:13px;font-weight:700;">' + f.q + '</span>' +
        '<svg id="' + id + 'Chevron" viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0;transition:transform 0.2s;"><polyline points="6,9 12,15 18,9"/></svg>' +
      '</button>' +
      '<div id="' + id + '" style="display:none;padding:0 16px 14px;font-size:13px;color:var(--muted);line-height:1.7;">' + f.a + '</div>' +
    '</div>';
  }).join('');
}

function _lglToggleFaq(id) {
  var panel = document.getElementById(id);
  var chevron = document.getElementById(id + 'Chevron');
  if (!panel) return;
  var open = panel.style.display !== 'none';
  panel.style.display = open ? 'none' : 'block';
  if (chevron) chevron.style.transform = open ? '' : 'rotate(180deg)';
}
