/* ────────────────── OPEN / CLOSE MODAL ────────────────── */
function openReportModal(productIndex, type = 'product') {
  currentReportTarget = { index: productIndex, type };
  pendingEvidences = [];

  const overlay = document.getElementById('report-modal-overlay');
  const titleEl = document.getElementById('rm-title-text');
  const emojiEl = document.getElementById('rmProductEmoji');
  const nameEl  = document.getElementById('rmProductName');
  const storeEl = document.getElementById('rmProductStore');

  // Populate product info
  const p = (productIndex >= 0 && products[productIndex]) ? products[productIndex] : null;
  if (type === 'vendor') {
    titleEl.textContent = '⚑ Reportar Vendedor';
    emojiEl.setAttribute('emoji', p ? p.e : '🏪');
    if(p && p.img){emojiEl.setAttribute('src',p.img);} else {emojiEl.removeAttribute('src');}
    nameEl.textContent   = p ? 'Vendedor: ' + p.s : 'Vendedor';
    storeEl.textContent  = 'Reportar comportamento suspeito do vendedor';
  } else {
    titleEl.textContent = '⚑ Reportar Produto';
    emojiEl.setAttribute('emoji', p ? p.e : '📦');
    if(p && p.img){emojiEl.setAttribute('src',p.img);} else {emojiEl.removeAttribute('src');}
    nameEl.textContent   = p ? p.n : 'Produto';
    storeEl.textContent  = p ? 'Loja: ' + p.s : 'Loja';
  }

  // Reset form
  document.getElementById('rmReason').value   = '';
  document.getElementById('rmDetails').value  = '';
  document.getElementById('rmDetailsCount').textContent = '0';
  document.getElementById('rmEvidenceGrid').innerHTML   = '';
  document.getElementById('rmEvidenceInput').value      = '';

  const btn = document.getElementById('rmSubmitBtn');
  btn.disabled = false;
  document.getElementById('rmSubmitIcon').textContent = '⚑';
  document.getElementById('rmSubmitText').textContent = 'Enviar Denúncia';

  overlay.classList.add('open');
  setTimeout(initFormSelects, 60); // converte selects do modal;
  document.body.style.overflow = 'hidden';

  // Attach char counter
  document.getElementById('rmDetails').oninput = function() {
    document.getElementById('rmDetailsCount').textContent = this.value.length;
  };
}

