/* ────────────────── EVIDENCE UPLOAD ────────────────── */
function handleEvidenceUpload(event) {
  const files = Array.from(event.target.files);
  if (!files.length) return;

  files.forEach(file => {
    if (file.size > 5 * 1024 * 1024) {
      showToast('⚠️ ' + file.name + ' é muito grande (máx 5MB)');
      return;
    }
    const reader = new FileReader();
    reader.onload = (e) => {
      pendingEvidences.push({ name: file.name, dataUrl: e.target.result });
      renderEvidenceGrid();
    };
    reader.readAsDataURL(file);
  });
}

function renderEvidenceGrid() {
  const grid = document.getElementById('rmEvidenceGrid');
  if (!grid) return;
  grid.innerHTML = pendingEvidences.map((ev, i) => `
    <div class="rm-evidence-thumb" title="${ev.name}">
      <img src="data:image/png;base64," alt="${ev.name}">
      <button class="rm-evidence-remove" onclick="removeEvidence(${i})" type="button">✕</button>
    </div>
  `).join('');
}

function removeEvidence(index) {
  pendingEvidences.splice(index, 1);
  renderEvidenceGrid();
}

/* ────────────────── CONFIRM & SEND REPORT ────────────────── */
async function confirmReport() {
  const reason  = document.getElementById('rmReason').value.trim();
  const details = document.getElementById('rmDetails').value.trim();

  if (!reason)        { showToast('⚠️ Selecione o motivo da denúncia', 'error'); return; }
  if (details.length < 10) { showToast('⚠️ Descreva melhor o problema (mínimo 10 caracteres)', 'error'); return; }

  const btn = document.getElementById('rmSubmitBtn');
  btn.disabled = true;
  document.getElementById('rmSubmitIcon').innerHTML = '<span style="display:inline-block;width:13px;height:13px;border:2px solid rgba(255,255,255,0.3);border-top-color:#fff;border-radius:50%;animation:spin 0.8s linear infinite;"></span>';
  document.getElementById('rmSubmitText').textContent = 'Enviando...';

  const reasonLabels = {
    produto_falsificado: '🚫 Produto falsificado',
    anuncio_enganoso: '⚠️ Anúncio enganoso',
    preco_abusivo: '💸 Preço abusivo',
    produto_proibido: '🔞 Produto proibido',
    nao_entregue: '📦 Produto não entregue',
    diferente_anuncio: '↩️ Produto diferente',
    violacao_propriedade: '©️ Violação IP',
    vendedor_fraudulento: '👤 Vendedor fraudulento',
    outro: '❓ Outro'
  };

  const p = (currentReportTarget.index >= 0 && products[currentReportTarget.index]) ? products[currentReportTarget.index] : null;

  const newReport = {
    id: 'RPT-' + String(Date.now()).slice(-6),
    productIndex: currentReportTarget.index,
    productName: p ? p.n : 'Desconhecido',
    productEmoji: p ? p.e : '📦',
    storeName: p ? p.s : 'Desconhecido',
    type: currentReportTarget.type,
    reason, reasonLabel: reasonLabels[reason] || reason,
    details,
    evidences: pendingEvidences.map(ev => ev.dataUrl),
    status: 'recebida',
    createdAt: new Date().toISOString(),
    logs: [
      {
        text: 'Denúncia recebida. Protocolo #' + ('RPT-' + String(Date.now()).slice(-6)) + ' gerado.',
        color: '#22C55E',
        time: new Date().toISOString(),
        images: pendingEvidences.map(ev => ev.dataUrl)
      }
    ]
  };

  // ── Attempt real API call ──
  try {
    const formData = new FormData();
    formData.append('productIndex', currentReportTarget.index);
    formData.append('type', currentReportTarget.type);
    formData.append('reason', reason);
    formData.append('details', details);
    pendingEvidences.forEach((ev, i) => {
      // Convert dataUrl to blob
      const arr = ev.dataUrl.split(',');
      const mime = arr[0].match(/:(.*?);/)[1];
      const bstr = atob(arr[1]);
      const n = bstr.length;
      const u8 = new Uint8Array(n);
      for (let j = 0; j < n; j++) u8[j] = bstr.charCodeAt(j);
      formData.append('evidences', new Blob([u8], { type: mime }), ev.name);
    });

    // Uncomment when backend is ready:
    // const resp = await fetch(API_BASE, { method: 'POST', body: formData });
    // if (!resp.ok) throw new Error('API error');
    // const data = await resp.json();
    // newReport.id = data.id || newReport.id;

    // Simulated delay for demo
    await new Promise(r => setTimeout(r, 1200));

  } catch(err) {
    // Fallback to local store — UI still works
    console.warn('Backend unavailable, storing locally:', err);
  }

  // Always add to local store
  reportsStore.unshift(newReport);
  updateDenunciasCount();

  // Simulate status advance after 3 seconds
  setTimeout(() => {
    const r = reportsStore.find(x => x.id === newReport.id);
    if (r) advanceStatus(r.id);
  }, 3000);

  closeReportModal();
  showToast('✅ Denúncia enviada! Protocolo: ' + newReport.id, 'success');

  // If dashboard is open, re-render
  if (document.getElementById('dash-denuncias').classList.contains('active') ||
      document.getElementById('dash-denuncias').style.display !== 'none') {
    renderReports();
  }
}

/* ────────────────── STATUS ADVANCEMENT (simulated flow) ────────────────── */
function advanceStatus(reportId) {
  const r = reportsStore.find(x => x.id === reportId);
  if (!r) return;

  const flow = ['recebida', 'analise', 'defesa', 'resolvida'];
  const idx  = flow.indexOf(r.status);
  if (idx === -1 || idx >= flow.length - 1) return;

  const next = flow[idx + 1];
  const logs_map = {
    analise:  { text: 'Denúncia em análise pela equipe de segurança WeKz. Prazo: 24h.', color: '#F59E0B' },
    defesa:   { text: 'Vendedor notificado. Aguardando resposta de defesa (prazo: 72h).', color: '#A78BFA' },
    resolvida:{ text: 'Caso encerrado pela equipe WeKz. Medidas aplicadas conforme política da plataforma.', color: '#EF4444' },
  };

  r.status = next;
  r.logs.push({ text: logs_map[next].text, color: logs_map[next].color, time: new Date().toISOString(), images: [] });

  updateDenunciasCount();

  const panel = document.getElementById('dash-denuncias');
  if (panel && panel.style.display !== 'none') renderReports();
}

/* ────────────────── RENDER DASHBOARD ────────────────── */
function renderReports(filter = 'all') {
  const list = document.getElementById('denunciasList');
  if (!list) return;

  let data = [...reportsStore];
  if (filter === 'open')   data = data.filter(r => r.status !== 'resolvida');
  if (filter === 'closed') data = data.filter(r => r.status === 'resolvida');

  if (!data.length) {
    list.innerHTML = `<div class="denuncias-empty"><div class="big-icon">🛡️</div><p>Nenhuma denúncia encontrada.</p></div>`;
    return;
  }

  const statusInfo = {
    recebida:  { label: '🟢 Recebida',           cls: 'status-recebida'  },
    analise:   { label: '🟡 Em Análise',          cls: 'status-analise'   },
    defesa:    { label: '🟣 Defesa do Vendedor',  cls: 'status-defesa'    },
    resolvida: { label: '🔴 Resolvida',           cls: 'status-resolvida' },
  };

  const pipelineSteps = [
    { key: 'recebida', label: 'Recebida'  },
    { key: 'analise',  label: 'Análise'   },
    { key: 'defesa',   label: 'Defesa'    },
    { key: 'resolvida',label: 'Resolvida' },
  ];

  list.innerHTML = data.map(r => {
    const si = statusInfo[r.status] || statusInfo.recebida;
    const flow = ['recebida','analise','defesa','resolvida'];
    const statusIdx = flow.indexOf(r.status);

    const pipelineHTML = pipelineSteps.map((step, i) => {
      let cls = '';
      if (i < statusIdx)  cls = 'done';
      if (i === statusIdx) cls = 'active';
      const line = i < pipelineSteps.length - 1 ? '<div class="pipeline-line"></div>' : '';
      return `<div class="pipeline-step ${cls}"><div class="pipeline-dot"></div>${step.label}</div>${line}`;
    }).join('');

    // Seller-facing action: only the 'defesa' stage is an action the seller actually performs.
    // 'recebida' and 'analise' are internal WeKz moderation stages — no seller action there.
    let actionHTML = '';
    if (r.status === 'defesa') {
      actionHTML = r.defesaSubmitted
        ? `<div style="margin-top:14px;padding:10px 12px;background:rgba(167,139,250,0.08);border:1px solid rgba(167,139,250,0.25);border-radius:8px;font-size:12px;color:#A78BFA;">🛡️ Defesa enviada. Aguardando análise da equipe WeKz.</div>`
        : `<div style="margin-top:14px;">
            <button onclick="toggleDefesaForm('${r.id}')" style="width:100%;padding:10px;background:rgba(167,139,250,0.1);border:1px solid rgba(167,139,250,0.3);color:#A78BFA;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer;transition:var(--transition);">🛡️ Apresentar Defesa</button>
            <div id="defesa-form-${r.id}" style="display:none;margin-top:10px;">
              <textarea id="defesa-text-${r.id}" placeholder="Explique sua versão dos fatos sobre esta denúncia..." style="width:100%;min-height:90px;padding:10px;font-size:12px;font-family:inherit;background:rgba(0,0,0,0.2);border:1px solid var(--border);border-radius:8px;color:var(--text);resize:vertical;"></textarea>
              <button onclick="submitDefesa('${r.id}')" style="margin-top:8px;width:100%;padding:8px;background:var(--teal);border:none;color:#04201e;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer;">Enviar Defesa</button>
            </div>
          </div>`;
    } else if (r.status !== 'resolvida') {
      actionHTML = `<button onclick="advanceStatus('${r.id}')" style="margin-top:14px;width:100%;padding:8px;background:rgba(0,180,171,0.08);border:1px dashed rgba(0,180,171,0.3);color:var(--teal);border-radius:8px;font-size:11px;cursor:pointer;transition:var(--transition);" title="Simula o avanço da análise interna da equipe WeKz">⚡ [Demo] Simular avanço da análise WeKz</button>`;
    }


    const logsHTML = r.logs.map(log => `
      <div class="log-entry">
        <div class="log-dot" style="background:${log.color};box-shadow:0 0 6px ${log.color}55;"></div>
        <div class="log-content">
          <div class="log-text">${log.text}</div>
          <div class="log-time">🕐 ${formatLogTime(log.time)}</div>
          ${log.images && log.images.length ? `
          <div class="log-images">
            ${log.images.map(img => `
              <div class="log-img-thumb" onclick="viewImage('${img}')">
                <img src="data:image/png;base64," alt="Evidência">
              </div>`).join('')}
          </div>` : ''}
        </div>
      </div>`).join('');

    return `
      <div class="denuncia-item" id="dItem-${r.id}">
        <div class="denuncia-header" onclick="toggleDenuncia('${r.id}')">
          <span style="font-size:24px;flex-shrink:0;">${r.productEmoji}</span>
          <div class="denuncia-info">
            <div class="denuncia-title">${r.productName}</div>
            <div class="denuncia-meta">
              <span>📋 ${r.id}</span>
              <span>${r.reasonLabel}</span>
              <span>🕐 ${formatLogTime(r.createdAt)}</span>
            </div>
          </div>
          <span class="denuncia-status ${si.cls}">${si.label}</span>
          <span class="denuncia-chevron">▼</span>
        </div>
        <div class="denuncia-logs">
          <!-- Pipeline -->
          <div class="status-pipeline">${pipelineHTML}</div>
          <!-- Details summary -->
          <div style="margin-top:14px;padding:12px;background:rgba(0,0,0,0.2);border-radius:10px;margin-bottom:14px;">
            <div style="font-size:11px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:0.8px;margin-bottom:6px;">Motivo da denúncia (relato do comprador)</div>
            <div style="font-size:13px;line-height:1.6;color:var(--text);">${r.details}</div>
          </div>
          <!-- Logs -->
          <div style="font-size:11px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:0.8px;margin-bottom:8px;">Histórico de atualizações</div>
          ${logsHTML}
          <!-- Seller action (Defesa) or demo stage-advance -->
          ${actionHTML}
        </div>
      </div>`;
  }).join('');
}

function toggleDefesaForm(reportId) {
  const el = document.getElementById('defesa-form-' + reportId);
  if (el) el.style.display = (el.style.display === 'none' || !el.style.display) ? 'block' : 'none';
}

function submitDefesa(reportId) {
  const ta = document.getElementById('defesa-text-' + reportId);
  const text = ta ? ta.value.trim() : '';
  if (!text) { showToast('⚠️ Escreva sua defesa antes de enviar.', 'error'); return; }

  const r = reportsStore.find(x => x.id === reportId);
  if (!r) return;

  r.logs.push({ text: 'Vendedor apresentou defesa: "' + text + '"', color: '#A78BFA', time: new Date().toISOString(), images: [] });
  r.defesaSubmitted = true;
  renderReports();
  showToast('✅ Defesa enviada! A equipe WeKz irá analisar e notificar ambas as partes.', 'success');

  // Simulate WeKz reviewing the defense and resolving the case
  setTimeout(() => advanceStatus(reportId), 4000);
}

function toggleDenuncia(id) {
  const el = document.getElementById('dItem-' + id);
  if (!el) return;
  el.classList.toggle('open');
}

function filterDenuncias(filter, btn) {
  document.querySelectorAll('#dash-denuncias .rev-filter').forEach(b => b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  renderReports(filter);
}

function formatLogTime(iso) {
  const d = new Date(iso);
  return d.toLocaleDateString('pt-BR', { day:'2-digit', month:'2-digit', year:'numeric' }) + ' às ' +
         d.toLocaleTimeString('pt-BR', { hour:'2-digit', minute:'2-digit' });
}

function updateDenunciasCount() {
  const el = document.getElementById('denunciasCount');
  if (el) {
    const open = reportsStore.filter(r => r.status !== 'resolvida').length;
    el.textContent = open;
    el.style.display = open > 0 ? 'inline-flex' : 'none';
  }
}

function viewImage(src) {
  // Simple lightbox
  const overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.92);z-index:99999;display:flex;align-items:center;justify-content:center;cursor:zoom-out;';
  const img = document.createElement('img');
  img.src = src;
  img.style.cssText = 'max-width:90vw;max-height:90vh;border-radius:12px;box-shadow:0 40px 80px rgba(0,0,0,0.5);';
  overlay.appendChild(img);
  overlay.onclick = () => overlay.remove();
  document.body.appendChild(overlay);
}

